-- Poems batch 196
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('e68e4bd1-3b4b-49df-aea8-d891c29622ae','寄廣右方提刑','趙庚夫','宋','宋诗','song-poetry','','[]','節旄昨下九疑山，圖畫仙真上界還。',64,'全唐诗/poet.song.187000.json','["節旄昨下九疑山，圖畫仙真上界還。", "巡歷半經三管地，笑談盡伏五溪蠻。", "受恩人拜祠堂下，留墨神呵古洞間。", "早晚歸班論邊瑣，有書時遣扣柴關。"]'),
('34294ac2-58fe-489e-969a-e40ae314d868','寄建康老友','趙庚夫','宋','宋诗','song-poetry','','[]','朋舊多隨秋葉風，與君心賞向來同。',64,'全唐诗/poet.song.187000.json','["朋舊多隨秋葉風，與君心賞向來同。", "十年相憶頭先白，萬里重分途更窮。", "蓴菜雖堪誇洛下，酒樽終是憶江東。", "自從學道全無夢，直待親逢紫陌中。"]'),
('a413cbde-26c1-481d-984b-f9890ac365e1','真州聽角','趙庚夫','宋','宋诗','song-poetry','','[]','畫角聽時恨最深，戍樓偏在女牆陰。',64,'全唐诗/poet.song.187000.json','["畫角聽時恨最深，戍樓偏在女牆陰。", "聲寒恐有新霜落，意遠未隨紅日沉。", "凉月一天孤雁影，秋風萬里狂夫心。", "連宵只解搜詩意，哀怨何曾動羽林。"]'),
('bef1957e-8b9a-43ef-b7c5-8620c5c864b3','題孔道士雲庵','趙庚夫','宋','宋诗','song-poetry','','[]','道人居玉笥，手闢小蓬萊。',48,'全唐诗/poet.song.187000.json','["道人居玉笥，手闢小蓬萊。", "門寂山相對，庵空雲自來。", "茶煙朝宛轉，丹氣夜昭回。", "欲助梨花夢，携鋤獨種梅。"]'),
('55a8605c-e66a-48bc-9da7-efbe3733b942','清泉','趙庚夫','宋','宋诗','song-poetry','','[]','清泉煮茗自甘肥，詩卷新來十大圍。',64,'全唐诗/poet.song.187000.json','["清泉煮茗自甘肥，詩卷新來十大圍。", "衰齒尚能餐枸杞，餘齡斷未泣牛衣。", "每思削髮遊方去，時夢乘雲謁帝歸。", "何世獨無勳業士，古來惟有逸民稀。"]'),
('63358658-c0c5-4c69-b290-606eac2f4e43','看梅','趙庚夫','宋','宋诗','song-poetry','','[]','竟日梅花側，枝枝入肺肝。',48,'全唐诗/poet.song.187000.json','["竟日梅花側，枝枝入肺肝。", "濕疑霜旋剪，清比玉堪餐。", "臨水嚴光釣，吟風東野寒。", "年來難取友，珍重莫吹殘。"]'),
('3a579ce0-3d18-45fe-b0aa-a68084b298e3','書田舍所見','趙庚夫','宋','宋诗','song-poetry','','[]','海上多風色，青山與屋齊。',48,'全唐诗/poet.song.187000.json','["海上多風色，青山與屋齊。", "禾堆深卧犬，樹杪忽聞鷄。", "白酒清無麯，青裙老未笄。", "主人偏道氣，被褐自扶犂。"]'),
('d620b33f-f3f9-4ae0-a548-d3427bea7c07','山居苦','趙庚夫','宋','宋诗','song-poetry','','[]','栽松成曲徑，洗石出秋屏。',48,'全唐诗/poet.song.187000.json','["栽松成曲徑，洗石出秋屏。", "米價占新月，更籌認曙星。", "買牛鄰共契，祭竈婦看經。", "不覺成頭白，頻看燒地青。"]'),
('0da5d64f-3e27-41cd-95af-9c97216f59da','題張山人幽居','趙庚夫','宋','宋诗','song-poetry','','[]','昔隠君平卜，今聞事又非。',48,'全唐诗/poet.song.187000.json','["昔隠君平卜，今聞事又非。", "肘猶懸蠹簡，身止掛鶉衣。", "芒屨沿山去，茅簷講易歸。", "先儒皆若此，切莫歎時違。"]'),
('64586a6d-c84a-4931-8b53-837a28b71589','友人別墅','趙庚夫','宋','宋诗','song-poetry','','[]','買山仍近水，結屋又安墳。',48,'全唐诗/poet.song.187000.json','["買山仍近水，結屋又安墳。", "此舉堪驚世，餘年獨羨君。", "釣舟須共載，禪榻亦平分。", "切莫施門戶，□藏恐礙雲。"]'),
('11182aac-a75b-4868-ae2b-8e6721488e0c','李長吉集','趙庚夫','宋','宋诗','song-poetry','','[]','幾回掩却又重看，吟罷心如着露蘭。',32,'全唐诗/poet.song.187000.json','["幾回掩却又重看，吟罷心如着露蘭。", "欲上玉樓窺老筆，虬龍擁處雪霜寒。"]'),
('11db7af0-f97b-4305-b081-9edf6aaefb5c','論詩','趙庚夫','宋','宋诗','song-poetry','','[]','未得歸山養聖胎，憑誰輕脫出山來。',64,'全唐诗/poet.song.187000.json','["未得歸山養聖胎，憑誰輕脫出山來。", "老猶作態經霜柳，靜有餘妍照水梅。", "大小場知惟酒戶，淺深難說是詩才。", "吟翁終欲招田父，只話桑麻共一杯。"]'),
('22f7fc91-2491-49b3-b6bc-08c473db72f4','鶴食','趙庚夫','宋','宋诗','song-poetry','','[]','鶴食從妻給，花窠課子鋤。',48,'全唐诗/poet.song.187000.json','["鶴食從妻給，花窠課子鋤。", "絕糧緣買硯，止酒爲躭書。", "野服迎人懶，禪心涉世疏。", "丹爐添火候，健似十年初。"]'),
('d24a64e9-e607-42fc-88e2-d8e2228000c5','同僧遊𤂌陽塘上生院','趙庚夫','宋','宋诗','song-poetry','','[]','沿堤上下看沙鷗，得句支筇自點頭。',64,'全唐诗/poet.song.187000.json','["沿堤上下看沙鷗，得句支筇自點頭。", "風露高時將鶴伴，溪山好處載僧遊。", "老無志願惟漁艇，閒有功夫上寺樓。", "歲晚淵明須自笑，督郵未至合歸休。"]'),
('b52c4e7d-76a3-400e-abaa-5ba23527884d','句  其一','趙庚夫','宋','宋诗','song-poetry','','[]','君家自在劍山外，莫浪江南勸路人。',16,'全唐诗/poet.song.187000.json','["君家自在劍山外，莫浪江南勸路人。"]'),
('11f4b42a-1ef9-42df-ac32-6ee84d74f9c3','句  其二','趙庚夫','宋','宋诗','song-poetry','','[]','故人埋玉僧歸塔，獨聽疎鐘起暮愁。',16,'全唐诗/poet.song.187000.json','["故人埋玉僧歸塔，獨聽疎鐘起暮愁。"]'),
('d1305c45-5b2e-4ef4-8316-ec91db9059a5','句  其三','趙庚夫','宋','宋诗','song-poetry','','[]','鶴殘籬外筍，鼠舐墨中膠。',12,'全唐诗/poet.song.187000.json','["鶴殘籬外筍，鼠舐墨中膠。"]'),
('ae92ae35-1566-41b7-a903-e8c22ddaf25d','句  其四','趙庚夫','宋','宋诗','song-poetry','','[]','詩句日從窗眼寫，墨丸夜入枕頭收。',16,'全唐诗/poet.song.187000.json','["詩句日從窗眼寫，墨丸夜入枕頭收。"]'),
('fbe07032-2668-416d-bfc3-7a4f7e2042ca','句','杜杲','宋','宋诗','song-poetry','','[]','父子俱開國，朝廷不負人。',12,'全唐诗/poet.song.187000.json','["父子俱開國，朝廷不負人。"]'),
('d8977950-4578-42bb-b7f7-42c38adddb85','改之下第賦贈','李大方','宋','宋诗','song-poetry','','[]','劉郎氣豪酒豪詩更豪，乃肯折節作賦遺恨無纖毫。',170,'全唐诗/poet.song.187000.json','["劉郎氣豪酒豪詩更豪，乃肯折節作賦遺恨無纖毫。", "詩雄賦老不入世俗眼，仰空大叫索酒歌離騷。", "劉郎新詩今莫敵，挑戰梅社無遺力。", "果然桃杏一山開，龍馬行天曉無跡。", "錦標重奪更一年，却來走馬春風前。", "撐腸文字五千卷，吟哦得意揚休鞭。", "世間榮辱俱遊戲，莫爲功名銷壯志。", "我輩胡顔自古然，劉蕡況是公家事。", "銀杯錦被驌驦裘，呼童喚酒鏖窮愁。", "自憐却被微官縛，不及相從上酒樓。"]'),
('b79c3ef0-eb14-43c0-8b84-0e2797305119','句  其一','李大方','宋','宋诗','song-poetry','','[]','三百年來今幾秋，天地自老江自流。',16,'全唐诗/poet.song.187000.json','["三百年來今幾秋，天地自老江自流。"]'),
('ca7650b1-b349-47dd-a0ef-2c9a9b3aec3a','句  其二','李大方','宋','宋诗','song-poetry','','[]','笛聲吹起白玉槃，正照御前楊柳碧。',16,'全唐诗/poet.song.187000.json','["笛聲吹起白玉槃，正照御前楊柳碧。"]'),
('14f4b56a-56a7-41fc-9d1f-116568c5db9c','句  其三','李大方','宋','宋诗','song-poetry','','[]','可憐一代經綸業，不抵鍾山幾首詩。',16,'全唐诗/poet.song.187000.json','["可憐一代經綸業，不抵鍾山幾首詩。"]'),
('55c82ba6-c0a8-4eac-a1ee-89e08d669249','句  其四','李大方','宋','宋诗','song-poetry','','[]','後院落花人不到，黄鸝飛下石榴陰。',16,'全唐诗/poet.song.187000.json','["後院落花人不到，黄鸝飛下石榴陰。"]'),
('545557ed-efd8-45f4-b5de-a3667cf4f0e4','觀山','趙汝謩','宋','宋诗','song-poetry','','[]','朅來快閣慰吾意，更說觀山傳舊年。',64,'全唐诗/poet.song.187000.json','["朅來快閣慰吾意，更說觀山傳舊年。", "不憚筍輿穿草棘，只知野叟足林泉。", "半空嵐影挂簷外，一徑凉颸過酒邊。", "料得涪山爲拈出，當時千尺不應然。"]'),
('efbf7dce-79f7-4bdf-9169-416e0f1d49d9','題富覽亭','張孝章','宋','宋诗','song-poetry','','[]','碧瓦朱甍接翠崖，周迴無地着纖埃。',64,'全唐诗/poet.song.187000.json','["碧瓦朱甍接翠崖，周迴無地着纖埃。", "山從雲脚斷邊出，水向天根盡處來。", "去蜀征帆輕渺渺，隔淮春樹綠洄洄。", "偷閒一到塵襟滌，坐見星河落酒杯。"]'),
('9f48a829-f274-4cc3-84d1-d773d79ecf2d','遊九鎖','楊邁','宋','宋诗','song-poetry','','[]','尋幽向何處，大滌山水好。',48,'全唐诗/poet.song.187000.json','["尋幽向何處，大滌山水好。", "九峰拔奇秀，下有松石老。", "白雲和紅葉，滿徑無人掃。", "振衣長風生，一笑登木杪。"]'),
('d415fb91-0c05-46f7-9750-0787b32df5f9','句','林士表','宋','宋诗','song-poetry','','[]','有書來進御，無語不關農。',12,'全唐诗/poet.song.187000.json','["有書來進御，無語不關農。"]'),
('af1792e1-4256-4ac9-875b-81866e008056','中閣禪院','留元崇','宋','宋诗','song-poetry','','[]','初來羅浮山，萬變駭林壑。',120,'全唐诗/poet.song.187000.json','["初來羅浮山，萬變駭林壑。", "更作招提遊，佳處在中閣。", "忽然天地間，一縱千里目。", "未論雲頂上，此景占仍獨。", "近聞泉涓涓，青眺山簇簇。", "簷壓喬松低，檻有餘霞落。", "長風東南來，皓月襟袖薄。", "境靜僧幽閒，意遠味淡泊。", "抱琴歸去來，禪榻寄一宿。", "白雲依古山，青霄起孤鶴。"]'),
('44ecadb4-29bf-46df-a65f-06baf5031f90','卓錫泉','留元崇','宋','宋诗','song-poetry','','[]','尋仙得招提，借我此歇脚。',48,'全唐诗/poet.song.187000.json','["尋仙得招提，借我此歇脚。", "瓜棗未暇求，杯水得甘酌。", "境空風泉高，夜永雲卧薄。", "明當約麻姑，石橋騎白鶴。"]'),
('73374a30-b694-40ad-8c1a-241ab3059f2c','又題卓錫泉','留元崇','宋','宋诗','song-poetry','','[]','吾師知地脈，杖錫此間卓。',120,'全唐诗/poet.song.187000.json','["吾師知地脈，杖錫此間卓。", "分占神仙囿，敲出清泠玉。", "錫飛已乘龍，泉潔可飲鶴。", "林下幾寒暑，池中不盈涸。", "木石常借潤，瓶罌隨量足。", "池無汲綆線，逗引走修竹。", "渴心生塵埃，對此愜所欲。", "洗耳聽松音，潄齒汲山綠。", "更携一壺歸，爲浣衆生濁。", "遥愧山中人，四時自斟酌。"]'),
('1756eacc-4a26-49a0-bcff-0e8e7b4b2a5a','羅浮','留元崇','宋','宋诗','song-poetry','','[]','神仙神山羅與浮，二山東來幾千秋。',112,'全唐诗/poet.song.187000.json','["神仙神山羅與浮，二山東來幾千秋。", "蓬萊夜半失左股，龍驚虎噉玉女愁。", "至今兩山翠欲滴，却與蓬萊比山色。", "黄金作橋通九霄，水晶爲簾挂千尺。", "神仙舊說何渺茫，神仙窟宅今何望。", "仙翁在山泉水香，仙翁飛去松風長。", "我將浣手扣玉戶，乞杯長生九霞觴。"]'),
('3f23e6e5-71d4-48fd-8a66-cb712e505025','茶園','留元崇','宋','宋诗','song-poetry','','[]','嶺根聞犬吠，上到野人家。',48,'全唐诗/poet.song.187000.json','["嶺根聞犬吠，上到野人家。", "山晚月有色，天寒梅未花。", "蔬園依水石，茅屋带煙霞。", "何物堪留客，烹茶成雪芽。"]'),
('0848e97c-785a-4853-b532-48f4fd8d2169','遊羅浮','留元崇','宋','宋诗','song-poetry','','[]','遠看空碧混崔嵬，近見重重翠作堆。',64,'全唐诗/poet.song.187000.json','["遠看空碧混崔嵬，近見重重翠作堆。", "古木陰中藏洞府，亂雲深處出樓臺。", "文禽耀日來相喚，羽客乘風去不回。", "惟有東坡舊遊跡，屐痕猶自遍蒼苔。"]'),
('4bd00466-4a9b-4577-9854-e29e2b844c70','天漢橋','留元崇','宋','宋诗','song-poetry','','[]','誰人挽落天河水，飛向寒崖無古今。',32,'全唐诗/poet.song.187000.json','["誰人挽落天河水，飛向寒崖無古今。", "寄語山靈好呵護，書儒從此得知音。"]'),
('041a43f1-6af3-439f-afb4-fb66830eb032','卓錫泉','留元崇','宋','宋诗','song-poetry','','[]','風月衿懷歉古人，蕭然天地一閒身。',32,'全唐诗/poet.song.187000.json','["風月衿懷歉古人，蕭然天地一閒身。", "夜來偶讀唐庚記，貫石通泉在一真。"]'),
('e25efa8b-af18-4576-9240-10d45f521069','慈濟庵二首  其一','留元崇','宋','宋诗','song-poetry','','[]','笑指星壇近斗傍，七松上映七星光。',32,'全唐诗/poet.song.187000.json','["笑指星壇近斗傍，七松上映七星光。", "黄龍洞口胡麻飯，不是神仙不得嘗。"]'),
('491373c3-d025-4a49-821a-02e51f3a3c27','慈濟庵二首  其二','留元崇','宋','宋诗','song-poetry','','[]','歸自星壇日未斜，草庵留住一杯茶。',32,'全唐诗/poet.song.187000.json','["歸自星壇日未斜，草庵留住一杯茶。", "道人自點花如雪，云是新收白露芽。"]'),
('b04f3207-cd56-4534-a4d5-c80bdb293274','高宗皇帝挽詞二首  其一','倪思','宋','宋诗','song-poetry','','[]','稽古神文煥，中興武烈光。',48,'全唐诗/poet.song.187000.json','["稽古神文煥，中興武烈光。", "挈圖親授子，體道妙爲皇。", "萬乘隆尊養，千齡甫壽康。", "龍湖俄趣駕，遽返白雲鄉。"]'),
('1b3932cc-bd5a-4860-bf54-385b7dbdb6b2','高宗皇帝挽詞二首  其二','倪思','宋','宋诗','song-poetry','','[]','黼翣方徐轉，龍輴望已遥。',48,'全唐诗/poet.song.187000.json','["黼翣方徐轉，龍輴望已遥。", "胥濤平似掌，禹穴儼如朝。", "喪考群心痛，號旻聖孝昭。", "稽經崇廟號，萬世永尊堯。"]'),
('74527f64-235e-4d4f-b1d2-60c3336b67c8','南劍道中桂','倪思','宋','宋诗','song-poetry','','[]','道傍巖桂老成行，翠葉經冬不著霜。',32,'全唐诗/poet.song.187000.json','["道傍巖桂老成行，翠葉經冬不著霜。", "想見秋清風月裏，綴金粟顆賸輸香。"]'),
