('11a0203f-c305-4cad-b18f-364bd1d7628c','螢','錢時','宋','宋诗','song-poetry','','[]','一點暉暉落扇間，欲飛還撲近欄干。',32,'全唐诗/poet.song.187000.json','["一點暉暉落扇間，欲飛還撲近欄干。", "乾坤日月光明藏，莫作書邊冷眼看。"]'),
('e15877d8-20bc-4698-b7c8-7063607fd0da','聞子居近况','錢時','宋','宋诗','song-poetry','','[]','十里溪山別兩年，忽聞消息爲欣然。',32,'全唐诗/poet.song.187000.json','["十里溪山別兩年，忽聞消息爲欣然。", "把書簷下往來看，不覺人行到面前。"]'),
('bdbae3d9-3309-4fa1-9ec3-4dce0b62cb95','南塘歸途','錢時','宋','宋诗','song-poetry','','[]','岩花消息晚來風，透出長林萬萬重。',32,'全唐诗/poet.song.187000.json','["岩花消息晚來風，透出長林萬萬重。", "一句好詩拈不出，乾坤都屬廣寒宮。"]'),
('41148098-e77e-4129-8492-66c6badc8b8a','謝守和章及先天之旨','錢時','宋','宋诗','song-poetry','','[]','未消着眼到潛虛，那復談經上石渠。',32,'全唐诗/poet.song.187000.json','["未消着眼到潛虛，那復談經上石渠。", "會得先天無別旨，困眠饑飯更求餘。"]'),
('79eb13c8-303c-4d43-9a8a-263f8efb7de0','合溪座上','錢時','宋','宋诗','song-poetry','','[]','深碧沉沉冷欲秋，此時亭上飽追遊。',32,'全唐诗/poet.song.187000.json','["深碧沉沉冷欲秋，此時亭上飽追遊。", "溪分溪合關何事，尚欠圜機訂九流。"]'),
('6219e40f-b5de-4057-9bcc-b33796568041','徐簿餉烏飯八月八日','錢時','宋','宋诗','song-poetry','','[]','紅薑黑飯薦珍羞，愧爾瞿曇老比邱。',32,'全唐诗/poet.song.187000.json','["紅薑黑飯薦珍羞，愧爾瞿曇老比邱。", "先聖兒孫今滿地，有人能記誕彌不。"]'),
('6f859766-f472-412d-95a5-9a20f236d7d6','睡起','錢時','宋','宋诗','song-poetry','','[]','雨浥蒲風晚更凉，數花薝蔔凈生香。',32,'全唐诗/poet.song.187000.json','["雨浥蒲風晚更凉，數花薝蔔凈生香。", "高眠深穩清無夢，儘覺人間白晝長。"]'),
('bef58a0e-49f0-4b84-9186-99523b08ea94','蝸牛','錢時','宋','宋诗','song-poetry','','[]','雨浥蝸牛遶砌行，與吾同樂本同生。',32,'全唐诗/poet.song.187000.json','["雨浥蝸牛遶砌行，與吾同樂本同生。", "擠排蠻觸分疆界，可笑蒙莊自起爭。"]'),
('ad37f970-2f3f-44fa-ac3b-fe044d13d9a2','去年五月十八日歸自唐山感舊','錢時','宋','宋诗','song-poetry','','[]','新嶺歸來整一年，老夫心事只依然。',32,'全唐诗/poet.song.187000.json','["新嶺歸來整一年，老夫心事只依然。", "何曾礙却家常飯，國史宏綱手自編。"]'),
('9334c036-ee42-4366-b296-93a67a1a39f2','當食自喜二首  其一','錢時','宋','宋诗','song-poetry','','[]','飲食無他止養身，人間多少不惺惺。',32,'全唐诗/poet.song.187000.json','["飲食無他止養身，人間多少不惺惺。", "朝晡細嚼家常飯，一卷神農本草經。"]'),
('facf37bc-0967-481b-a3c4-7b2f5c6665ae','當食自喜二首  其二','錢時','宋','宋诗','song-poetry','','[]','旋摘園蔬隨意好，軟炊土米遶牙香。',32,'全唐诗/poet.song.187000.json','["旋摘園蔬隨意好，軟炊土米遶牙香。", "人言少喫多滋味，此是尊生第一方。"]'),
('f79c2fbc-858f-4f6f-aade-ed6fa6dfcfa1','得片石著歲寒欄干外二首  其一','錢時','宋','宋诗','song-poetry','','[]','梅竹交陰晚更奇，等閑片石亦相宜。',32,'全唐诗/poet.song.187000.json','["梅竹交陰晚更奇，等閑片石亦相宜。", "此時亭上瀟瀟雨，牆外行人却未知。"]'),
('05b968c9-e01c-458f-adb5-1aab5e5fa21a','得片石著歲寒欄干外二首  其二','錢時','宋','宋诗','song-poetry','','[]','片石飛來入品題，曲欄池上爾偏宜。',32,'全唐诗/poet.song.187000.json','["片石飛來入品題，曲欄池上爾偏宜。", "老懷易得生歡喜，冷面相看又賦詩。"]'),
('dbb1c3ea-c5a0-4975-82a9-03d8759bf428','對老輩語兒時事','錢時','宋','宋诗','song-poetry','','[]','回首春風逞少年，厭聞人說舊因緣。',32,'全唐诗/poet.song.187000.json','["回首春風逞少年，厭聞人說舊因緣。", "而今恨不逢班輩，說著兒時在眼前。"]'),
('1d94bd82-9e5b-4f8a-afe8-afff2c84636b','步月庭下  其一','錢時','宋','宋诗','song-poetry','','[]','秋花恰恰到秋中，透頂生香滿院風。',32,'全唐诗/poet.song.187000.json','["秋花恰恰到秋中，透頂生香滿院風。", "浪說霓裳天上曲，全家都在廣寒宮。"]'),
('e1a78df4-0795-4fad-9989-0111ee062c7a','步月庭下  其二','錢時','宋','宋诗','song-poetry','','[]','幾年等得到花開，投老看花能幾回。',32,'全唐诗/poet.song.187000.json','["幾年等得到花開，投老看花能幾回。", "四樹婆娑庭下桂，月明深夜更徘徊。"]'),
('beb3e730-9372-4014-ac76-42cbe2564997','新亭觀菊二首  其一','錢時','宋','宋诗','song-poetry','','[]','碧天無際細浮香，淺白深黄未著霜。',32,'全唐诗/poet.song.187000.json','["碧天無際細浮香，淺白深黄未著霜。", "莫恨花開秋向晚，晚秋方是好風光。"]'),
('8b1349ac-0a78-4841-a236-7f1fb048d3ee','新亭觀菊二首  其二','錢時','宋','宋诗','song-poetry','','[]','日融香煖閙枝頭，遶砌回環看不休。',32,'全唐诗/poet.song.187000.json','["日融香煖閙枝頭，遶砌回環看不休。", "莫把此花容易看，東籬無菊不成秋。"]'),
('0b82b41f-ef8a-4055-9745-76a2183adddf','晨興池上觀梅','錢時','宋','宋诗','song-poetry','','[]','雙鵲查查曉戀枝，暗香風度曲欄池。',32,'全唐诗/poet.song.187000.json','["雙鵲查查曉戀枝，暗香風度曲欄池。", "日來只了高齋去，滿樹花開總不知。"]'),
('26f9ee36-c1ec-47d5-8b49-add20f0360e1','除日暮放鯽魚於月池者九夜再得六復秉燭放之偶合陰陽老數成一絕','錢時','宋','宋诗','song-poetry','','[]','除夕生魚有異逢，挑燈兩度散春風。',32,'全唐诗/poet.song.187000.json','["除夕生魚有異逢，挑燈兩度散春風。", "莫言九六無心得，須信乾坤一念中。"]'),
('745b4e1d-7e12-4be3-9053-81e9203968a7','池上梅復開一花今數日矣始成絕句','錢時','宋','宋诗','song-poetry','','[]','一花消息小春前，冷眼相看似故年。',32,'全唐诗/poet.song.187000.json','["一花消息小春前，冷眼相看似故年。", "但覺老懷詩漸懶，畧無行遣到花邊。"]'),
('77a02c43-7820-4b95-b95f-bd64eb40a0cb','示槱','錢時','宋','宋诗','song-poetry','','[]','詩成正自不因題，看取風人發興時。',32,'全唐诗/poet.song.187000.json','["詩成正自不因題，看取風人發興時。", "語到口頭無可奈，未須搜攪苦吟詩。"]'),
('27d2aaf5-b6ef-4c3f-8968-1df3e70d7d90','精廬枕上','錢時','宋','宋诗','song-poetry','','[]','山隠夜來山月好，幽香滿地開花草。',32,'全唐诗/poet.song.187000.json','["山隠夜來山月好，幽香滿地開花草。", "竹梢墮露鳴屋瓴，谷鳥一聲報清曉。"]'),
('d17cc510-54b9-4bc8-b690-d99e59d337e7','九月一日睡起','錢時','宋','宋诗','song-poetry','','[]','帖帖冬窩眠正穩，剝地鐘聲忽敲醒。',32,'全唐诗/poet.song.187000.json','["帖帖冬窩眠正穩，剝地鐘聲忽敲醒。", "起來空堂一事無，日弄波紋滿窗影。"]'),
('a501be76-c5b5-4522-8a2b-dccdc4a99271','夜半觀潮','錢時','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','月夜舟如天上坐，極目更無山一箇。',32,'全唐诗/poet.song.187000.json','["月夜舟如天上坐，極目更無山一箇。", "海神夜半忽出奇，雷鼓長驅雪山過。"]'),
('c3a1607f-2aee-47b7-bd75-67e8583b324f','泊四板橋沙外觀月','錢時','宋','宋诗','song-poetry','','[]','江海無波渺吳越，遠山數點低如抹。',32,'全唐诗/poet.song.187000.json','["江海無波渺吳越，遠山數點低如抹。", "長空浸碧秋沉沉，端正江心一輪月。"]'),
('68e888fc-f005-4a8e-ad9a-cc75c00fb13d','冬窩夜語','錢時','宋','宋诗','song-poetry','','[]','幽人只合卧林邱，不覺心幽境更幽。',64,'全唐诗/poet.song.187000.json','["幽人只合卧林邱，不覺心幽境更幽。", "青汗有時昭帝則，黑甜餘暇伴賓游。", "黄花粲粲冬窩夜，丹葉蕭蕭蜀阜秋。", "會得箇中消息理，兩眉不著世間愁。"]'),
('7273987a-6ac7-40fe-bce1-805fb2863253','聯輝閣詩','錢時','宋','宋诗','song-poetry','','[]','拂拂精藍護翠雲，幾番雷雨卧龍興。',64,'全唐诗/poet.song.187000.json','["拂拂精藍護翠雲，幾番雷雨卧龍興。", "兩賢高躅明千佛，三世傳家又一燈。", "白社風流原有地，青編事業豈依僧。", "山川姓字從茲響，看取天衢次第登。"]'),
('835f061f-a39f-4756-9afa-7e2b008c184d','義貓行','錢時','宋','宋诗','song-poetry','','[]','我家老狸奴，健捕無其比。',216,'全唐诗/poet.song.187000.json','["我家老狸奴，健捕無其比。", "去年能養兒，二男而一女。", "種草不碌碌，趫捷俱可喜。", "策勳到鄰家，高卧不憂鼠。", "今年女子七，母復誕三子。", "三子乳有餘，七子不易耳。", "頗似相軫念，抱弄時相乳。", "依依同氣恩，髣髴見情理。", "一日忽銜子，來同七子處。", "薰然如一家，雜乳無彼己。", "天地即我心，萬物非異體。", "一日脫邊幅，此外無別旨。", "嗟彼胡不仁，形骸分爾汝。", "同類日相傷，呀然矜爪觜。", "探巢攫胎卵，吞噬不知止。", "但見己子肥，遑恤他子死。", "貓也本虎屬，能爲義士舉。", "作詩傳世間，一獸有如此。"]'),
('7ad1cda2-8221-4735-9815-d8a9e0fa5ad4','遊齊山倉使遣贈長歌和韵','錢時','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','昔來陽未復，倏忽今大壯。',288,'全唐诗/poet.song.187000.json','["昔來陽未復，倏忽今大壯。", "頗復懷茲遊，山山日環鄉。", "雪多春較澀，寒力花難王。", "晨興起和羹，御風颯然往。", "嵌空互出奇，峭立屹相並。", "應接不暇瞬，跬步即異狀。", "明遊俱可人，心愜有餘况。", "寄隠定何許，醒翁本無相。", "渾渾太古前，此巧豈天匠。", "天亦莫能名，誰歟實開創。", "妙空與上清，可笑渠汝誑。", "繡春最孤絕，勢壓翠微上。", "一带抹長江，羣雉拱千嶂。", "超覽妙無涯，天地入吾量。", "疇能事劖鎸，瑣瑣較真妄。", "所乏者古木，無木更虛曠。", "蠻觸戰封疆，鷄蟲爭得喪。", "坐縛萬古癡，無病自生恙。", "好是兩忘猜，不勞費監謗。", "載弄陽春曲，萬彙同盎盎。", "長歌卷雪腴，頗恨阻搜訪。", "此事屬臞仙，公勿多怊悵。", "東山掛遊屐，皇猷頼公暢。", "玉堂深復深，夜植青藜杖。"]'),
('7de85c0f-016a-408d-9a16-37236a2847b2','聞兒輩舉漁者言喜成古調','錢時','宋','宋诗','song-poetry','','[]','魚固人所欲，痰飲常忌此。',168,'全唐诗/poet.song.187000.json','["魚固人所欲，痰飲常忌此。", "茲晨一杯羹，食之乃大美。", "漁者包裹來，樂與我爲市。", "兒輩問何故，秤平不虧爾。", "吾家自高曾，仁厚著閭里。", "一衡無兩權，昭昭坦如砥。", "憶昔少年時，獵夫晨賣鹿。", "老幹持衡出，忽爾非舊比。", "此豈我家風，責之怒裂眥。", "口腹詐求贏，寧我餓而死。", "忍割子孫肉，而以啖我齒。", "折衡謝獵夫，勞酒遣乃已。", "今餘三十載，而得聞斯語。", "喜與同志言，書之詔孫子。"]'),
('e749e7c2-cc19-48c5-9b94-a76368d80aaf','余與呂守之買舟西歸林常甫吳清淑呂伯起出餞江樓古調以別','錢時','宋','宋诗','song-poetry','','[]','兩角勍觸蠻，八荒等兄弟。',192,'全唐诗/poet.song.187000.json','["兩角勍觸蠻，八荒等兄弟。", "人生天地間，貴在情義耳。", "嘉禾二三友，一見傾底裏。", "春風散天和，非彼亦非此。", "清淑溫以直，常甫正而美。", "東涉金沙雪，西挹錢塘水。", "舟泛月雙湖，轡聯松九里。", "冬春朔四換，追隨實終始。", "宣橋歲云暮，乃復得伯起。", "頎然出玉山，臭味林吳似。", "修門亦旬月，朝夕相料理。", "餞我江上樓，樓欄豁天宇。", "海山渺無際，呼吸入窗几。", "長鯨駭高浪，卷舒在吾趾。", "風帆擘天出，揖別苦無語。", "共挽春江濤，洒作蒼生雨。"]'),
('44eb03f2-8ca3-4b45-aa4c-06c9590ec96b','偶書','錢時','宋','宋诗','song-poetry','','[]','世上紛紛競奇巧，人人自巧不知寶。',160,'全唐诗/poet.song.187000.json','["世上紛紛競奇巧，人人自巧不知寶。", "此巧本不屬思爲，妙質融融復皜皜。", "天地萬象羅其中，縱橫變化無時窮。", "珠璧隠現光錯落，丹青組織花瓏葱。", "有時六出不停翦，有時柔茵鋪地遍。", "有時飛空調羽商，嘈雜間關聲百囀。", "千態萬狀難形容，欲著一語迷西東。", "宣尼但說不可見，後學强名造化工。", "我欲從渠問誰造，不覺低頭發長笑。", "且不可見那可言，春秋冬夏無非教。"]'),
('0fce8a5e-cfc7-409a-b18f-57b179e1f780','機舂歌','錢時','宋','宋诗','song-poetry','','[]','機舂結草溪之唇，翳桑古柳聯清陰。',128,'全唐诗/poet.song.187000.json','["機舂結草溪之唇，翳桑古柳聯清陰。", "無人認得東流水，如此妙旨誰知音。", "碧渠走峻琉璃滑，鳴瀑怒卷波瀾闊。", "飛輪轉撥無已時，試問此機是誰發。", "此機欲見妙無形，此機那復聲可聞。", "自從清濁未高下，直至而今無暫停。", "上有茅齋人靜止，日用變化心如水。", "齋名果育定何如，爲言只此機舂是。"]'),
('a59c87c2-e3d2-4a80-9c88-311467b72694','山翁吟','錢時','宋','宋诗','song-poetry','','[]','歲云暮矣雪塞門，白髮山翁病且貧。',64,'全唐诗/poet.song.187000.json','["歲云暮矣雪塞門，白髮山翁病且貧。", "鶉衣百結皮凍裂，旦暮撥雪尋草根。", "催租暴卒打門戶，妻子驚逃翁怖懼。", "盡道長官如母慈，如何赤子投機虎。"]'),
('5e80dadb-5bc9-427f-a128-b1542c502f8c','書感','錢時','宋','宋诗','song-poetry','','[]','狥利者不可與謀義，怙私者不可與言公。',100,'全唐诗/poet.song.187000.json','["狥利者不可與謀義，怙私者不可與言公。", "蠻觸勝負勍兩角，肝膽乃有楚越同。", "陽清陰濁難同宮，弱水西流河漢東。", "洪河砥柱霜中松，中道而立能者從。", "凡百君子宜自愛，何苦下與瑣瑣爭雞蟲。", "朝來滿室生秋風，庭樹兩葉三葉紅。"]'),
('cb3424d4-b37d-41b2-b517-e3669d95d52e','蠶婦歎','錢時','宋','宋诗','song-poetry','','[]','蠶婦拂蠶葉如縷，愛之何啻珠玉比。',114,'全唐诗/poet.song.187000.json','["蠶婦拂蠶葉如縷，愛之何啻珠玉比。", "呼奴勤向帳前看，夜卧靡寧三四起。", "未必便能絲掛體，睠焉于懷有真喜。", "人人辦得此時心，推而廣之豈不美。", "以此事君定忠臣，以此事父定孝子。", "以此事夫定賢婦，一念真成轉樞耳。", "嗟哉世人胡不然，三綱茫茫不如蠶一紙。"]'),
('5bebd14c-3af9-46e7-b320-c44fd78cda3a','贈墨工','錢時','宋','宋诗','song-poetry','','[]','客來投我一點漆，快汲清泉洗端石。',128,'全唐诗/poet.song.187000.json','["客來投我一點漆，快汲清泉洗端石。", "晴窗凈几試一揮，錯落精神光照日。", "如此妙質奇復奇，變化縱橫隨所施。", "可憐自有不自寶，日用紛紛誰得知。", "願言莫染荒唐辭，亦莫隨俗供妍媸。", "雜學支離二千載，汗牛充棟終何爲。", "由來此物自神聖，妙不可言那可盡。", "分明宇宙在毫端，萬古糊塗人不信。"]'),
('f9836a79-cd00-4806-bdea-edcc8ab669d2','子山弟因病有感喜成長句','錢時','宋','宋诗','song-poetry','','[]','本支兄弟十一人，眼前僅有六人存。',128,'全唐诗/poet.song.187000.json','["本支兄弟十一人，眼前僅有六人存。", "于中少者亦頭白，世事短長難具論。", "老兄年來苦多疾，安樂窩中且將息。", "肯復營營供物奴，頗聞吾弟今得力。", "是身出沒如雲浮，彈指百年誰轉頭。", "死生富貴自天命，本無一事吾何求。", "我聞旡妄不須藥，君行有眚君應覺。", "鴒原未用憂急難，且來伴我山中樂。"]'),
('d9d9e6ab-93ce-496d-bcb4-b60f7295353c','篙師歎','錢時','宋','宋诗','song-poetry','','[]','山鄉山多田種稀，年豐健婦猶啼饑。',128,'全唐诗/poet.song.187000.json','["山鄉山多田種稀，年豐健婦猶啼饑。", "今年禾黍秋旱死，不有下澗民枯魚。", "頗聞水鄉諸郡熟，一飽可令餘郡足。", "江船下米無頭由，商人嗷嗷坐窮蹙。", "長年抱膝指屢彈，時節自好官司難。", "古來鄰國忍爲壑，何乃境內成觸蠻。", "我聞斯言真的當，無人爲徹九天上。", "禁江徒爾厄吾民，海舶有時關節放。"]'),
('cfecc1f3-9ed9-4a14-add4-bd0a7937b67b','小甆瓶','錢時','宋','宋诗','song-poetry','','[]','小甆瓶，形模端正玉色明。',135,'全唐诗/poet.song.187000.json','["小甆瓶，形模端正玉色明。", "烏聊山邊纔百文，見者嘆賞不容聲。", "乃知物無賤與貴，要在制作何如耳。", "輪囷如瓠不脫俗，雖玉萬鎰吾何取。", "王正二日聞斯言，欣然爲賦甆瓶篇。", "濁世憒憒隨風旋，跖不夷謀吁可憐。", "百年氣節一朝捐，身落糞壤心窬穿。", "豈不見齊田魯季勢薰天，萬世之下簞瓢賢。", "熊也勉旃然不然。"]'),
('932ac5a3-0040-451d-99b7-14bc3ecfa7c9','留仲謙','錢時','宋','宋诗','song-poetry','','[]','二十年前舊詩友，子居仲謙真耐久。',96,'全唐诗/poet.song.187000.json','["二十年前舊詩友，子居仲謙真耐久。", "少時懷抱易過逢，老去雲林難聚首。", "去年廣塾得子居，論心豈但相煦濡。", "咫尺仲謙招不得，有園日涉將毋娛。", "風吹原頭動春色，招携肯爲山翁出。", "恰恰子居來日來，巋然暮展遥天碧。"]'),
('4ca06de0-6a41-4f53-a64d-44577b13afae','讀書燈','錢時','宋','宋诗','song-poetry','','[]','讀書燈，明暳暳，溪堂故人親送似。',192,'全唐诗/poet.song.187000.json','["讀書燈，明暳暳，溪堂故人親送似。", "歷落平生未見書，與汝間關幾半世。", "幾年來，味無味，併與青編共捐棄。", "半身淪落浙江濆，壁角破圈塵沒鼻。", "新春忽爾思起廢，頃刻工夫依前具。", "提入山翁結草廬，永夜虛窗照天地。", "聖教衰，異端熾，千古冥行士何事。", "人人有此大光明，埋沒荒唐渺漫處。", "象山翁，天啟秘，嫡嗣慈湖更超詣。", "陋儒俗學破沉痾，暗室迷途逢寶炬。", "讀書燈，明一切，不是山翁愛文字。", "逢人若問伏羲前，燈下齁齁方瞌睡。"]'),
('570b8e27-fd29-413c-ae71-a4d0a6cc77a8','庚辰錄譬如結款他日打斷得了方成一段公案耳子居命時潤色此殆謙詞敬賡韵以謝','錢時','宋','宋诗','song-poetry','','[]','萬馬一隙爭匆匆，回頭祇是人心同。',64,'全唐诗/poet.song.187000.json','["萬馬一隙爭匆匆，回頭祇是人心同。", "百聖妙旨本無語，的的末在詩句工。", "我生賸愧晚知學，可把蕪詞污新作。", "玄冬深夜君試聽，萬竅號風皆木鐸。"]'),
('360b5e1f-cf47-40c2-b5b7-5a2f21edd630','贈日者','錢時','宋','宋诗','song-poetry','','[]','世上癡兒愛官職，買山不作千金惜。',64,'全唐诗/poet.song.187000.json','["世上癡兒愛官職，買山不作千金惜。", "烏囊費盡鐵鞋穿，近在方寸人不識。", "公卿將相無時無，安得生賢爲楷模。", "嵩岳降神尼毓聖，此倘有地君其圖。"]'),
('84b84241-2ed1-40aa-b1fe-cea9bc657dfc','示槱默  其一','錢時','宋','宋诗','song-poetry','','[]','男兒頭上三尺紗，不比脚纏三尺帛。',99,'全唐诗/poet.song.187000.json','["男兒頭上三尺紗，不比脚纏三尺帛。", "桑弧蓬矢射天地，墮地已展青雲翮。", "四海九州多勝流，不出戶庭空白頭。", "有識難與俗同調，非才何必緣遠遊。", "豈不見赤驥摇足日千里，何煩揮策苦鞭摇。", "目前㹠犬奚爾爲，逐逐一飽糠籺肥。"]'),
('42b9c7a0-cb16-4cc3-a54f-b4299a6d4b75','示槱默  其二','錢時','宋','宋诗','song-poetry','','[]','飛蛾戀逐眼前光，身殞膏火空茫茫。',96,'全唐诗/poet.song.187000.json','["飛蛾戀逐眼前光，身殞膏火空茫茫。", "蛆蠅變化出復沒，生死不離污穢場。", "求之有道得有命，可把枯榮亂邪正。", "進德修業當及時，去去光陰難語進。", "汝爲君子無靦顔，啜菽飲水盡親歡。", "不然正使位一品，九地含羞吾得瞑。"]'),
('f351bd8d-d26a-4ef6-a8be-0e665b92142c','漁浦夜雪懷季敭','錢時','宋','宋诗','song-poetry','','[]','季敭欲我來山陰，季思欲我歸嚴陵。',96,'全唐诗/poet.song.187000.json','["季敭欲我來山陰，季思欲我歸嚴陵。", "嚴陵山陰兩無住，來去於我如浮雲。", "飛雪漫漫浙江暮，朔風吹船漁浦渡。", "咫尺不到興有餘，底須夜出山陰路。", "東華塵土緇人衣，顧瞻禹穴何巍巍。", "克艱一言萬世師，季敭季敭何時歸。"]'),
('72354b21-dfbe-4ebd-a08f-94cc12fdf2dd','端忞疲於哺蠶老婦憫而餉之余作古調以贊之','錢時','宋','宋诗','song-poetry','','[]','族孫買葉中山歸，惻然聞之矜爾疲。',96,'全唐诗/poet.song.187000.json','["族孫買葉中山歸，惻然聞之矜爾疲。", "長腰豚蹄亟送似，未暇問到而蠶饑。", "此時此念難藏假，廐焚退朝遑恤馬。", "馬非不愛愛我人，用違其才終土苴。", "試問母今蠶幾筐，間關未必能補瘡。", "我亦有蠶非條桑，他日天機雲錦裳。"]'),
('dd660b1e-18b2-46d7-a08b-f56ab15e2a75','杰姪所居之前舊無竹二月中忽出筀筍一根特立可愛爲賦長句','錢時','宋','宋诗','song-poetry','','[]','舊聞四月筀，不聞二月萌。',120,'全唐诗/poet.song.187000.json','["舊聞四月筀，不聞二月萌。", "籜龍忽當門，頭角何崢嶸。", "朅來此地荒穢耳，遠隔長林不相倚。", "群穉猶埋糞壤中，挺然劍拔參天起。", "人云瑞應非偶然，妙不可詰那可言。", "孰前孰後孰爲瑞，孰識此根天地先。", "祇今孤秀駭衆目，半脫錦綳聳新綠。", "善守勿令風雨摧，他年滿地皆修竹。"]'),
('27fc4d84-981b-4a50-aa14-3dae6d8cb720','杰姪有萬事分已定二詩信筆成和','錢時','宋','宋诗','song-poetry','','[]','萬事分已定，胡爲但戚戚。',52,'全唐诗/poet.song.187000.json','["萬事分已定，胡爲但戚戚。", "不爲麟鳳爲虺蛇，不種芝蘭種荆棘。", "芝蘭有餘香，麟鳳爲世祥。", "荆棘動成礙，虺蛇終自傷。"]'),
('c4073104-5aca-4121-8ee1-a43184ea1bbc','穉女談命有感','錢時','宋','宋诗','song-poetry','','[]','韓將軍出金鎗班，調官挈家來西山。',100,'全唐诗/poet.song.187000.json','["韓將軍出金鎗班，調官挈家來西山。", "嗟哉厲鬼不汝貸，一妻二女何間關。", "失身醉仙漫餬口，不知命落醉仙手。", "嬌少年才十二三，敲金便着紅塵走。", "憶昔干戈多亂離，草間公卿兒女啼。", "但願吾皇有道守四夷，未消瑣瑣且爲將軍悲。"]'),
('62e67710-95bf-4378-a1f5-56170c985ed5','題方大夫家訓','錢時','宋','宋诗','song-poetry','','[]','中興天子方御戎，長城萬里張魏公。',99,'全唐诗/poet.song.187000.json','["中興天子方御戎，長城萬里張魏公。", "此時此家盡好武，抵掌一呼來幕中。", "幕中羣雄肝膽烈，指顧關河日彈鋏。", "若爲歲晚歸課兒，只說讀書興農業。", "定知萬事俱弗如，豈直鎗劍輸毛錐。", "君不見二十七年耕草廬，出師一表汗青書。"]'),
('529e6709-b7f7-4fa7-beec-d04a593984d6','用守之盟七友歌韵示諸子','錢時','宋','宋诗','song-poetry','','[]','學兵須學兵無敵，學醫須學醫無疾。',128,'全唐诗/poet.song.187000.json','["學兵須學兵無敵，學醫須學醫無疾。", "學詩須學詩無邪，絕義世間非浪出。", "長虹貫日天與力，枯腸正好耕六籍。", "舞雩千載詠而歸，小技文章那可屈。", "蜀阜家風日日奇，萬竹深園暮天碧。", "朱絲好鳥共幽哢，迭奏黄鐘與無射。", "兒曹作計終自愛，莫把榆枋礙雲翼。", "康節有言良足珍，衣到弊時多蟣蝨。"]'),
('12cd0e4a-035c-4ff3-86aa-ef96fe5a0235','喜諸子所和詩盟歌俱有可采再用韵見意','錢時','宋','宋诗','song-poetry','','[]','蠻觸封疆日勍敵，金丹不療膏肓疾。',131,'全唐诗/poet.song.187000.json','["蠻觸封疆日勍敵，金丹不療膏肓疾。", "抖擻風埃發詩骨，參差頭角嶄然出。", "老夫所志在大雅，諸子政須勤帝籍。", "三歎變風我心惻，箾韶忍受淫哇屈。", "豈不見渭川千畝拂雲長，前日手栽數寸碧。", "苟得其養終巨世，勿玩流光生厭射。", "世間淺者無遠識，如獸繫足鳥摧翼。", "伯樂眼空冀北羣，湯鼎坐弔淮南蝨。"]'),
('e7fb4e65-3484-4dcc-ba4e-0bccfec43153','用樵姪漁舟韵','錢時','宋','宋诗','song-poetry','','[]','樂天知命吾何求，粗繒大布心休休。',105,'全唐诗/poet.song.187000.json','["樂天知命吾何求，粗繒大布心休休。", "小山松桂歲寒友，一日不見如三秋。", "白雲岩上飛相逐，白雲巖前一窗足。", "秋花未落春花開，辦得工夫驚寵辱。", "長安貴人爭輕肥，高桅大柁去復來。", "豈不見漁子好生涯，受用不盡一瓜皮，炙手可熱渠得知。"]'),
('8c723207-d872-492a-8d34-f38574b2b586','中秋約子溫兄子山弟小酌一展壽慶兩大字賦長句','錢時','宋','宋诗','song-poetry','','[]','前年齊山得壽字，體勢端方嵩嶽峙。',128,'全唐诗/poet.song.187000.json','["前年齊山得壽字，體勢端方嵩嶽峙。", "今年包帚書慶圖，更覺龍驤而虎踞。", "今我幸爲堯舜民，賢者送似生精神。", "壽匪自天實由我，慶果何物寧緣人。", "西風縹緲中秋節，滿院巖花香正冽。", "團圞兄弟小持觴，二字一展相娛悅。", "安得突兀起高堂，名以壽慶當中央。", "吾三人者和且康，年年此日岩花香。"]'),
('e2bb33ce-f076-4c9f-911d-4c9327d2ede3','袁尚右座中王屯田出與可竹甚奇歸成古調','錢時','宋','宋诗','song-poetry','','[]','郎星聚頭金地麓，十月夜堂春昱昱。',160,'全唐诗/poet.song.187000.json','["郎星聚頭金地麓，十月夜堂春昱昱。", "屯田博古到名畫，座上忽展牛腰束。", "我生不識須菩提，薛鶴楊梅姑置之。", "寒梢八幅奇更偉，上有巴中與可題。", "蒼蛟滑走石詰曲，鐵鈎怒掃聯蛇腹。", "欹風洒雨清逼人，恍疑身在篔簹谷。", "十尋雙幹劍拔雄，筆力有盡意無窮。", "冥冥上與風霆會，拭目變化洪陂龍。", "長憶東坡一轉語，與可德人非畫史。", "輪囷寫出歲寒心，政要諸公相料理。"]'),
('9db517ef-187c-432e-80eb-850b82f3f42f','五日晨興說既濟彖殊愜因成古調','錢時','宋','宋诗','song-poetry','','[]','端平元年初復古，懽喜羣生脫危阻。',64,'全唐诗/poet.song.187000.json','["端平元年初復古，懽喜羣生脫危阻。", "蠶香麥熟喧里閭，蒲糝艾花照樽俎。", "我本宜俗俗不宜，未學癡兒□蠅虎。", "朝來一撤既濟戶，此時欣然對端午。"]'),
('3f7ba9c5-c937-426c-aa51-8ebf35f88ce2','三月五日復雨霰','錢時','宋','宋诗','song-poetry','','[]','三月二日霰且雷，明日漫天白皚皚。',106,'全唐诗/poet.song.187000.json','["三月二日霰且雷，明日漫天白皚皚。", "陰雲聚散才信宿，冰珠更復漫天來。", "我不憂千花萬花枝壓折，亦不憂千山萬山石凍裂。", "麥如馬尾桑如錢，歲饑歲寒繄爾雪。", "一冬望爾胡不然，此日何日能狂顛。", "亟呼巽二掃落滕六魄，放出高高萬里東皇天。"]'),
('80c26101-9f6c-4178-9723-e657205ecc47','合溪夜歸呈諸大夫','錢時','宋','宋诗','song-poetry','','[]','前日合溪能多詩，此日合溪何以爲。',96,'全唐诗/poet.song.187000.json','["前日合溪能多詩，此日合溪何以爲。", "是中真趣渠未知，無聲之詩詩更奇。", "溪山淵淵魚自躍，溪樹陰陰禽自樂。", "野航日暮載牛歸，隴麥已秋蠶上箔。", "此時觴酒溪亭空，吾與魚鳥皆春風。", "安得四海車書同，春風浩浩遊其中。"]'),
('47e972aa-8991-46a5-b9c2-a831cc053fa9','管湖馬上','錢時','宋','宋诗','song-poetry','','["\u897f\u6e56"]','去年跨馬西湖曲，畫船歌管聲相逐。',96,'全唐诗/poet.song.187000.json','["去年跨馬西湖曲，畫船歌管聲相逐。", "諸友聯轡俱絕俗，敲鐙微吟山水綠。", "今年跨馬管家湖，山花欲動山禽呼。", "安得諸友復聯轡，如許野趣蘇堤無。", "野趣野翁心自可，未必行人總宜我。", "爾不宜我柰爾何，春風滿袖誰當歌。"]'),
('5c1e468d-f0df-40cc-b93f-32142f50aa76','借亭觀魚','錢時','宋','宋诗','song-poetry','','[]','春日春風衣杲杲，海棠未老春正好。',96,'全唐诗/poet.song.187000.json','["春日春風衣杲杲，海棠未老春正好。", "與客行過借亭西，平沙步步生芳草。", "空潭愛日透底明，遊鱼如散空中霙。", "徘徊欲坐去未忍，却恨借亭猶假名。", "有名無亭真是假，是假是真俱土苴。", "去年今日蘇公堤，玉勒雕鞍相家馬。"]'),
('e3d9dcf8-a8f1-42da-97f5-5945fc2ad7d4','聞里中蠶饑不肯食山桑成長句','錢時','宋','宋诗','song-poetry','','[]','往年蠶老苦乏食，採遍山桑無處覓。',158,'全唐诗/poet.song.187000.json','["往年蠶老苦乏食，採遍山桑無處覓。", "救饑恨不到口頭，略無揀擇和枝喫。", "今年葉亦未爲荒，稍羅粉米尋山桑。", "掉頭不肯喫，大似向來藜藿腸。", "山中連遭歲事惡，餓羸顛倒填溝壑。", "草根拔盡不能充，往往珍羞視藜藿。", "屈指于今能幾時，日前僅飽非有餘。", "問着只要青稈米，薄賤粟麥如沙泥。", "馬鳴不應也時樣，學爾愚氓惡情狀。", "天公嗔爾警爾深，飽時忘却饑時心。"]'),
('30fd85d5-1815-4853-95c7-b9b2d033a4b7','有送大本淵明菊者成長句','錢時','宋','宋诗','song-poetry','','[]','丹葉蕭蕭秋肅肅，有人來獻淵明菊。',128,'全唐诗/poet.song.187000.json','["丹葉蕭蕭秋肅肅，有人來獻淵明菊。", "淵明千古自高風，歲歲寒花照空谷。", "金鈿圓簇玉葳蕤，怳然彭澤歸來時。", "歸來可是知幾早，不肯爲米歸猶遲。", "老夫家住深山裏，彭澤知它在何許。", "本不曾出不須歸，冷面相看但歡喜。", "况此妙絕難可名，不識何者爲淵明。", "與客遶花行復坐，一聲幽鳥花前過。"]'),
('5818a3fb-5d42-4423-aab7-a22e44d6f237','九月朔示二小姪孫','錢時','宋','宋诗','song-poetry','','[]','有客踵我門，喜我得男孫。',56,'全唐诗/poet.song.187000.json','["有客踵我門，喜我得男孫。", "得男人所喜，爲男豈不尊。", "桑弧蓬矢射天地，墮地已作四方志。", "世上紛紛空白頭，直須了却男兒事。"]'),
('38b5780e-289c-476c-bf28-cda46290986e','採芝歌','錢時','宋','宋诗','song-poetry','','[]','巖花開兮香滿堂，秋旻杲杲兮秋風長。',71,'全唐诗/poet.song.187000.json','["巖花開兮香滿堂，秋旻杲杲兮秋風長。", "採芝一曲兮何荒唐，爲秦而遁兮出爲子房。", "天下有道兮登姚皇，共鯀斥兮夔龍驤。", "山中人兮樂時康，採芝採芝兮無褰我裳。"]'),
('04c9fa3c-964a-47db-b2b0-6ea133c1abdb','市橋間竹雞聲','錢時','宋','宋诗','song-poetry','','[]','泥滑滑，向誰語，山南山北幽林裏。',42,'全唐诗/poet.song.187000.json','["泥滑滑，向誰語，山南山北幽林裏。", "一朝籠入閙廛中，猶自千聲萬聲不知止。", "爾勿呼，人憎汝。"]'),
('827e07c0-e57b-4bff-b2b4-f0d1ab90061e','宜樓晚望','錢時','宋','宋诗','song-poetry','','[]','宜樓望芝山，淺淺平林出。',56,'全唐诗/poet.song.187000.json','["宜樓望芝山，淺淺平林出。", "芝山望宜樓，隠隠蒼龍脊。", "樓中妙景山不知，山外有山樓不宜。", "老眼西風沒疆界，一時傾入囊中詩。"]'),
('27043792-39ac-48f7-8542-9d6ca1b149e6','偶成','錢時','宋','宋诗','song-poetry','','[]','醯雞甕藏眼，鼴鼠河滿腹。',53,'全唐诗/poet.song.187000.json','["醯雞甕藏眼，鼴鼠河滿腹。", "啄木頭鏗敲，蝸牛角出縮。", "君不見浩浩無邊春，出門面面皆交親。", "未到地靈地，安知人傑人。"]'),
('1887fe03-26fa-48e4-8c11-cb4e9be4ba53','橫途歸路','錢時','宋','宋诗','song-poetry','','[]','山花榮，山禽鳴，綠楊碧澗聲泠泠。',60,'全唐诗/poet.song.187000.json','["山花榮，山禽鳴，綠楊碧澗聲泠泠。", "此時山翁尋故人，笋輿伊軋兮度密穿青，且行且止兮草軟沙平。", "溪雲山雨相送迎，衝口而出我詩成。"]'),
('3ec53dd2-1a4d-47bc-8d92-04b816cb8524','千古吟','錢時','宋','宋诗','song-poetry','','[]','日杲杲兮風葉翩翩，饑我禾黍兮渴飲澗泉。',67,'全唐诗/poet.song.187000.json','["日杲杲兮風葉翩翩，饑我禾黍兮渴飲澗泉。", "伏羲非畫孔非編，非有秘旨天外傳。", "小黠大癡亦何苦，汗牛充棟終不補。", "晴窗白髮一事無，獨抱遺經弔千古。"]'),
('6961e0bd-8dbe-483c-9b29-5d53e0937af0','清快吟','錢時','宋','宋诗','song-poetry','','[]','清似秋岩琴上月，快如春峽棹前波。',32,'全唐诗/poet.song.187000.json','["清似秋岩琴上月，快如春峽棹前波。", "三間茅屋埋頭坐，一榻薰風信口歌。"]'),
('f04d12ac-cb58-433b-8df7-ca25ee2bb400','巋然亭','錢時','宋','宋诗','song-poetry','','[]','西山紫翠入層霄，老木塵風萬竅號。',32,'全唐诗/poet.song.187000.json','["西山紫翠入層霄，老木塵風萬竅號。", "會得此時亭上意，巍然非下亦非高。"]'),
('01d843cb-2d20-475a-8f4d-116472322bb0','登蜀阜','錢時','宋','宋诗','song-poetry','','[]','滿林春鳥語高低，新綠陰陰分外宜。',32,'全唐诗/poet.song.187000.json','["滿林春鳥語高低，新綠陰陰分外宜。", "山隠此時無一事，諸兒齊誦老夫詩。"]'),
('7558450a-ccba-4cd5-a737-86ff4f4b11ee','龜石  其一','錢時','宋','宋诗','song-poetry','','[]','濺浪翻波濕不晴，灘頭龜石幾千春。',32,'全唐诗/poet.song.187000.json','["濺浪翻波濕不晴，灘頭龜石幾千春。", "浮屠漫演無生法，誰是庵中不死人。"]'),
('5dab086f-2ddb-4e1a-905b-5638de8d2cfb','龜石  其二','錢時','宋','宋诗','song-poetry','','[]','穹龜波暖錦江晴，不逐波流不計春。',32,'全唐诗/poet.song.187000.json','["穹龜波暖錦江晴，不逐波流不計春。", "報吉報凶空火厄，可憐枯骨要靈人。"]'),
('ee4aff90-e1d3-4786-b097-c7fa55a0ed4b','新亭落成','錢時','宋','宋诗','song-poetry','','[]','峭壁擎空不偶然，自從開闢我周旋。',64,'全唐诗/poet.song.187000.json','["峭壁擎空不偶然，自從開闢我周旋。", "放開西北三邊地，托起東南一片天。", "得句謾酬康節韵，知音未斷伯牙絃。", "太平風蕗真堪老，不屬枯禪不屬仙。"]'),
('9e6d95d0-c15a-44b7-ab48-31d503a6c191','高齋晚步','錢時','宋','宋诗','song-poetry','','[]','上有鷹鸇下網羅，千重雲水萬重波。',64,'全唐诗/poet.song.187000.json','["上有鷹鸇下網羅，千重雲水萬重波。", "安之若命心無慊，知者其天爾奈何。", "面面好山清凈供，聲聲幽鳥太平歌。", "憑誰寄語喬丞相，儘覺門中受用多。"]'),
('a0210865-af03-4c51-8936-cf2e6a22c072','武昌澄道寺前溪上觀魚','錢時','宋','宋诗','song-poetry','','[]','山溪清徹底，映日浮修鱗。',48,'全唐诗/poet.song.187000.json','["山溪清徹底，映日浮修鱗。", "人間湯鼎烹，見此一掬春。", "倚杖爲欣然，長淮浩無垠。", "寄語溪上翁，可以觀吾仁。"]'),
('385fac24-3bdf-4b6b-b3d5-f279ba7627bc','晚霽','錢時','宋','宋诗','song-poetry','','[]','斑駁天穿漏，驚奔浪疊空。',48,'全唐诗/poet.song.187000.json','["斑駁天穿漏，驚奔浪疊空。", "山留宿雨碧，雲受夕陽紅。", "蠶麥關時務，鶑花怯老翁。", "乾坤方寸地，今古一絲風。"]'),
('79d6b470-add0-46aa-ac2f-7b43f83dfdca','晚步即事','錢時','宋','宋诗','song-poetry','','[]','晚行叢竹下，群雀忽驚飛。',24,'全唐诗/poet.song.187000.json','["晚行叢竹下，群雀忽驚飛。", "一笑爲回首，拈花上翠微。"]'),
('0fe98914-6ce4-427b-9c28-2dadb9f7c7fc','與客步月坐澗中石上','錢時','宋','宋诗','song-poetry','','[]','林遍山深一罅天，臨流趺坐月娟娟。',32,'全唐诗/poet.song.187000.json','["林遍山深一罅天，臨流趺坐月娟娟。", "此時妙音誰能領，繞石琅琅走澗泉。"]'),
('2608c158-19e1-4c1e-8ce3-26de1c2b1fd9','十六渡','錢時','宋','宋诗','song-poetry','','[]','頗聞十六渡，客子良間關。',132,'全唐诗/poet.song.187000.json','["頗聞十六渡，客子良間關。", "一雨落澗谷，湍氣怒潺潺。", "我來屬秋晚，霜葉初斕斑。", "窈窕行竹輿，鳴禽相與閑。", "複嶺互交鎖，淺瀨隨回灣。", "路斷一罅通，石磴危躋攀。", "時見荷鋤者，行歌語蠻蠻。", "採山有薇蕨，結廬有茅菅。", "安知避世人，不曾巢其間。", "何時一枝筇，溯流到黄山。", "桃源事荒怪，誰謂非人寰。"]'),
('a618996a-7881-4cd6-83a1-637dcf951553','蜀阜精廬無風自凉方欣然出戶見竹雞將雛砌外','錢時','宋','宋诗','song-poetry','','[]','薝蔔浄如洗，蒼筤清且深。',120,'全唐诗/poet.song.187000.json','["薝蔔浄如洗，蒼筤清且深。", "依巖自幽潤，況無日影侵。", "亭午一升階，忽若投凌陰。", "涼氣颯以入，肅肅生衣襟。", "大火浮炎埃，虛堂抱雲林。", "安得冰霜顔，聽我山中吟。", "盤桓去未忍，砌外行山禽。", "一母將四雛，出沒叢草陰。", "我非有馴德，渠自無機心。", "欣然歸北窗，載弄南風琴。"]'),
('46ea1b7b-d723-4f5a-95ea-62f1c627237c','新晴','錢時','宋','宋诗','song-poetry','','[]','宿雲穿日薄，商略作新晴。',48,'全唐诗/poet.song.187000.json','["宿雲穿日薄，商略作新晴。", "燕子先期社，海棠今日春。", "溪山雙白鬢，天地一閑身。", "無語東風裏，飛花亂撲人。"]'),
('8e1d71e1-6adb-45ae-823e-089d9aba7b5c','安素午睡','錢時','宋','宋诗','song-poetry','','[]','禾黍秋相近，溪山日自長。',24,'全唐诗/poet.song.187000.json','["禾黍秋相近，溪山日自長。", "午窗千嶂雨，幽夢一簾香。"]'),
('6b2841b9-3338-4740-8552-eb382eff4703','溪南遇雨','錢時','宋','宋诗','song-poetry','','[]','溪風颯颯雨霏霏，秋滿蘋汀獨步歸。',64,'全唐诗/poet.song.187000.json','["溪風颯颯雨霏霏，秋滿蘋汀獨步歸。", "丹噀園林棠葉老，錦纏籬落豆花肥。", "眼前風景依然在，箇裏光陰得者稀。", "憶著歲寒雲壑上，山禽對雨傍人飛。"]'),
('586fd175-b965-4671-add8-6fe53c0c3c66','邑人張孝友親歿廬墓六年有五色鳥集墓隴邑大夫張公侃旌其廬名其鄉曰移風鄉','徐洪','宋','宋诗','song-poetry','','[]','孝友聞張仲，貽謀直到今。',48,'全唐诗/poet.song.187000.json','["孝友聞張仲，貽謀直到今。", "六年枯血淚，五色集祥禽。", "表此勵頹俗，來茲生孝心。", "移風名不忝，茂宰意良深。"]'),
('9f20c65f-3e6a-44ee-8690-f5776dab06dc','烏衣巷','羅必元','宋','宋诗','song-poetry','','[]','烏衣池館一時新，晉宋齊梁舊主人。',32,'全唐诗/poet.song.187000.json','["烏衣池館一時新，晉宋齊梁舊主人。", "無處可尋王謝宅，落花啼鳥秣陵春。"]'),
('8badcb93-c002-4715-aee4-edb017728154','長干里','羅必元','宋','宋诗','song-poetry','','[]','山壠中間號曰干，此干長里盛衣冠。',32,'全唐诗/poet.song.187000.json','["山壠中間號曰干，此干長里盛衣冠。", "想應王謝朝回後，日日行人看繡鞍。"]'),
('039e8fd1-d854-4db8-b72a-54fb65bcf719','駐馬坡','羅必元','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一登偉觀眇山河，下有將軍駐馬坡。',32,'全唐诗/poet.song.187000.json','["一登偉觀眇山河，下有將軍駐馬坡。", "不是胸中兵十萬，長江天險誤人多。"]'),
('10435290-ecdb-40f2-87e8-2c830b81409f','秦淮','羅必元','宋','宋诗','song-poetry','','[]','秦淮橫貫帝王州，萬瓦鱗鱗枕碧流。',32,'全唐诗/poet.song.187000.json','["秦淮橫貫帝王州，萬瓦鱗鱗枕碧流。", "繫艇莫愁何處去，綠楊深巷有青樓。"]'),
('675cce3e-0a65-430e-a5ea-dff4e4013402','賞心亭','羅必元','宋','宋诗','song-poetry','','[]','勝地分明可賞心，江山滿目飽登臨。',32,'全唐诗/poet.song.187000.json','["勝地分明可賞心，江山滿目飽登臨。", "洛陽黯淡烟雲遠，多少英雄淚染襟。"]'),
('91e536c0-c8ac-4157-b621-72ad912b0cdf','新亭','羅必元','宋','宋诗','song-poetry','','[]','五馬來時集宴遊，江山風景勿關愁。',32,'全唐诗/poet.song.187000.json','["五馬來時集宴遊，江山風景勿關愁。", "合思戮力中原語，對泣何須作楚囚。"]'),
('474d41c4-b064-48c2-904c-b74b3aa7b06f','南軒','羅必元','宋','宋诗','song-poetry','','[]','萬松盤嶺勢回環，才抱青溪浸碧山。',32,'全唐诗/poet.song.187000.json','["萬松盤嶺勢回環，才抱青溪浸碧山。", "莫道南軒專一壑，古今天下共曾顔。"]'),
('978cef29-601c-40f3-9f3d-494d796954fb','鳳凰臺','羅必元','宋','宋诗','song-poetry','','[]','振衣快上鳳凰遊，極目中原淚欲流。',64,'全唐诗/poet.song.187000.json','["振衣快上鳳凰遊，極目中原淚欲流。", "慨歎興亡思太白，永言眇邈憶齊丘。", "烏衣已往人千古，白鷺依然月一洲。", "君子坐朝今在治，重恢關洛不須愁。"]'),
('41fefce1-8441-4fd7-9906-b125b6cafae3','周處臺','羅必元','宋','宋诗','song-poetry','','[]','周處豪雄亦可人，勇於遷善罕前聞。',32,'全唐诗/poet.song.187000.json','["周處豪雄亦可人，勇於遷善罕前聞。", "區區未說除蛟虎，一念中間舜跖分。"]'),
('549d9f63-63d1-4fce-a8d0-cfa3f6bd3420','雨花臺','羅必元','宋','宋诗','song-poetry','','[]','蕭帝傾心向佛家，謾言天女墜天花。',32,'全唐诗/poet.song.187000.json','["蕭帝傾心向佛家，謾言天女墜天花。", "蘆僧一葉橫江去，回首梁園日脚斜。"]'),
('367b350e-7602-4a4c-abfc-ac948f4da805','金陵作','羅必元','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','六朝遺跡舊山川，萬里長江當守邊。',32,'全唐诗/poet.song.187000.json','["六朝遺跡舊山川，萬里長江當守邊。", "一念易驕人事廢，不關飛渡北來船。"]'),
('b0944b82-8e0f-4f82-9510-6c5724325364','凭高懷古','羅必元','宋','宋诗','song-poetry','','[]','凭高懷古思悠悠，遥想騎馿白下遊。',32,'全唐诗/poet.song.187000.json','["凭高懷古思悠悠，遥想騎馿白下遊。", "不是龍眠圖畫裏，如今親到蔣山頭。"]'),
('c2901263-6cdb-4b6b-b60d-52b9432a12f0','金蓮步','羅必元','宋','宋诗','song-poetry','','[]','金陵佳麗不虛傳，浦浦荷花水上仙。',32,'全唐诗/poet.song.187000.json','["金陵佳麗不虛傳，浦浦荷花水上仙。", "未會與民同樂意，却於宮裏看金蓮。"]'),
('a0427eed-9015-4da5-9ae9-ccc652ad1b55','清凉寺竹','羅必元','宋','宋诗','song-poetry','','[]','清凉世界竹如雲，舊日君王愛此君。',32,'全唐诗/poet.song.187000.json','["清凉世界竹如雲，舊日君王愛此君。", "時代改遷龍變化，荒山啼鳥不堪聞。"]'),
('5d332708-eacc-4ac4-8838-35fa2df8feb3','卞壼墓','羅必元','宋','宋诗','song-poetry','','[]','節義之風古所褒，清談於晉視如毛。',32,'全唐诗/poet.song.187000.json','["節義之風古所褒，清談於晉視如毛。", "百年王謝丘墟了，惟卞將軍墓最高。"]'),
('3dee7df8-4069-4db3-8081-7aee8e7c8586','題半山寺','羅必元','宋','宋诗','song-poetry','','[]','道德文章一世師，只傷學術欠通時。',32,'全唐诗/poet.song.187000.json','["道德文章一世師，只傷學術欠通時。", "不思翻動熙寧禍，却欲重修作福基。"]'),
('a9ec69e8-9981-4f36-8070-fa9260a77151','定林寺','羅必元','宋','宋诗','song-poetry','','[]','罷相歸來再讀書，定林庵內守清虛。',32,'全唐诗/poet.song.187000.json','["罷相歸來再讀書，定林庵內守清虛。", "少年錯解周官處，悔殺當朝是誤渠。"]'),
('0272fa39-007d-4ac9-a63b-85a24ae24697','題衢州順溪館','曾從龍','宋','宋诗','song-poetry','','[]','紅照西沉暫解鞍，偶然假館豈求安。',32,'全唐诗/poet.song.187000.json','["紅照西沉暫解鞍，偶然假館豈求安。", "新豐獨酌誰爲侶，坐對窗前竹一竿。"]'),
('23b45b7b-40b6-48e4-bd4a-c64330bc533b','題清水寺','曾從龍','宋','宋诗','song-poetry','','[]','壁立崢嶸萬仞峰，騎鯨俄蛻葛陂筇。',64,'全唐诗/poet.song.187000.json','["壁立崢嶸萬仞峰，騎鯨俄蛻葛陂筇。", "空流詩句傳千古，今在蓬萊第幾重。", "巖上勝游成幻夢，壁間遺跡暗塵容。", "山僧好把紗籠護，莫學闍黎飯後鍾。"]'),
('30957eae-6d6f-4e78-87f7-79e82cfbdd5d','禪師塔','陳貴誠','宋','宋诗','song-poetry','','[]','舊到烏回寺，相迎識短筇。',48,'全唐诗/poet.song.187000.json','["舊到烏回寺，相迎識短筇。", "重來已無跡，今去欲安從。", "春曉空啼鳥，巖枯吼夜龍。", "諸天圍繞處，重聽一樓鐘。"]'),
('566df10b-4a48-4e5c-9ae3-6ba70b3678e6','定業寺','胡鑒','宋','宋诗','song-poetry','','[]','拂雲開紫氣，窈窕入幽境。',84,'全唐诗/poet.song.187000.json','["拂雲開紫氣，窈窕入幽境。", "杉森若趨山，竹青無盡境。", "寒螿互響答，野鳥話深靜。", "暗水冽池光，疎風碎金影。", "騁懷抖黄埃，吸景別清鏡。", "三年面溪西，所樂尤未竟。", "出野山益深，佳氣爲參請。"]'),
('41820e95-9f8c-49d3-83ae-f9468a7df828','佛牙山','胡鑒','宋','宋诗','song-poetry','','[]','烈火烹煎沸鼎游，夢回漸覺此身浮。',64,'全唐诗/poet.song.187000.json','["烈火烹煎沸鼎游，夢回漸覺此身浮。", "坐忘三載蕉中鹿，卧護一帆天際舟。", "要識此心如止水，盡將塵迹送牢愁。", "荆溪莓蘚青無恙，待與石亭三日留。"]'),
('7b41b7c1-03c5-4b38-9746-b447ed9aee9c','歸釣吟','華岳','宋','宋诗','song-poetry','','[]','我生本是絲綸客，嘗抱絲綸釣王國。',382,'全唐诗/poet.song.187000.json','["我生本是絲綸客，嘗抱絲綸釣王國。", "膠庠雖識姚有虞，載車未遇周西伯。", "抱琴歸去古江邊，江頭風月猶依然。", "江風刮岸岸如削，江月照人人未眠。", "沙平浪靜江天闊，換酒捉魚魚撥剌。", "有時醉椀和月吞，有時醉棹和煙撥。", "或唱歌，或吹笛，欵乃宮商人不識。", "歌聲喚徹煙水寒，笛聲清透雲霄碧。", "不張帆，任渠去，去到雲山深處住。", "雲山深處有畫圖，添箇雲山畫圖侶。", "不撥棹，任渠流，流入玻瓈影裏頭。", "玻瓈影裏迸珠玉，千斛萬斛誰能收。", "倦時眠，醉時舞，漁家自有神仙府。", "睡時蝴蝶夢莊周，舞處鷗鳶奏韶武。", "自舉歸釣吟，清江漠漠煙沉沉。", "雲藏萬壑暗水尾，風吹孤月摇天心。", "翠微父，翠微父，和我行歌進南浦。", "畫橋流水抹晴煙，殘照暮霞收宿雨。", "水連天，天似水，一蓑活計誰能比。", "楓葉飄霜鱸鱠香，楊花飛雪河魨美。", "也不學，姜太公，百年將至方非熊。", "會須年少遇真主，恢我諸夏車書同。", "也不學，嚴子陵，雲臺不爲冠殊勳。", "中興只作釣臺侶，胸中百萬知無兵。"]'),
('9ead9218-3cbc-4cc2-ad68-9267181b99b1','記夢','華岳','宋','宋诗','song-poetry','','[]','溪泠泠，皷鼕鼕，虛堂淅瀝生寒風。',144,'全唐诗/poet.song.187000.json','["溪泠泠，皷鼕鼕，虛堂淅瀝生寒風。", "寒風繞我夢魂去，飛颺直上蓬萊宮。", "蓬萊宮殿女如玉，霓裳羽扇環簾櫳。", "月娥留我宴珠翠，玳筵間列花叢叢。", "酒酣萬象羅心胸，舉盃話別殊匆匆。", "青鸞命駕下空闊，一聲璫珮鳴丁東。", "被衣起坐周四顧，庭戶悄悄無人蹤。", "銀河萬里倒澄碧，冰鑑半輪斜倚空。", "橫江孤鶴一聲唳，喚起鄉心千萬重。"]'),
('7fb6594e-4c45-43b6-8e71-fce5d1bef3cf','梅','華岳','宋','宋诗','song-poetry','','[]','衰蘭枯荷了秋色，幾向寒梢問消息。',96,'全唐诗/poet.song.187000.json','["衰蘭枯荷了秋色，幾向寒梢問消息。", "溪橋交馬斷腸時，翠袖佳人日暮歸。", "玉面亭亭漢宮樣，一見風流慰心賞。", "寒標孤絕太無情，誰爲移春上玉京。", "月華凄切霜華白，夜半飄香度簾額。", "寄聲橫笛且休吹，愁殺江南未歸客。"]'),
('3307056a-3881-4935-9883-90ba1bb2bad4','山水吟','華岳','宋','宋诗','song-poetry','','[]','閩之山峨峨，可以接穹蒼。',190,'全唐诗/poet.song.187000.json','["閩之山峨峨，可以接穹蒼。", "閩士孕其秀，胸次尤難量。", "閩之水滔滔，可以燭妍醜。", "閩士生其間，其美不容口。", "君不見周家社稷生甫申，崧岳當年曾降神。", "又不見千里秀氣鍾三蘇，眉山草木皆焦枯。", "我生恨不由河洛，虛負三光并五岳。", "地靈人傑推江東，人物風流兼磊落。", "顧此閩之東，自古多英雄。", "求其爲絕稱，獨一忠穆公。", "公今已即世，後世誰可擬。", "惟有詹仲通，一人而已耳。", "仲通何如人，景星與鳳凰。", "不險亦不深，山高兮水長。"]'),
('9d9e5030-43c1-4e97-901b-f98599c541a4','浴','華岳','宋','宋诗','song-poetry','','[]','龍藩地暖冬無雪，十月風光似三月。',224,'全唐诗/poet.song.187000.json','["龍藩地暖冬無雪，十月風光似三月。", "好風不動綺羅塵，人在繡幃簾半揭。", "酒腸拍索能回春，春潮八面香熏熏。", "香肌汗透披縠紋，思得滄海驅埃氛。", "銀鍋蟹眼生春雪，銀瓢捾破鍋心月。", "流霞傾入碧琅玕，香霧氤氳雲半掇。", "花藤織出金芙蕖，烟青藕紫堆雲盂。", "一聲璫珮簾鈎垂，皂盤捧出雙明珠。", "蠟花照入蘭湯閣，珠璣體迸紅猊活。", "鳳豁雲濤濯錦毛，龍翻雪浪澆銀甲。", "起拏裙霧圍春風，臙巾抹出桃花紅。", "香泉入齒潄寒玉，吐作冰雪飛長空。", "蒼頭急把春衫換，腕玉輕穿雲一片。", "出門兩腋生清風，身在嫦娥廣寒殿。"]'),
('5c147e6c-db83-4e1e-aa5e-99f6f3b40761','嘲熱','華岳','宋','宋诗','song-poetry','','[]','南方有神名祝融，髮赭面丹唇朱紅。',128,'全唐诗/poet.song.187000.json','["南方有神名祝融，髮赭面丹唇朱紅。", "執鞭入海驅赤龍，火車勒駕燒長空。", "千驂萬乘如聯轡，烈焰騰騰灼天地。", "九霄烜赫皆甑蒸，四海煎熬俱鼎沸。", "流金爍石氣不通，天下俱在紅爐中。", "葛衫襟濕疑有雨，羅紈柄折渾無風。", "祝融祝融毋太酷，天道炎凉嘗反覆。", "看看少皡催戍瓜，盡把凉風散煩溽。"]'),
('a3c73da6-5fd6-4801-88dd-6d6baf895c71','釣鼇行','華岳','宋','宋诗','song-poetry','','[]','北風浩蕩滄溟闊，千萬軍聲夜潮聒。',256,'全唐诗/poet.song.187000.json','["北風浩蕩滄溟闊，千萬軍聲夜潮聒。", "翻空濁浪鼓雷霆，舟子停蘭面如血。", "龍門有客何猙獰，弩目張膽殊不驚。", "桅檣破浪裂洋島，直欲一舉空蛟鯨。", "我之釣兮非世比，新月爲鈎索霞綺。", "先拗虹蜺爲釣竿，却把鵾鵬作香餌。", "欲垂未垂號鬼神，星斗無光天地昏。", "海靈乞命免生死，一鈎連六酬銜恩。", "我公萬里風煙伯，度量汪汪寰海窄。", "蟠胸高聳蓬萊山，壯氣直吞雲夢澤。", "恩波萬壑奔洪流，風帆浪楫交觥籌。", "金鱗照日巨如斗，四海觸物無虛舟。", "我生本是釣鼇客，幾歲灘頭望風色。", "忽聞霹靂破崑崙，便整絲綸駕航舶。", "我今十轄迎公開，會須舉手生風雷。", "不然長嘯謝水府，明月滿船歸去來。"]'),
('a1cba54c-9326-48f7-9ef8-fe687cf5a271','上趙漕','華岳','宋','宋诗','song-poetry','','[]','太山之巔有喬松，凜凜千丈摩蒼空。',224,'全唐诗/poet.song.187000.json','["太山之巔有喬松，凜凜千丈摩蒼空。", "風雲有會直相際，轟雷掣電蟠蛟龍。", "盤根錯節真天種，卿月郎星伴辰拱。", "高風蕭瑟涕清泉，桃李無言謾丘壟。", "南宮仙桂饒天香，南國蔽芾歌甘棠。", "大枝擎天作砥柱，小枝駕海成虹梁。", "六月無風天欲雨，赤龍銜火燒空宇。", "亭亭橫蓋指扶桑，萬壑千崖冷無暑。", "大椿可笑欺莊周，便指千歲爲春秋。", "使民若戰夏后社，用汝當作商川舟。", "自慚藤蔓纏林壑，未遂鷦鷯一枝樂。", "盤桓已喜跨高寒，更借扶摇薦鵰鶚。", "我聞處士方綢繆，三友簡在公寧留。", "蒼姬已托大夫蔭，赤子願陪丞相遊。"]'),
('fbd72ff9-bf95-43c4-90de-e3add2448a14','鄰女搔綿吟','華岳','宋','宋诗','song-poetry','','[]','閒窗日上三竿竹，窗下嬌娥整輪輻。',160,'全唐诗/poet.song.187000.json','["閒窗日上三竿竹，窗下嬌娥整輪輻。", "匆匆未暇理雲鬟，半朵青鴉倚紅玉。", "青梢摘盡銀香囊，畫欄平倚斑筠筐。", "時將纖手翻雪霜，酥胸玉面同光芒。", "捧歸細捲銀成索，牽出鬆鬆雲一握。", "珠唇呵挺氣溫溫，鸚觜踏車聲絡絡。", "今年莫怪功績稀，阿嬭勒繡鴛鴦幃。", "如今織出秋江練，十月正好裁新衣。", "客心聞此愁無著，一夜清寒動寥寞。", "明朝爲問買一端，剪做道袍披落魄。"]'),
('684821f1-32f6-4178-b52c-4f95d2ac003b','送商府判','華岳','宋','宋诗','song-poetry','','[]','比年十月君初來，梅花破雪迎君開。',256,'全唐诗/poet.song.187000.json','["比年十月君初來，梅花破雪迎君開。", "自從佐劍壽民脈，凋山瘵水皆春臺。", "去年七月君開府，燕燕鶑鶑爲君舞。", "五日盡蟄潭底龍，千里應無市中虎。", "今年二月君將歸，風牽回柳縈君衣。", "君衣不作回柳轉，直上雲端朝紫微。", "紫微有館名西掖，珠玉羅鈿瞰金碧。", "郎星卿月謾徘徊，箇中自是神仙宅。", "紫微有山名大坡，烏飛豸立冠峨峨。", "一聲霹靂震天地，萬里腥血流江河。", "紫微有旨垂丹冊，二者于斯請君擇。", "便須東取元化鈞，談笑從容正疆埸。", "君家事業銘冠裳，鸞鳳指日鳴朝陽。", "伊洛諸公有政事，洙泗諸子無文章。", "稟違展轉情難處，溪上恩波湛今古。", "東風吹恨入長亭，零落桃花淚如雨。"]'),
('5d7d149b-98df-4793-8903-1fb51b946ca1','平政橋','華岳','宋','宋诗','song-poetry','','[]','建水合流三百里，直下富沙如撚指。',256,'全唐诗/poet.song.187000.json','["建水合流三百里，直下富沙如撚指。", "溪東披拽纜過西，千丈春風怒濤起。", "香輪不解碾清江，造舟貫索成河梁。", "年年麥熟梅欲黄，連城千里皆波光。", "淳熙太守憂溱洧，問津日夜思無計。", "老農叉手願鳩工，疊石中流使民濟。", "金珠賣價不計緡，鎸瑕斷梓功方成。", "功成燕雀賀新屋，炳然萬棟輝丹青。", "插天螮蝀橫江尾，下壓寒潭碧無底。", "市聲不到畫梁間，秋色盡歸朱箔裏。", "我行一月無風波，今朝醉眼翻青羅。", "金鰲背路客揮𩍐，玉虹跨浪舟飛梭。", "石唇噴盡寒崖雪，雪中電掣金蛇赤。", "兩岸樓頭將相家，八州車馬神仙客。", "人言辟人推政平，故此特以平政名。", "我聞政事平如水，水到不平還作聲。"]'),
('2e4676a1-6a72-49e1-aa3b-e1437a8bed8d','贈陳道人','華岳','宋','宋诗','song-poetry','','[]','君不見樵人王翰畫山水，一夜風雷揭窗紙。',158,'全唐诗/poet.song.187000.json','["君不見樵人王翰畫山水，一夜風雷揭窗紙。", "又不見長沙洞清畫龍蛇，滿軸煙雲翻撚指。", "二子相去數百年，筆端妙意誰能傳。", "雙溪道人何所授，一見筆法堪齊肩。", "筆一淡，輕煙映出垂楊岸。", "遠山依約有還無，斜照不紅秋水漫。", "筆一濃，黑雲萬疊翻狂風。", "江天日暮暗煙靄，天地星斗皆昏朦。", "瀟湘詩人不解語，被君吐作無聲句。", "何時覓取綃一縑，寫我英姿伴煙雨。"]'),
('173604f4-f691-4ebb-b62c-28340d9e0c0a','柴氏','華岳','宋','宋诗','song-poetry','','[]','節婦一樽酒，義士拜而受。',160,'全唐诗/poet.song.187000.json','["節婦一樽酒，義士拜而受。", "義士一首詩，節婦雙眉皺。", "眉皺意何如，有難難相救。", "嘆我廊廟器，淹回在污陋。", "惠我旨且嘉，慇懃推意厚。", "吾今繫閩建，家貧喜鄰富。", "青眼到朱扉，白屋成華胄。", "吾聞孤竹子，周室三緘口。", "又聞杞梁妻，秦邦稱烈婦。", "此輩誠間生，世代不常有。", "如何天一方，同時俱輻湊。", "愧無八品珍，草草具籩豆。", "何當再拜摳我衣，巵酒恭爲兒女壽。"]'),
('1ba6435a-928e-4ceb-8c3f-58a4c715d950','傷春','華岳','宋','宋诗','song-poetry','','[]','衣袂怯春寒，春在江南岸。',136,'全唐诗/poet.song.187000.json','["衣袂怯春寒，春在江南岸。", "我意正傷春，復被春縈絆。", "一雨臙脂濕，萬壑冰澌泮。", "撩我惜春心，與春傷爛漫。", "柳垂不染絲，織成愁一片。", "杏吐無煙火，燒碎腸千斷。", "憶昔腰如柳，柳腰輕易按。", "憶昔面如花，花面嬌難喚。", "人不似春芳，隨處得看翫。", "因春憶美人，不見徒扼腕。", "何時醉卧花柳中，一笑千金不容換。"]'),
('baf18fcf-d824-4d7d-a92f-062450ea8702','百舌','華岳','宋','宋诗','song-poetry','','[]','流鶑一去無消息，燕怯春寒歸未得。',160,'全唐诗/poet.song.187000.json','["流鶑一去無消息，燕怯春寒歸未得。", "綠窗清晝靜無人，似把衷情訴知識。", "上苑東風二月春，淡黄楊柳初成陰。", "解將一片無情舌，學盡百般能語禽。", "紅英紫萼紛如雪，萬姹千嬌總饒舌。", "莫嫌花外太啁啾，默默難酬好時節。", "須臾綠暗紅亦稀，伯勞杜宇鷹鸇飛。", "更兼獵弋恣羅網，卷舌不語全毛衣。", "堪嗟國士徒切直，不似幽禽明語默。", "何如鉗口歸山林，莫問燕南并越北。"]'),
('63c83ad5-8543-4d02-a5db-f3744582ed62','飲仙閣','華岳','宋','宋诗','song-poetry','','[]','槽頭壓盡春山綠，槽下真珠瀉醽醁。',112,'全唐诗/poet.song.187000.json','["槽頭壓盡春山綠，槽下真珠瀉醽醁。", "騷人一笑傾蓋盤，滿面春風漲紅玉。", "少陵得此不欲言，乃指八子爲中仙。", "主人傾蓋慕此意，一閣新構堂西偏。", "于今世態薄于紙，何必勞心問青紫。", "願君醉我金屈巵，萬事過耳同風飛。", "醺醺和月尚栽竹，長嘯一聲歸翠微。"]'),
('4849f79e-b4a2-4fe4-8f56-2ba4fe7d15f5','贈祝跛','華岳','宋','宋诗','song-poetry','','[]','我生多蹇難，事業冷於水。',84,'全唐诗/poet.song.187000.json','["我生多蹇難，事業冷於水。", "內外兩五行，醜惡諱人舉。", "武夷有跛者，抱術徧荆楚。", "摳衣忽趨隅，覿面便相許。", "摇手無所需，再拜拂毫楮。", "一詩聊贈行，無以壯箱筥。", "他時了功名，爲結煙霞侶。"]'),
('bf021dfa-e20c-4c65-a002-504b050da01d','富沙道中述懷','華岳','宋','宋诗','song-poetry','','[]','敗鼓非全材，毀瓦不自牧。',48,'全唐诗/poet.song.187000.json','["敗鼓非全材，毀瓦不自牧。", "造物兒未戲，達人火先撲。", "卜不到渭濱，人徒嗟海曲。", "彼哉真彼哉，伐盡牛山木。"]'),
('d39a61de-b6e4-41dc-9006-ddeacccd7853','驟雨','華岳','宋','宋诗','song-poetry','','[]','牛尾烏雲潑濃墨，牛頭風雨翩車軸。',64,'全唐诗/poet.song.187000.json','["牛尾烏雲潑濃墨，牛頭風雨翩車軸。", "怒濤頃刻卷沙灘，十萬軍聲吼鳴瀑。", "牧童家住溪西曲，侵早騎牛牧溪北。", "慌忙冒雨急渡溪，雨勢驟晴山又綠。"]'),
('dc6080b5-aca0-4d83-a3c5-51c5dc193de5','別王泰之','華岳','宋','宋诗','song-poetry','','[]','黄塵漫漫小峰路，白石齒齒茗坑渡。',64,'全唐诗/poet.song.187000.json','["黄塵漫漫小峰路，白石齒齒茗坑渡。", "相亭南來第一程，人煙蕭條歲云暮。", "故人小隠三家村，約我旗亭聊一樽。", "相逢此地復相別，明朝懷抱同誰論。"]'),
('1498c0c1-1fc3-4dae-b603-b6b20d97b7b1','江上雙舟催發','華岳','宋','宋诗','song-poetry','','[]','前帆風飽江天闊，後帆半出疎林闕。',96,'全唐诗/poet.song.187000.json','["前帆風飽江天闊，後帆半出疎林闕。", "後帆招手呼前帆，畫鼓輕敲總催發。", "前帆雪浪驚飛湍，後帆舵尾披銀山。", "前帆漸緩後帆急，相傍俱入蘆花灘。", "島嶼縈回斷還續，沙尾夕陽明屬玉。", "望中醉眼昏欲花，誤作閒窗小橫軸。"]'),
('617b08c6-d793-462b-840e-1300efb5ef65','慰吳吉甫縣尉','華岳','宋','宋诗','song-poetry','','[]','子鍼如京師，一室膏鼎臠。',192,'全唐诗/poet.song.187000.json','["子鍼如京師，一室膏鼎臠。", "兄室雖被戕，一妻猶可免。", "伯奢事行役，八子俱蹂踐。", "兄家禍雖劇，一女特婉孌。", "女死固可傷，殊未敵冠冕。", "妻在固全軀，喪女憂莫遣。", "大厦既灰飛，豐儲皆席卷。", "鶺鴒起嘆嗟，鸞凰徒展轉。", "我昔以難勤，荷兄垂勸勉。", "兄今以難告，倍覺淚淟涊。", "泛觀天之理，禍福嘗相反。", "有難既不死，他時非淺淺。", "去兄一牛鳴，爲地良非遠。", "不能見兄慰，面目實有靦。", "自料吾與兄，氣量及者鮮。", "胡爲蒼者天，與子獨羈蹇。"]'),
('604f8a24-643d-4e51-8291-703cf2a702c2','贈劉相士','華岳','宋','宋诗','song-poetry','','[]','班超未侯漢，誰識烏孫客。',156,'全唐诗/poet.song.187000.json','["班超未侯漢，誰識烏孫客。", "韓信已王齊，誰知長樂厄。", "彼亦非異術，忠諛分黑白。", "直道世且違，彼亦何足責。", "自古勳業人，把鏡惟自索。", "顧我灑落資，足可振翰翮。", "如何汗馬秋，英雄尚南謫。", "祇應捻胎鬼，手段不合格。", "古括子劉子，閲人幾千百。", "一見麞鼠質，便許正疆埸。", "知子忠且諛，愚固未暇擇。", "萬一符子言，亦可名簡冊。", "它時雙蹇馿，約子訪黄石。"]'),
('fe0bc932-b360-450c-be28-b9d18474bc54','誚胡同巡','華岳','宋','宋诗','song-poetry','','[]','岳昔游時卿，兄嘗過敝廬。',240,'全唐诗/poet.song.187000.json','["岳昔游時卿，兄嘗過敝廬。", "捫心論事業，耐久良非虛。", "岳今隸城旦，氣象誠慘舒。", "髠黥塞糞壤，敢辱長者車。", "嘗聞古人交，窮達無親疎。", "富貴不相忘，有終還有初。", "與兄三載別，無日不引裾。", "中間喜一見，欣慰云何如。", "相去天一涯，雲濤疏鴈魚。", "忽聞夙駕回，喜色喧門閭。", "相聞即相別，厥意良躊躇。", "嘗聞郢中人，結客于樵漁。", "又聞淮南王，受德于刑餘。", "岳既不自檢，失身墮籧篨。", "壯士視一死，其猶爾欷歔。", "勢分已霄壤，孤托難相於。", "願兄此召還，巍然奉中除。", "前巖與西閣，談笑看連茹。", "或過趙可父，爲岳聲起居。", "薰風有良便，當拜平安書。"]'),
('d501cd8c-99fc-422d-b09a-ef7f9ba62715','送詹仲通縣尉','華岳','宋','宋诗','song-poetry','','[]','秋郊送行色，執別臨清流。',216,'全唐诗/poet.song.187000.json','["秋郊送行色，執別臨清流。", "風神掣回柳，故故牽衣裘。", "吟螿附草際，催客登蘭舟。", "問客何所之，駕言京闕遊。", "愚聞京闕間，多難三春秋。", "閫外炙魚肉，闕內羅羊頭。", "鼎却吠堯犬，冠還沐楚猴。", "和戎重輸費，廊廟有隠憂。", "賑荒少儲蓄，郡國無良謀。", "飛蝗蔽日月，兆龜拆田疇。", "君以經濟材，抱負衝斗牛。", "家傳醫國秘，殊不諸子儔。", "有用即隆平，豈特爲東周。", "願君攄緒餘，咳唾開冕旒。", "管領一世雄，克復歸神州。", "賤子忝知遇，脫網將從游。", "相隨上凌煙，也勝登瀛洲。", "作詩告于君，君其許之不。"]'),
('78107cb2-6386-4728-a623-9493c74608b7','上詹仲通縣尉  其一','華岳','宋','宋诗','song-poetry','','[]','松竹不著花，密葉徒如帚。',144,'全唐诗/poet.song.187000.json','["松竹不著花，密葉徒如帚。", "江梅不藏葉，寒花綴枯朽。", "獨有龍焙茶，花葉秀而耦。", "冰霜著羣木，凍死十八九。", "惟此百草靈，名可綴三友。", "春雷迸雀舌，夜雨滴龍口。", "皆萌哺啜心，誰假栽培手。", "惟有蔡端明，識之在蒿蔌。", "移根入北苑，金碧煥星斗。", "夸作龍鳳團，封成獻元后。", "問花何以報，牙舌甘鼎臼。", "他時子復生，爲公滌繁垢。"]'),
('3f45bc63-7982-4fb2-8568-7d44b4837944','上詹仲通縣尉  其二','華岳','宋','宋诗','song-poetry','','[]','西風卷荷衣，披披不成幅。',144,'全唐诗/poet.song.187000.json','["西風卷荷衣，披披不成幅。", "清霜拆蕙囊，冽冽已成蓿。", "如何獨東籬，黄華笑寒菊。", "物之有盛衰，循環若推轂。", "世事良亦然，亦豈物所欲。", "金鈿鎔落日，零露灑寒玉。", "人皆惜芳菲，誰復念幽獨。", "惟有陶淵明，慇懃費培沃。", "簪花從帽落，撚酒醉商陸。", "從此擅秋芳，芙桂非同錄。", "問花何以報，剪首薦醽醁。", "他時更粉軀，爲公采明目。"]'),
('8aceeff9-f902-44d5-939a-3dd8365dbd4a','寄大庾郭縣尉','華岳','宋','宋诗','song-poetry','','[]','前年建安縣，始識韓荆州。',288,'全唐诗/poet.song.187000.json','["前年建安縣，始識韓荆州。", "一見辱知遇，許我嘗從游。", "尋幽訪赤壁，買笑陪青樓。", "有酒即命駕，夜飲忘觥籌。", "雪香飄梅花，歸駕仍遲留。", "送君城北隅，歲事希一周。", "告德雖未久，有懷奚所投。", "客來自錦溪，知爲藍田遊。", "摳衣欲趨隅，其奈風馬牛。", "方圖拜尺紙，文此不敏羞。", "乃復三不緘，獲戾于君侯。", "謫客干典刑，宜爾餐吳鈎。", "幸不畀我死，殘喘延俘囚。", "搜索徧中外，釋縛良無由。", "始思鵾鵬翼，庇我反手猶。", "噓燈拂毫楮，尺素馳星流。", "荷公三復還，惻然添我憂。", "許我京闕間，與我爲良謀。", "于今秋復冬，俟命猶置郵。", "西風掠天宇，魚鴈俱沉浮。", "未審恩波中，許我共濟不。", "我材襪線短，願公廣甄收。", "他日賓幕府，鏖戰當焚舟。", "公兮不我援，復駕言焉求。"]'),
('76158510-a5ca-4158-8e11-83b67aad6246','嚴陵方市','華岳','宋','宋诗','song-poetry','','[]','浮雲掃盡天宇清，千花萬花開錦屏。',64,'全唐诗/poet.song.187000.json','["浮雲掃盡天宇清，千花萬花開錦屏。", "好風吹皺一池綠，白鳥點破千山青。", "客行五里復五里，兩眼丹青間紅紫。", "杖屨不知行路難，人在江南圖畫裏。"]'),
('423bf783-4de8-4be2-a321-80c915e4cc26','月巖','華岳','宋','宋诗','song-poetry','','[]','六丁一鑿空雲烟，滿窟勒駕驅神僊。',64,'全唐诗/poet.song.187000.json','["六丁一鑿空雲烟，滿窟勒駕驅神僊。", "冰輪推出月中月，玉斧劈開天外天。", "便把嫦娥騎綵鳳，却呼羽客烹銀蟾。", "更邀王母瑶池酒，今夜廣寒同醉眠。"]'),
('3922c353-070d-45d9-8714-f8e663d67c4e','熱中呈楚南僧','華岳','宋','宋诗','song-poetry','','[]','帝炎執鞭驅赤龍，火車萬乘燒長空。',64,'全唐诗/poet.song.187000.json','["帝炎執鞭驅赤龍，火車萬乘燒長空。", "長空萬里俱藴隆，流金爍石天地同。", "我來亭亭日當午，欲避驕陽竟無所。", "願求一灑楊柳枝，化作東閩萬家雨。"]'),
('26440e83-5859-4137-be50-7fc801dde935','送春','華岳','宋','宋诗','song-poetry','','[]','留春無計奈春何，九十過眼如飛梭。',64,'全唐诗/poet.song.187000.json','["留春無計奈春何，九十過眼如飛梭。", "三分二分風雨爾，十日九日愁悶呵。", "風前飛絮政無數，雨後落花全不多。", "爭如買酒速相就，君自起舞吾能歌。"]'),
('787b07cd-6324-4049-b446-795503c6eae6','僧畫','華岳','宋','宋诗','song-poetry','','[]','萬景峰前老禪叔，搜羅風月歸巖谷。',32,'全唐诗/poet.song.187000.json','["萬景峰前老禪叔，搜羅風月歸巖谷。", "胸中有句吐無聲，寫作生綃三四幅。"]'),
('af1ddded-529a-4757-98e6-e89881dd8a57','賀趙法曹','華岳','宋','宋诗','song-poetry','','[]','紅日轉簷花，飛鳴一聲鵲。',120,'全唐诗/poet.song.187000.json','["紅日轉簷花，飛鳴一聲鵲。", "鵲翅未離簷，有客拽鈴索。", "呼童急啟戶，問客意何若。", "客聞笑而言，法曹參計鑰。", "因知鵲之鳴，報我良不惡。", "知我門下人，一楗聊相托。", "如公材器大，末掾豈能縛。", "咫尺蓬萊宮，左右芙蓉幕。", "直入鳳凰池，更上麒麟閣。", "賤子無所需，願作揚州鶴。"]'),
('0f2cf501-7588-4b94-998d-97e385189b1c','野菜吟','華岳','宋','宋诗','song-poetry','','[]','芙蓉峰下揚雄宅，路入城闉里三百。',160,'全唐诗/poet.song.187000.json','["芙蓉峰下揚雄宅，路入城闉里三百。", "有山無粟養鷄豚，有水無人捕魚鼈。", "山翁菜色流清涎，齒頰連月無腥羶。", "客來問我何所有，手指萬壑煙霞邊。", "青芹不似蘆蒿美，石芥防風空剔齒。", "蕨腦纔抽穉子拳，蘆牙已迸佳人指。", "兒童不待明朝陽，花襟路濕爭慌忙。", "携籠拍塞貯不盡，歸來滿袖春風香。", "攬衣踏破青銅鏡，挼動碧雲流一徑。", "漉歸銀鼎作波濤，無限春工上盤飣。"]'),
('e624f4e1-8e66-49f0-81d1-49e6bd90be82','酒歌','華岳','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','嘗聞子美清江曲，日典春衣耽美祿。',192,'全唐诗/poet.song.187000.json','["嘗聞子美清江曲，日典春衣耽美祿。", "又聞太白遊長安，市上熏熏醉眠熟。", "風流國裏太平時，處處紅樓漾酒旗。", "王孫公子恣行樂，繁絃脆管相追隨。", "誰知寥落天涯客，笠頂清風杖挑月。", "芒鞋踏徧山水雄，奮身欲入黄金闕。", "方嗟蕭索向西園，刮面寒風雨漲天。", "回頭忽喜黑衣至，急破紅泥傾數船。", "雖無皓齒歌金縷，也掃新詩狂欲舞。", "兒童拍手笑攔街，應怪吳儂喜如許。", "長江波浪卷銀山，去去仍悲道路難。", "只憑一醉進未得，更借高風吹片帆。"]'),
('6166494d-cdd4-417b-91c9-70d16bd423cc','寄敬甫葉兄','華岳','宋','宋诗','song-poetry','','[]','歲次丁卯秋，八月既生魄。',288,'全唐诗/poet.song.187000.json','["歲次丁卯秋，八月既生魄。", "于時謫建安，脫去未有策。", "忽覩星鳳光，慨然陪履舄。", "自謂入閩建，閲人幾千百。", "間有知功名，所見得邪僻。", "否則苟利祿，鄙猥何足責。", "獨我子敬甫，挺挺出蠻貊。", "舌端摇戈矛，筆下羅疆埸。", "扣以軍國秘，歷歷有奇畫。", "以此方定交，歸心已翰翮。", "送君東郭門，握手不忍釋。", "明年入中都，首上平戎策。", "甫結君相知，便念長沙謫。", "細草天子書，願置孤臣驛。", "論薦方躊躇，倚門重垂白。", "轍環溫凊圍，笑言方啞啞。", "去我兩牛鳴，恍若關山隔。", "去年槐花黄，郡國書貢籍。", "若以經濟材，俯亦從此役。", "白屋寄簪纓，青燈聯袵席。", "談笑生風雷，議論燦金碧。", "雪香飛梅花，歸鞍整南陌。", "別後殊未幾，拳拳在朝夕。", "君腹坦東牀，吾身繫西圜。"]'),
('36c210b7-31a2-427b-b6bd-b846c9189745','記夢','華岳','宋','宋诗','song-poetry','','[]','夜漏徹三更，夢牛入我屋。',228,'全唐诗/poet.song.187000.json','["夜漏徹三更，夢牛入我屋。", "有角斷而懸，有足折而縮。", "驚覺細思量，讖有何禍福。", "兆者事之先，形者心之屬。", "事既兆于心，夢乃形于腹。", "入屋牛有蓋，爲牢事刑獄。", "吾今尚縲囚，其應已桎梏。", "體具牢方具，無足牢不足。", "不足意無他，示予可脫輻。", "去蓋只論牛，其義尤可錄。", "牛足不下垂，得一生可續。", "牛角不上橫，得某去何速。", "一旦忤君心，吾罪當何贖。", "生去氣橫秋，風馬不相逐。", "下裂輿地圖，上應周天宿。", "崢嶸挽萬鈞，其始播百穀。", "身雖在籠檻，志不經溝瀆。", "甯戚不吾歌，丙吉當吾哭。", "安得如齊王，過堂憐觳觫。"]'),
('1f330f59-9c45-4874-a74b-b88561bc7fcd','琴','華岳','宋','宋诗','song-poetry','','[]','月浸虛堂夜氣清，起聽萬籟寂無聲。',32,'全唐诗/poet.song.187000.json','["月浸虛堂夜氣清，起聽萬籟寂無聲。", "輕輕拂動匣面塵，玉笋不彈風自鳴。"]'),
('9de46249-9f1b-46cb-9cac-4f04420efd3e','苦蚊','華岳','宋','宋诗','song-poetry','','[]','四壁人聲絕，榻下蚊煙滅。',24,'全唐诗/poet.song.187000.json','["四壁人聲絕，榻下蚊煙滅。", "可憐翠微翁，一夜敲打拍。"]'),
('bad5da9e-c2c0-46c4-aa70-3d1857809064','次李信州七十韵','華岳','宋','宋诗','song-poetry','','[]','挺挺萬人傑，堂堂間世賢。',288,'全唐诗/poet.song.187000.json','["挺挺萬人傑，堂堂間世賢。", "胸中兵十萬，足下客三千。", "揚賦希三嘆，坡詩和百篇。", "錦囊華似衮，綵筆大如椽。", "隨陸縱橫舌，良平左右肩。", "兩驂公子服，四牡魯侯畋。", "量闊滄溟岸，胸蟠泰華巔。", "紅壇歌魯杏，白社結陶蓮。", "遣幣通秦好，求姻托鄭㜕。", "匣藏須虎兕，冠飾待貂蟬。", "標自龍頭奪，書由鴈足傳。", "不侯嗤李廣，求使短張騫。", "食客希毛遂，茶僧集大顛。", "詩材親子建，字法邁公權。", "黄貉蒙金絡，青驄勒寶韉。", "伐燕欺騎劫，聘魯慢韓穿。", "周室歌山甫，齊人美仲連。", "劍從豐水鑄，碑向峴山鎸。", "有頌褒唐太，無詩刺衛宣。", "檄堪傳代郡，節可仗居延。", "聽訟疎淹禁，豐財剔冗員。", "策從之反後，鞭著祖生先。", "孝有參而已，忠如丘者焉。", "春冰同皎潔，秋月共嬋娟。"]'),
('805a056c-254d-4183-ac54-fd6e9b3ed373','丹青閣','華岳','宋','宋诗','song-poetry','','[]','未識丹青意，凭欄試解嘲。',144,'全唐诗/poet.song.187000.json','["未識丹青意，凭欄試解嘲。", "煙雲朝起陸，汀渚暮生潮。", "山卓數枝筆，天橫一幅綃。", "霞收紅暈淺，溪褪綠痕消。", "箇裏風煙冷，于中景物饒。", "飛黄凌翠閣，寒碧瞰紅橋。", "酒盡香凝甕，詩成錦掣標。", "朱衣扶客醉，翠袖殢人嬌。", "屏帳接千里，畫圖連九霄。", "長風來水尾，斜日轉山腰。", "赤脚支筇穩，蒼頭控馬驕。", "老臣今已矣，兒女總金貂。"]'),
('d3d7f837-d4b0-4ac5-a6b2-35a8370c5d96','上韓平原','華岳','宋','宋诗','song-poetry','','[]','君家勳業在盤盂，莫把頭顱問钃鏤。',64,'全唐诗/poet.song.187000.json','["君家勳業在盤盂，莫把頭顱問钃鏤。", "漢地不埋王莽骨，唐天難庇祿山軀。", "不隨召奭始求老，便學孔明終托孤。", "十廟英靈儼如在，謾于宗社作穿窬。"]'),
('be6860fb-52a1-45fc-b2ce-5f2637d0700b','清富樓  其一','華岳','宋','宋诗','song-poetry','','[]','楞伽心地有瞿曇，清富名樓足可觀。',64,'全唐诗/poet.song.187000.json','["楞伽心地有瞿曇，清富名樓足可觀。", "買斷江山詩料足，揭開風月畫圖寬。", "都無一點紅塵到，便作千雙白璧看。", "我欲鞭馿快幽賞，白鷗盟在不憂寒。"]'),
('2c1541cb-0836-4dc8-bedf-0aad3c5ce517','清富樓  其二','華岳','宋','宋诗','song-poetry','','[]','去年清富屢求詩，今日凭闌約翠微。',64,'全唐诗/poet.song.187000.json','["去年清富屢求詩，今日凭闌約翠微。", "山带野花堪入畫，水環汀草欲成圍。", "一園黄菊有餘食，兩頃白雲無限衣。", "說與塵寰守錢虜，不勞魂夢到禪扉。"]'),
('e695646a-31ef-48c1-9aad-a442a70f8d5d','出郭','華岳','宋','宋诗','song-poetry','','[]','十客聯鑣出北門，馬蹄剜盡碧苔痕。',64,'全唐诗/poet.song.187000.json','["十客聯鑣出北門，馬蹄剜盡碧苔痕。", "從教管史占星聚，且聽盃人和月吞。", "我欲求仙問離坎，君當隨佛整乾坤。", "樽前慷慨休辭醉，明日有懷誰共論。"]'),
('fcdc03fe-0d64-44c6-b276-925575838c3a','舍後丈地令人植花種竹悶則邀清風明月盡醉而倒','華岳','宋','宋诗','song-poetry','','[]','有地都來一丈餘，墾鋤元不費工夫。',64,'全唐诗/poet.song.187000.json','["有地都來一丈餘，墾鋤元不費工夫。", "匝牆先種竹三本，遶檻却栽花數株。", "風伯喚來煩解珮，月娥邀得醉携壺。", "憑君試向蓬萊問，還有神仙似我無。"]'),
('0df7e0f0-7e01-4b88-8fe3-59be5240caa6','送周魁','華岳','宋','宋诗','song-poetry','','[]','昨夜霜風鼓萬兵，今朝華節照邊庭。',64,'全唐诗/poet.song.187000.json','["昨夜霜風鼓萬兵，今朝華節照邊庭。", "人間元日是春日，天上魁星爲使星。", "且向虎囊探寸尺，却歸麟閣倣丹青。", "離觴不是延清夜，明日異邦長短亭。"]'),
('83009ba1-e922-4eaf-aa7c-f0871f43b041','二月二日即事','華岳','宋','宋诗','song-poetry','','[]','春潮昨夜沒平灘，一雨催花色半含。',64,'全唐诗/poet.song.187000.json','["春潮昨夜沒平灘，一雨催花色半含。", "鴈喚元宵歸塞北，燕銜新社到江南。", "無歡不必遊花籍，有病何須置藥籃。", "只把公忠答天地，從教兒女閙冠簪。"]'),
('b261981d-6fa6-4205-b048-f52f15814de3','登樓晚望','華岳','宋','宋诗','song-poetry','','[]','六曲朱闌瞰碧虛，淡煙秋水接平蕪。',64,'全唐诗/poet.song.187000.json','["六曲朱闌瞰碧虛，淡煙秋水接平蕪。", "展開風月添詩料，裝點江山歸畫圖。", "舉足便堪馳駟馬，折腰何必問雙鳬。", "當年庾亮今還在，定約樓前醉一壺。"]'),
('1a312587-1bb3-4381-8d3f-de977a94598c','訓爨婢','華岳','宋','宋诗','song-poetry','','[]','十載膠庠莫怪窮，旅囊安得有從容。',64,'全唐诗/poet.song.187000.json','["十載膠庠莫怪窮，旅囊安得有從容。", "無錢休欠牛羊債，有酒只將魚蟹供。", "班頷昔嘗肥似燕，沈腰今已瘦如蜂。", "從今莫恣肥甘口，只擷清蔬祭豢龍。"]'),
('3c2436b3-cb02-42d3-94db-dd57ddc2a0da','別藍詳道','華岳','宋','宋诗','song-poetry','','[]','君在江東我水西，君今北去我南歸。',64,'全唐诗/poet.song.187000.json','["君在江東我水西，君今北去我南歸。", "竹孫和客凌風瘦，梅子偏他得雨肥。", "鶑囀好聲歸酒斚，花分紅影上人衣。", "相看莫作皺眉別，期子秋高賦式微。"]'),
('063027f3-7fce-4cb4-8061-2851271d02c2','傷春','華岳','宋','宋诗','song-poetry','','[]','初入京華菊薦香，途中今已過春芳。',64,'全唐诗/poet.song.187000.json','["初入京華菊薦香，途中今已過春芳。", "十年恰走萬餘里，兩鬢幾乎一半霜。", "却酒不禁春黯淡，落花愁對月昏黄。", "不堪夜半歸心切，更被杜鵑啼斷腸。"]'),
('8c47d5f4-4dbd-43fb-8fcc-38c7380cde63','別子陳子','華岳','宋','宋诗','song-poetry','','[]','丙寅三月三十日，天子檄我南國行。',64,'全唐诗/poet.song.187000.json','["丙寅三月三十日，天子檄我南國行。", "蒲劍欲飛春漲急，柳綿才脫曉寒輕。", "事非得已初何好，物到不平終作聲。", "自古英雄總多難，賈梁何必怨清明。"]'),
('d70dc220-2f1d-4190-9c79-5d0e65453e4d','河魨','華岳','宋','宋诗','song-poetry','','[]','形容初不類魚蝦，偏稱蘆蒿與荻芽。',64,'全唐诗/poet.song.187000.json','["形容初不類魚蝦，偏稱蘆蒿與荻芽。", "觸物可憐空怒腹，囓人無計謾聱牙。", "子排金粟真堪畏，乳溜玉酥何足誇。", "從此烹鮮督庖吏，只將鮎鳠假名它。"]'),
('ac58c906-f1d5-45ba-ac57-d28410c31289','自嘆','華岳','宋','宋诗','song-poetry','','[]','自嘆身謀我獨疎，只貪風月恣歡娛。',64,'全唐诗/poet.song.187000.json','["自嘆身謀我獨疎，只貪風月恣歡娛。", "盃盤遇客隨多寡，囊橐何時問有無。", "萬里梯航無罥罣，十年牆屋有穿窬。", "從今老去無他望，綠綺一張醪一壺。"]'),
('ce2fe2ff-1029-49ea-91c1-a92ae41d70fb','春日書懷','華岳','宋','宋诗','song-poetry','','[]','紫褪紅銷到海棠，幾多遊俠爲渠忙。',64,'全唐诗/poet.song.187000.json','["紫褪紅銷到海棠，幾多遊俠爲渠忙。", "秋聲落盞鶑調曲，春色惱人花鬭香。", "羝乳雖能屈蘇武，牛衣終不卧王章。", "男兒多少英雄氣，只對東風醉幾場。"]'),
('9b8cd159-3f26-46f7-aabd-cfadfec6d5d5','過文脊山','華岳','宋','宋诗','song-poetry','','[]','百峰攢碧版橋西，眼力增明步武遲。',64,'全唐诗/poet.song.187000.json','["百峰攢碧版橋西，眼力增明步武遲。", "紅映竹籬花笑客，翠翻雲幕雨催詩。", "蕡還及第吾何媿，廣不封侯子未思。", "凡物不齊皆有謂，到頭忠義是男兒。"]'),
('20bcc2a9-1a81-4733-af86-b88f8c255fc6','熱','華岳','宋','宋诗','song-poetry','','[]','翠微家在大江東，五月鞭馿入建中。',64,'全唐诗/poet.song.187000.json','["翠微家在大江東，五月鞭馿入建中。", "雲烈火車天欲雨，汗淹香葛扇無風。", "不求殿閣千間庇，却喜巖泉一線通。", "爲汲滿盂清齒頰，與君行盡夕陽紅。"]'),
('6f399a7f-d8a5-48b5-9a62-da33fd689d2c','有感','華岳','宋','宋诗','song-poetry','','[]','十年憂患客江城，雙鬢蕭蕭已不禁。',64,'全唐诗/poet.song.187000.json','["十年憂患客江城，雙鬢蕭蕭已不禁。", "多病不逢醫國手，感懷徒有濟時心。", "西風吹夢夜寒悄，黄葉滿階秋意深。", "休笑當年杜陵老，白頭今亦不勝簪。"]'),
('81464f77-87e2-4bd5-ba30-9025f9e3d04a','悶中賡趙丞韵','華岳','宋','宋诗','song-poetry','','[]','壯士不同兒女曹，誰云賦性太粗豪。',64,'全唐诗/poet.song.187000.json','["壯士不同兒女曹，誰云賦性太粗豪。", "一編韜略進擒虎，十轄絲綸學釣鼇。", "劍口不磨韓信血，鼎心須刮食其膏。", "英雄多少不平氣，一夜朔風爭怒號。"]'),
('cb272ea8-9578-4a9f-8feb-08d3131aee6f','秋宵有感','華岳','宋','宋诗','song-poetry','','[]','滿目秋容拂畫圖，敗荷衰柳接平蕪。',64,'全唐诗/poet.song.187000.json','["滿目秋容拂畫圖，敗荷衰柳接平蕪。", "西風刮地鴈聲落，寒月滿天人影孤。", "木耳有才持紫橐，楮皮無計換青蚨。", "不知此去功名事，還許封彝見也無。"]'),
('cab0d7cc-52f6-44f4-9e95-71f1f333505f','過羊腸嶺','華岳','宋','宋诗','song-poetry','','[]','拂面東風吹夕陽，路蟠千折過羊腸。',64,'全唐诗/poet.song.187000.json','["拂面東風吹夕陽，路蟠千折過羊腸。", "山疑隨馬回回見，花欲撩人故故香。", "世路與誰分曲直，人情于我自炎凉。", "何當更上風烟上，爲把窮途問彼蒼。"]'),
('4f53e2cc-d6e0-4e0d-84da-48641c5293a7','宿橫溪橋','華岳','宋','宋诗','song-poetry','','[]','夜宿橫溪煙靄間，眉頭歸路萬山攢。',64,'全唐诗/poet.song.187000.json','["夜宿橫溪煙靄間，眉頭歸路萬山攢。", "連天麥浪波千頃，撲地楊花雪一團。", "餘鏹不供春後醖，夾衾猶怯夜來寒。", "征夫莫怪車音澀，自是愁多行路難。"]'),
('530e93d1-5025-4464-a790-964243470021','送倪尚書赴召','華岳','宋','宋诗','song-poetry','','[]','守節如初未足觀，毫釐終始實其艱。',64,'全唐诗/poet.song.187000.json','["守節如初未足觀，毫釐終始實其艱。", "鄭公勇却樞衡貴，衛叔羞居荷橐班。", "冷暖萬端炊飯頃，是非一著弈棋間。", "江湖無限孤高客，拭目看公此召還。"]'),
('512c21c2-ddac-4450-ac2c-6fe4bd1e6858','宿嚴瀨','華岳','宋','宋诗','song-poetry','','[]','遐想高風殊未厓，艤舟夜訪子陵臺。',64,'全唐诗/poet.song.187000.json','["遐想高風殊未厓，艤舟夜訪子陵臺。", "銜山西照情何限，逝水東流夢不回。", "雙槳未聞卿月過，一尊先爲客星開。", "東都人物俱煨燼，獨有先生迹未灰。"]'),
('9546d619-0f1a-415c-973f-7dbf69069ad1','題澤民廟','華岳','宋','宋诗','song-poetry','','[]','生握藩旌死象梨，澤民山下澤民谿。',64,'全唐诗/poet.song.187000.json','["生握藩旌死象梨，澤民山下澤民谿。", "蒼天九重開日月，赤地千里興雲霓。", "寐假商宗曾得說，爵高韓信屢封齊。", "英雄不入蒼生眼，願借高風吹馬蹄。"]'),
('6b79f794-9943-4977-8915-e2445896d107','早春即事','華岳','宋','宋诗','song-poetry','','[]','楊柳絲絲弄淡黄，怯寒燕子未歸梁。',64,'全唐诗/poet.song.187000.json','["楊柳絲絲弄淡黄，怯寒燕子未歸梁。", "曉迷芳草騅騣濕，夜宿閒花蝶翅香。", "得句自慚非子美，賞音猶恐誤中郎。", "願言相約花前醉，莫放春容過海棠。"]'),
('36ea14e7-214a-4741-928c-154b40bc2965','早行述懷','華岳','宋','宋诗','song-poetry','','[]','歸心夜半已飛揚，喚僕吹燈促曉粧。',64,'全唐诗/poet.song.187000.json','["歸心夜半已飛揚，喚僕吹燈促曉粧。", "雞翅拍斜茅店月，馬蹄剜破板橋霜。", "二陵萬里埋荆棘，十廟百年生稻粱。", "安得有臣如祖逖，慨然擊楫誓江長。"]'),
('2c91846a-c21c-47cc-9242-c8848946c136','題易村','華岳','宋','宋诗','song-poetry','','[]','路轉峰回覺有村，數間茅屋瞰山陰。',64,'全唐诗/poet.song.187000.json','["路轉峰回覺有村，數間茅屋瞰山陰。", "午炊已飽翻匙玉，臘醖仍拚掛杖金。", "窮去作文和鬼送，興來得句倩蟬吟。", "一聲橫笛斜陽外，吹起江湖萬里心。"]'),
('448f4d16-2c85-4923-905e-4fa5cec0adab','述事','華岳','宋','宋诗','song-poetry','','[]','心不融明遂啟疑，源流本末致交馳。',64,'全唐诗/poet.song.187000.json','["心不融明遂啟疑，源流本末致交馳。", "谷何嘗響人相喚，岸幾曾行舟自移。", "枉直萬端明似鏡，是非一著錯如棋。", "磨心拔去誰能轉，試問諸公知不知。"]'),
('c64c01dc-d646-4536-8c49-a4b47f981f75','述懷','華岳','宋','宋诗','song-poetry','','[]','我生不解覓冠裳，滿目風波祇自傷。',64,'全唐诗/poet.song.187000.json','["我生不解覓冠裳，滿目風波祇自傷。", "楮券不堪供虜幣，沙籌那解足軍糧。", "人情在我隨多寡，世態從他自短長。", "只告天公乞安樂，百年隨分老農桑。"]'),
('f8482ba2-f25a-4df0-b8ac-33a41e877e08','寄劉浩然','華岳','宋','宋诗','song-poetry','','[]','樽酒檠窗鬢髮新，別來驚見雪霜侵。',64,'全唐诗/poet.song.187000.json','["樽酒檠窗鬢髮新，別來驚見雪霜侵。", "幾行淚滴風前燭，一片心敲月下砧。", "好德未聞如好色，知人安得似知音。", "一書欲寄南來鴈，江闊天高無處尋。"]'),
('621ab0cd-3c18-43bf-839a-877e6bb65b11','知遇','華岳','宋','宋诗','song-poetry','','[]','淮陰西漢一英雄，史氏持衡論亦工。',64,'全唐诗/poet.song.187000.json','["淮陰西漢一英雄，史氏持衡論亦工。", "不向追亡羨蕭相，却于援死著滕公。", "豈知並績三人傑，皆自當時一語功。", "後世人材自戕賊，炎凉安得古人風。"]'),
('5033d59b-f66f-4a76-b064-3d02247bc553','和戎','華岳','宋','宋诗','song-poetry','','[]','納幣求成事已非，可堪函首獻戎墀。',64,'全唐诗/poet.song.187000.json','["納幣求成事已非，可堪函首獻戎墀。", "一天共戴心非石，九地皆塗血尚泥。", "反漢須知爲鼂錯，成秦恐不在於期。", "和戎自有和戎策，却恐諸公未必知。"]'),
('f85b330d-b773-4f3a-b913-c19df88b561f','自寬','華岳','宋','宋诗','song-poetry','','[]','十事相尋九不諧，骨窮更值五行乖。',64,'全唐诗/poet.song.187000.json','["十事相尋九不諧，骨窮更值五行乖。", "人情厚薄且隨分，世態炎凉休掛懷。", "家欲自豐無楮幣，爨憑誰執有荆釵。", "如今且任眼前過，他日功名殊未涯。"]'),
('4bd13a4c-2b61-494b-b39e-bcc55437be53','黄氏三層樓','華岳','宋','宋诗','song-poetry','','[]','瘦筇支我上高寒，風露淒清酒力慳。',64,'全唐诗/poet.song.187000.json','["瘦筇支我上高寒，風露淒清酒力慳。", "千里人邀千里月，一重樓見一重山。", "筵前飛雪噴焦遂，檻外行雲遏小蠻。", "便好翻身駕黄鵠，直將情枉扣天關。"]'),
('86855f4c-5192-4d50-93b9-feb8af871d60','幽居','華岳','宋','宋诗','song-poetry','','[]','莫問門無長者車，只圖深巷樂樵漁。',64,'全唐诗/poet.song.187000.json','["莫問門無長者車，只圖深巷樂樵漁。", "一園黄落食無限，萬壑碧蓑衣有餘。", "鴈足北來歸訊杳，馬蹄南去故人疎。", "東風看整朝天旆，多少功名在故廬。"]'),
('7031cdeb-c6b8-4807-9fc1-5ae92dee352f','賀趙丞登第','華岳','宋','宋诗','song-poetry','','[]','要與宗盟立紀綱，俯從多士較文章。',64,'全唐诗/poet.song.187000.json','["要與宗盟立紀綱，俯從多士較文章。", "人材漏網無疏密，科目搜羅有短長。", "蟾窟一枝分玉樹，鳳池三浪出銀潢。", "何當推解延豪傑，爲復中原萬里疆。"]'),
('40787ac9-20ce-4fe9-9477-3521e7e3f02b','梅','華岳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一年無處覓春光，杖策尋春特地忙。',64,'全唐诗/poet.song.187000.json','["一年無處覓春光，杖策尋春特地忙。", "牆角數枝偏冷淡，江頭千樹欲昏黄。", "梢橫波面月摇影，花落樽前酒带香。", "更仗西湖老居士，爲予收拾付詩囊。"]'),
('6af92f24-fc64-48e1-93b0-911c8a8c75c6','捉月仙','華岳','宋','宋诗','song-poetry','','[]','纜解西風拍岸顛，鴈拖秋色上航船。',64,'全唐诗/poet.song.187000.json','["纜解西風拍岸顛，鴈拖秋色上航船。", "掛帆未作乘風客，舉棹先驚捉月仙。", "楚些有淵心石殞，賀狂無井眼花眠。", "慇懃爲酹一杯酒，斷送西江浪拍天。"]'),
('d275c556-6f7d-4d9e-989e-2c0a983668e6','呈寧次翁','華岳','宋','宋诗','song-poetry','','[]','王謙不事富春侯，自是薰蕕味不侔。',64,'全唐诗/poet.song.187000.json','["王謙不事富春侯，自是薰蕕味不侔。", "病體隔年留枉獄，夢魂連夜逐歸舟。", "可憐商木遷新令，欲爲韓門復舊讐。", "但得此心無所愧，爲公一死亦何尤。"]'),
('1cac66a2-0a5a-4ae9-a886-b42a9c4d903b','悶成','華岳','宋','宋诗','song-poetry','','[]','勿憂李廣不封侯，廣不封侯未足憂。',64,'全唐诗/poet.song.187000.json','["勿憂李廣不封侯，廣不封侯未足憂。", "漢鼎不烹曹操肉，吳鈎空斷伍員頭。", "鴻門自昔推屠狗，虎帳于今愧沐猴。", "千萬南陽遇徐庶，爲言豪傑尚縲囚。"]'),
('538b8051-a137-4ffb-b98d-2dd65c5e5403','別館即事','華岳','宋','宋诗','song-poetry','','[]','十年客裏過春光，客裏逢春分外狂。',64,'全唐诗/poet.song.187000.json','["十年客裏過春光，客裏逢春分外狂。", "半堵碧雲蝸路濕，一簾紅雨燕泥香。", "銜山西日辭春閣，拍岸東風趁夜航。", "莫向錢塘蘇小說，東吳新髻李紅娘。"]'),
('e25106ff-59a4-4c4b-82d3-e7eeee230403','武興解舟','華岳','宋','宋诗','song-poetry','','[]','西風落日楚江頭，秋水已平鸚鵡洲。',64,'全唐诗/poet.song.187000.json','["西風落日楚江頭，秋水已平鸚鵡洲。", "煙樹接天迷送旆，浪花翻雪噴行舟。", "三盃萬事我已飽，一日千里誰能留。", "見說平戎新遣使，班超投筆已封侯。"]'),
('a970cf2d-0918-4fa2-9d8b-fcc414a1a7ed','不遇','華岳','宋','宋诗','song-poetry','','[]','英雄不遇勿長吁，苟遇風雲彼豈拘。',64,'全唐诗/poet.song.187000.json','["英雄不遇勿長吁，苟遇風雲彼豈拘。", "不向關中效蕭相，便于江左作夷吾。", "當知晉霸非由晉，所謂虞亡豈在虞。", "多少英靈費河嶽，鍾子不遇獨何歟。"]'),
('0b18f9dd-d49e-4172-8ca8-8c5d49322265','紀事','華岳','宋','宋诗','song-poetry','','[]','鉗口刳腸未足殫，窮原探本可觀瀾。',64,'全唐诗/poet.song.187000.json','["鉗口刳腸未足殫，窮原探本可觀瀾。", "乞醯孰謂鄰非直，反矢須知友必端。", "暴虎欲從頭碎璧，沐猴還慮髮衝冠。", "積薪措火居其下，試問賈生安未安。"]'),
('1bcdbc17-eb2e-44fc-8c92-dacc0dff3a40','冬日述懷','華岳','宋','宋诗','song-poetry','','[]','寒入肌膚粟已生，銀河凍合水無聲。',64,'全唐诗/poet.song.187000.json','["寒入肌膚粟已生，銀河凍合水無聲。", "梅花漏泄春先到，風色商量雪未成。", "有愧何須問天理，無求方始合人情。", "男兒未際風雲會，辜負胸中十萬兵。"]'),
('1a121d2a-19b7-4157-a12d-7bd7d16b7ed4','暮春述懷','華岳','宋','宋诗','song-poetry','','[]','一年春事已差池，又見楊花貼水飛。',64,'全唐诗/poet.song.187000.json','["一年春事已差池，又見楊花貼水飛。", "梁燕不憂驚午枕，箔蠶生怕誤春衣。", "景逢佳處須行樂，事到難時且式微。", "幸有黄雞并濁酒，且和風月醉柴扉。"]'),
('a3f651d4-755b-460b-8cda-120f95250043','幽居','華岳','宋','宋诗','song-poetry','','[]','十頃平湖一簇山，湖山佳處著朱闌。',64,'全唐诗/poet.song.187000.json','["十頃平湖一簇山，湖山佳處著朱闌。", "分階草色迎春綠，漱石泉聲入夜寒。", "不擾自然人事好，有爲方信世途難。", "如今休說當年事，只把心平氣定看。"]'),
('0894131b-0d81-4cd9-899c-5955e3063b0e','謝二劉','華岳','宋','宋诗','song-poetry','','[]','鴈行臨慰暖如春，玉粒金包即拜恩。',64,'全唐诗/poet.song.187000.json','["鴈行臨慰暖如春，玉粒金包即拜恩。", "周粟不肥清聖肉，楚絲難繫直臣魂。", "二生在昔聞孤竹，一死于今愧屈原。", "圓簠下頒誠有謂，此情兄外更誰論。"]'),
('062d8f1f-8329-4324-8d43-2b4681c9cfdc','暮春述懷','華岳','宋','宋诗','song-poetry','','[]','買春無計托花神，費盡榆錢不計緡。',64,'全唐诗/poet.song.187000.json','["買春無計托花神，費盡榆錢不計緡。", "風絮飛成三徑雪，雨犂翻動一園春。", "有心報國從招禍，無相封侯莫怨貧。", "試問專壇與分社，予何人彼亦何人。"]'),
('96c3c32f-e08a-43a3-9415-0f1ed16bfd19','呈諸同舍','華岳','宋','宋诗','song-poetry','','[]','洛陽年少不知幾，十載南州賦式微。',64,'全唐诗/poet.song.187000.json','["洛陽年少不知幾，十載南州賦式微。", "三舉不登黄甲去，兩庠空笑白丁歸。", "頭長賈昔過三尺，腰大巨今徒十圍。", "祇恐金鑾不前席，誰云無策富王畿。"]'),
('9e37d4ad-b39d-4414-8446-81f519ef0060','寄陳士元','華岳','宋','宋诗','song-poetry','','[]','郊野英雄不肯收，膏粱芻豢有何謀。',64,'全唐诗/poet.song.187000.json','["郊野英雄不肯收，膏粱芻豢有何謀。", "胡兒只怒馬黄弩，公子當求狐白裘。", "唐詔屢頒蕡不第，漢壇纔築信當侯。", "古今得喪同兒戲，何必區區嘆白頭。"]'),
('b41316dc-f382-4de6-82e3-9ebd22c8b511','貧居','華岳','宋','宋诗','song-poetry','','[]','貧居不暇理椽茅，只倩江山圍一遭。',64,'全唐诗/poet.song.187000.json','["貧居不暇理椽茅，只倩江山圍一遭。", "林鳥樂時知地僻，嶺雲閒處覺天高。", "春衫著破重連線，臈酒擎乾獨醡糟。", "且把盃盤聊自適，不須平地起風濤。"]'),
('f79da953-8b22-460e-91ee-7b138d5f35af','呈魯功甫','華岳','宋','宋诗','song-poetry','','[]','拂面東風二月天，綠楊芳草暗平川。',64,'全唐诗/poet.song.187000.json','["拂面東風二月天，綠楊芳草暗平川。", "花容著雨鬭翻錦，春色惱人催禁煙。", "燈夜雖然君有約，花時却恐我無緣。", "直須得暇來相訪，當約嫦娥伴醉眠。"]'),
('0c9e659d-1562-4ddb-ad8a-94c059719153','勉馮著明','華岳','宋','宋诗','song-poetry','','[]','主憂臣辱已難堪，國事顛危况未安。',64,'全唐诗/poet.song.187000.json','["主憂臣辱已難堪，國事顛危况未安。", "溺嫂臨淵猶援手，鬭人同室尚攖冠。", "公如不唱從軍樂，士亦恐歌行路難。", "麟閣功名總勞苦，莫將行役作辛酸。"]'),
('1f8f4092-d2ab-4254-80d3-eafc8ecad76e','藕花','華岳','宋','宋诗','song-poetry','','[]','惜絲不肯織宮鞋，花月仙人謫不來。',64,'全唐诗/poet.song.187000.json','["惜絲不肯織宮鞋，花月仙人謫不來。", "河伯借泥封玉腕，風神翻浪沃香腮。", "無房不許蜂留宿，有蓋嘗令鷺自開。", "何事冤仇結青女，一朝收拾付塵灰。"]'),
('1f454c78-8128-4852-8a5f-e0a248f10c6e','自勉','華岳','宋','宋诗','song-poetry','','[]','世態風波不可論，且于閒處樂天真。',64,'全唐诗/poet.song.187000.json','["世態風波不可論，且于閒處樂天真。", "肥家無子堪登隴，憂國有人休問津。", "顔色雖蒙時借我，脚跟那解日隨人。", "客來若問當時事，摇手無言對北鄰。"]'),
('a267b0e1-a4a2-4af2-b8c7-d54c8691ac93','初夏即事','華岳','宋','宋诗','song-poetry','','[]','陰晴未判落梅天，柳巷無人絮撲氈。',64,'全唐诗/poet.song.187000.json','["陰晴未判落梅天，柳巷無人絮撲氈。", "滌器倒囊尋市醖，喚船挑網得溪鮮。", "鳥聲呼夢客千里，山色撩人句一聯。", "遐想故人應念我，馬蹄何處夕陽邊。"]'),
('05c0b3b3-75fc-40c7-a939-f19b1b64dd6c','呈鍾子嚴','華岳','宋','宋诗','song-poetry','','[]','那條路不通長安，莫把心腸獨自剜。',64,'全唐诗/poet.song.187000.json','["那條路不通長安，莫把心腸獨自剜。", "有釀何須兒索飲，無殽徒勸客加餐。", "千金不賞思歸楚，萬戶無封願識韓。", "大抵利名些子耳，幾多豪傑被縈絆。"]'),
('8bd162bf-57b8-4436-b211-781cfb43ab4c','寄楊渭夫','華岳','宋','宋诗','song-poetry','','[]','自愧材猷不足觀，獨于忠義死難干。',64,'全唐诗/poet.song.187000.json','["自愧材猷不足觀，獨于忠義死難干。", "二陵風雨誰思漢，萬里腥羶誰報韓。", "眼到北盟常揾血，話殘南渡欲衝冠。", "如何一代多人傑，稽首稱藩鼻不酸。"]'),
('60d8b02b-30bd-4fcc-a8c6-9c01adf87744','幽居','華岳','宋','宋诗','song-poetry','','[]','瀟灑幽居屋一重，入門花柳間青紅。',64,'全唐诗/poet.song.187000.json','["瀟灑幽居屋一重，入門花柳間青紅。", "簾嘗礙月鈎嘗掛，酒不逢花盞不空。", "畏愛難全公子日，雌雄誰識大王風。", "且將酒貨遷詩料，休問榷場通未通。"]'),
('9a5d489f-d5dd-47d3-84f5-78ec9fa898c7','呈王君庸','華岳','宋','宋诗','song-poetry','','[]','主人意重出霓裳，客子愁多欲斷腸。',64,'全唐诗/poet.song.187000.json','["主人意重出霓裳，客子愁多欲斷腸。", "眉黛暗傳春去恨，臉紅猶带夜來粧。", "竹根穉子肌膚滑，葉底荷花語笑香。", "多少行雲在巫峽，謾將詩思惱襄王。"]'),
('c9810f80-9774-479e-a258-2a12da3a869d','寄西山','華岳','宋','宋诗','song-poetry','','[]','宮牆無地可穿窬，猶幸先人有敝廬。',64,'全唐诗/poet.song.187000.json','["宮牆無地可穿窬，猶幸先人有敝廬。", "仕版可羞寧毀瓦，儒冠曾誤枉收書。", "供柴我合同收炭，寄食君當自辦蔬。", "此理曉然明似鏡，何須足下肆耕鋤。"]'),
('f84c0b55-c16e-476e-9356-de4143e37a79','呈李朝舉','華岳','宋','宋诗','song-poetry','','[]','一片忠肝照日明，濟時無策苦傷情。',64,'全唐诗/poet.song.187000.json','["一片忠肝照日明，濟時無策苦傷情。", "聱牙拊几悔南渡，和淚挑燈編北盟。", "漢用檄招三十郡，楚因歌散八千兵。", "太平若鬭生靈肉，何用生靈望太平。"]'),
('dcfa1471-3689-4c79-a818-974556919860','小春言懷','華岳','宋','宋诗','song-poetry','','[]','桃李生香花滿谿，南州十月尚襜衣。',64,'全唐诗/poet.song.187000.json','["桃李生香花滿谿，南州十月尚襜衣。", "春從酒罋榨將出，秋在詩囊带得歸。", "弓射十分方破的，棋高一著便爭機。", "勸君莫作等閒看，毫髮差殊事已非。"]'),
('ef0c5e9a-89db-415e-b1b9-1afd73126c80','春愁','華岳','宋','宋诗','song-poetry','','[]','十日春愁不出門，出門春事已消魂。',64,'全唐诗/poet.song.187000.json','["十日春愁不出門，出門春事已消魂。", "摘花掀帽倩人插，索酒得盃和月吞。", "啼鳥聲中近寒食，落花陰裏又黄昏。", "春來春去總休問，往事悠悠付一樽。"]'),
('c4c5005d-a3bd-4a6f-a903-09582e34370b','呈徐商卿','華岳','宋','宋诗','song-poetry','','[]','十年憂患謫東南，萬事于心了不關。',64,'全唐诗/poet.song.187000.json','["十年憂患謫東南，萬事于心了不關。", "病去只愁雙足軟，老來且喜一身閒。", "人情無處便生怨，天道有時猶好還。", "大抵久長居富貴，到頭天意亦須慳。"]'),
('c25ebffe-3649-4578-b33f-120f8307454a','春遊有感','華岳','宋','宋诗','song-poetry','','[]','上苑春工到海棠，老夫隨分爲春忙。',64,'全唐诗/poet.song.187000.json','["上苑春工到海棠，老夫隨分爲春忙。", "朱絃轉枕鶑催拍，紅粉倚欄花鬭粧。", "吾道幾時曾損益，人心今日自炎凉。", "願言相約花前醉，一聽兒童號酒狂。"]'),
('0d9ed33b-eaca-4231-ab29-53d2e2cf2643','憂','華岳','宋','宋诗','song-poetry','','[]','憂吾所謂果何憂，憂國憂家卒未休。',64,'全唐诗/poet.song.187000.json','["憂吾所謂果何憂，憂國憂家卒未休。", "坐法馬遷方去漢，釋囚箕子未歸周。", "西風萬籟聲聲恨，夜雨疎桐點點愁。", "有客不知吾所向，却將米價問南州。"]'),
('669911ad-8f5d-42e7-b873-cd229ee11985','述懷','華岳','宋','宋诗','song-poetry','','[]','我生胸次不塵埃，不學兒曹剛自媒。',64,'全唐诗/poet.song.187000.json','["我生胸次不塵埃，不學兒曹剛自媒。", "詩料雖憑風月製，宦途還聽鬼神開。", "十年教養猷初壯，半世功名念已灰。", "安得金鑾有清問，賈生何事未歸來。"]'),
('5b3d7fbe-1951-4875-bdef-c7894f66503f','套筒','華岳','宋','宋诗','song-poetry','','[]','作箇咿𠼳贅項咽，箇中和我萬愁牽。',64,'全唐诗/poet.song.187000.json','["作箇咿𠼳贅項咽，箇中和我萬愁牽。", "一筒作柄簫無竅，雙鐵爲圜扇有圈。", "身拜却疑人是犬，手擎還類筆如椽。", "從今節節能通氣，安得當爲積蓄錢。"]'),
('52059f27-2727-4536-8f84-e39a1a9c8d9d','春郊即事','華岳','宋','宋诗','song-poetry','','[]','東風吹動綺羅塵，翠蓋紅纓處處新。',64,'全唐诗/poet.song.187000.json','["東風吹動綺羅塵，翠蓋紅纓處處新。", "蝶翅拍開千樹雪，鶑聲催老十洲春。", "人生有酒須行樂，吏祿無階且食貧。", "歸客不須籠畫燭，醉和明月上雕輪。"]'),
('c5e5e63d-e9b2-4979-9a1e-e468fea30767','雪','華岳','宋','宋诗','song-poetry','','[]','天低江闊水連天，上下周回一色兼。',64,'全唐诗/poet.song.187000.json','["天低江闊水連天，上下周回一色兼。", "撲雀獵鷹翻白縞，得鱸漁父指青帘。", "馬拋玉勒瓏𤦪落，獅欠金鈴橘柚添。", "得句莫嫌呵凍筆，明年歲事已堪占。"]'),
('41b62155-3ce8-4b35-98b9-0357e95890fc','題富沙廟','華岳','宋','宋诗','song-poetry','','[]','平政橋頭火爍空，富沙宮殿烈煙中。',64,'全唐诗/poet.song.187000.json','["平政橋頭火爍空，富沙宮殿烈煙中。", "地形難撲徒臨水，天意能回遽反風。", "十里爆雷驚客夢，萬家全璧頼神功。", "君王注意恢神武，更乞威靈爲寶沖。"]'),
('6b05d410-b472-423e-ade7-ef358465bad7','次翁正叔溪山勝游之韵','華岳','宋','宋诗','song-poetry','','[]','溪南風物照窗扉，溪北蘭舟纜翠微。',64,'全唐诗/poet.song.187000.json','["溪南風物照窗扉，溪北蘭舟纜翠微。", "雙槳碧雲苔浦合，一簾紅雨杏花飛。", "只知有酒酬佳景，却恨無繩繫落暉。", "更約風流衆年少，明朝依舊莫相違。"]'),
('5de7036f-56bc-44cc-ac6a-2c9894e9a52c','春郊即事','華岳','宋','宋诗','song-poetry','','[]','東風吹不斷輪蹄，處處鞦韆環珮飛。',64,'全唐诗/poet.song.187000.json','["東風吹不斷輪蹄，處處鞦韆環珮飛。", "剪翠弄粧歸髻掠，亂紅翻錦上屏幃。", "花應笑我春嘗醉，燕解嘲人夜不歸。", "莫怪逢春太娛樂，人生能有幾芳菲。"]'),
('f548589c-f265-4533-99f6-137164c6c485','悶題','華岳','宋','宋诗','song-poetry','','[]','此心忠義出天資，奴隸兒童莫强爲。',64,'全唐诗/poet.song.187000.json','["此心忠義出天資，奴隸兒童莫强爲。", "燕雀不知鴻鵠志，牛羊徒飾虎狼皮。", "事當桀犬吠堯日，書在塞鴻歸漢時。", "拔劔問天天不語，料天還愧負男兒。"]'),
('9a40e224-6b77-4939-a581-f3f8af1199bc','呈陳平仲','華岳','宋','宋诗','song-poetry','','[]','達人安分樂平生，不與陰陽造化爭。',64,'全唐诗/poet.song.187000.json','["達人安分樂平生，不與陰陽造化爭。", "漢節有人恭且止，楚盤無客遂當行。", "薦公地栗三盃酒，分我天香一味羹。", "大抵有施須有報，木桃瓊玖愧詩評。"]'),
('d6a733ce-e849-401b-8a8d-5d0b2f423378','紙帳','華岳','宋','宋诗','song-poetry','','[]','主人冰雪灑胸襟，買宿銀城不計緡。',64,'全唐诗/poet.song.187000.json','["主人冰雪灑胸襟，買宿銀城不計緡。", "春草有詩皆白雪，秋毫無夢到紅塵。", "月娥好作雲間侶，風伯不寒冰下人。", "更喜五更窗外月，梅梢分得一枝春。"]'),
('7bcca783-59ad-4119-867a-740423e352c2','兵','華岳','宋','宋诗','song-poetry','','[]','兵貴先人斯奪人，莫教間諜漏真情。',64,'全唐诗/poet.song.187000.json','["兵貴先人斯奪人，莫教間諜漏真情。", "漢因有備吳終退，秦爲無人楚始爭。", "卦向爻中分損益，棋於局上定輸贏。", "不知都督三邊者，還肯江湖問一聲。"]'),
('a96313a4-e577-4dab-8b0e-c5ab091a1d3a','自訟','華岳','宋','宋诗','song-poetry','','[]','我生素不事詼諧，檐板方頭喚不回。',64,'全唐诗/poet.song.187000.json','["我生素不事詼諧，檐板方頭喚不回。", "遇事豈容無正論，濟時未必有長材。", "頭雖五鼎不辭劍，口恐三緘合用枚。", "不是生平太剛介，有如蹤跡尚塵埃。"]'),
('1b81d95d-9207-4277-ab0e-a013af8e2891','紀時','華岳','宋','宋诗','song-poetry','','[]','古今多少好英雄，未必奸邪未必忠。',64,'全唐诗/poet.song.187000.json','["古今多少好英雄，未必奸邪未必忠。", "上黨鼎膏流地白，長平坑血濺天紅。", "三邊傳檄兵雖息，二榷開場貨未通。", "更願年豐富金帛，飽裝駝駕爲和戎。"]'),
('c8252a7d-54fb-4bb3-89e7-5b87e3f8b8ba','重九','華岳','宋','宋诗','song-poetry','','[]','破帽無情不受吹，滿頭霜雪已如絲。',64,'全唐诗/poet.song.187000.json','["破帽無情不受吹，滿頭霜雪已如絲。", "菊花笑我三秋客，風物撩人九日詩。", "三楚膏腴已煨燼，二江皮肉更瘡痍。", "子卿三月無音信，鴻鴈南來何所之。"]'),
('a01e27d2-1470-434a-aa95-75364754326e','禱梅山','華岳','宋','宋诗','song-poetry','','[]','許我登龍尚未還，作詩更爲謁梅山。',64,'全唐诗/poet.song.187000.json','["許我登龍尚未還，作詩更爲謁梅山。", "如何威惠推千載，猶使英雄困八蠻。", "神不提身歸虎帳，鬼須擘口動龍顔。", "聰明儻爲扶宗社，願借風雷頃刻間。"]'),
('01a74344-7664-4965-bfe7-caa6b985503d','寄西山','華岳','宋','宋诗','song-poetry','','[]','姓名久不到西山，覓便無風鼻謾酸。',64,'全唐诗/poet.song.187000.json','["姓名久不到西山，覓便無風鼻謾酸。", "天塹有花春堰急，地爐無火夜堂寒。", "青燈昔記對牀卧，白髮今羞把鏡看。", "見說北歸常有鴈，一書無惜報平安。"]'),
('f284a371-ad10-479d-8b77-b3ba5d86b2c5','再禱梅山','華岳','宋','宋诗','song-poetry','','[]','梅山昔扣五通仙，曾許英雄第一籤。',64,'全唐诗/poet.song.187000.json','["梅山昔扣五通仙，曾許英雄第一籤。", "恰遇塵埃當擾擾，如何泥濘尚淹淹。", "若非推入高宗夢，須是遥分太史占。", "他日崧高詠申甫，一香先爲大王拈。"]'),
('6ad63192-973b-426f-b903-3bf02ed93c10','怒題','華岳','宋','宋诗','song-poetry','','[]','壯氣橫秋面渥丹，男兒未遇指休彈。',64,'全唐诗/poet.song.187000.json','["壯氣橫秋面渥丹，男兒未遇指休彈。", "賣漿豈料周分國，盜粟焉知漢築壇。", "脛脡未甘纏吏鞅，髑髏不信誤儒冠。", "夜深踢起床頭婢，和淚挑燈把劍看。"]'),
('255ec49a-8b3a-48a5-a6d1-7fffb0e7087c','寄范茂卿','華岳','宋','宋诗','song-poetry','','[]','社風吹迸雨前枝，正是施工北苑時。',64,'全唐诗/poet.song.187000.json','["社風吹迸雨前枝，正是施工北苑時。", "小胯未封纔入盝，短鎗初拆半含旗。", "一盆臘雪分龍井，萬杵春雷入鳳池。", "見說貢餘山似積，小煎還肯換新詩。"]'),
('4f35e7c9-9af6-43d5-9c3a-61dee0d08126','題溪莊','華岳','宋','宋诗','song-poetry','','[]','山擁青螺出粉牆，水環銀带插溪莊。',64,'全唐诗/poet.song.187000.json','["山擁青螺出粉牆，水環銀带插溪莊。", "一百五日雨翻浴，三十六宮人鬭粧。", "蝶翅拍花催舞袖，鳳毛翻錦入詩囊。", "新歡舊恨知多少，且對東風醉幾場。"]'),
('a678f3ea-ed07-47b2-a1b6-2f216b718681','奇見','華岳','宋','宋诗','song-poetry','','[]','紅牙催拍燕飛忙，一片行雲遶畫堂。',64,'全唐诗/poet.song.187000.json','["紅牙催拍燕飛忙，一片行雲遶畫堂。", "眉黛蹙成游子恨，臉紅燒斷故人腸。", "榆錢不買千金笑，柳带何須百寶粧。", "舞罷隔簾偷送目，不知誰是楚襄王。"]'),
('2c781269-eab8-46ec-9975-0942a0b13d49','思故人','華岳','宋','宋诗','song-poetry','','[]','太乙年來落冀并，幾多豪傑未成名。',64,'全唐诗/poet.song.187000.json','["太乙年來落冀并，幾多豪傑未成名。", "堯天日月計和玉，胡地山川知耀卿。", "盧六驅風能破屋，陳三平水可傾城。", "年來幕府勤延攬，何事諸兄未有聲。"]'),
('2c017bc2-1755-496a-bf20-8be42ff9b073','呈古洲老人','華岳','宋','宋诗','song-poetry','','[]','衛霍勳名李杜才，纔過四十也心灰。',64,'全唐诗/poet.song.187000.json','["衛霍勳名李杜才，纔過四十也心灰。", "俗塵趁少便披拂，詩料空多難剪裁。", "時事謾提眉便皺，家懷未說眼先開。", "朱簾更倩梅香掛，要放銀蟾入座來。"]'),
('ea8661b1-ce0b-4f23-886c-a8199ab3f75b','訓小童','華岳','宋','宋诗','song-poetry','','[]','飯罷令人喚小童，敢煩捉耳爲開蒙。',64,'全唐诗/poet.song.187000.json','["飯罷令人喚小童，敢煩捉耳爲開蒙。", "芎茶不用焦湯點，紙被還將艷火烘。", "醉欲伴眠當倩月，熱求揮汗合邀風。", "它時我建青油幕，廉汝封侯學衛公。"]'),
('d66cd245-9deb-464f-bc71-afe00e2386ab','郊飲','華岳','宋','宋诗','song-poetry','','[]','茅舍松棚隔小橋，碧帘斜掛竹籬腰。',64,'全唐诗/poet.song.187000.json','["茅舍松棚隔小橋，碧帘斜掛竹籬腰。", "豬頭煮去和皮擘，牛肉秤來带骨燒。", "村酒不圖邀客醉，野花復喜向人嬌。", "歸舟不用撐明月，只倩西風借晚潮。"]'),
('117f2248-f864-4d0c-926e-0dc0ac6be6a0','西爽','華岳','宋','宋诗','song-poetry','','[]','客子東南不著家，主人北里恣豪奢。',64,'全唐诗/poet.song.187000.json','["客子東南不著家，主人北里恣豪奢。", "夜深常倩月移竹，春老不煩風掃花。", "暮雨送凉歸枕簟，夕陽留客賦煙霞。", "何時執手闌干外，同把功名誓鏌鋣。"]'),
('960a81d8-854a-45f3-ae00-5897a7016cc4','斗齋','華岳','宋','宋诗','song-poetry','','[]','八方無處著瞿曇，百合中間寄一龕。',64,'全唐诗/poet.song.187000.json','["八方無處著瞿曇，百合中間寄一龕。", "滿挹酒漿供里北，平量風月借和南。", "腰如可折豈徒五，涎若果流何待三。", "更喜小窗能就拱，夜寒江靜著山函。"]'),
('28fcc5e8-4543-4d7b-8364-9f69989dc0c1','呈楚南僧','華岳','宋','宋诗','song-poetry','','[]','剛腸未肯報平安，擬把功名一擔擔。',64,'全唐诗/poet.song.187000.json','["剛腸未肯報平安，擬把功名一擔擔。", "方向杏壇逃敗北，却于蓮社得和南。", "香同世事炎還冷，茶類人情苦始甘。", "大抵久長同佛法，此心何處不瞿曇。"]'),
('73226032-806c-412a-af13-b021c0f37523','山居','華岳','宋','宋诗','song-poetry','','[]','布作寬袍竹作冠，蕭然萬慮不相關。',64,'全唐诗/poet.song.187000.json','["布作寬袍竹作冠，蕭然萬慮不相關。", "數聲橫笛煙霄外，一箇閒人天地間。", "若遇急流須勇退，從教倦鳥不知還。", "百年富貴君休羨，得似浮生半日閒。"]'),
('4e47e40a-d167-4638-8e73-84bc41198cf4','吳伯敘','華岳','宋','宋诗','song-poetry','','[]','太平官府不停囚，求劍烏衣欲刻舟。',64,'全唐诗/poet.song.187000.json','["太平官府不停囚，求劍烏衣欲刻舟。", "私筴是鷄難做鶴，公庭得馬便成牛。", "不疑若受千金謗，膠鬲當貽萬世羞。", "見說明公在蓮幕，不知能鑑此冤不。"]'),
('4119b091-dbbf-42af-8168-345eec3f9826','讀史','華岳','宋','宋诗','song-poetry','','[]','史筆如衡須正持，莫教浮誕出無稽。',64,'全唐诗/poet.song.187000.json','["史筆如衡須正持，莫教浮誕出無稽。", "已成帝業從烹父，未將王師休殺妻。", "秦逸號眠爲抱虎，劉狂名舞作聞鷄。", "麟經削後無全筆，磨玷吾當問白圭。"]'),
('5cab7715-2ef6-46dd-af06-6975cac00b60','建安暮秋','華岳','宋','宋诗','song-poetry','','[]','斜陽望斷水平橋，古柳蕭疎己半彫。',64,'全唐诗/poet.song.187000.json','["斜陽望斷水平橋，古柳蕭疎己半彫。", "魚躍浪花翻水面，鴈拖煙練束林腰。", "花時無鏹能追驥，月夜有詩堪續貂。", "回首故鄉多少恨，亂山無數路迢迢。"]'),
('e439bc18-c45f-4cc7-80f9-25ba4f568ee6','三衢道中','華岳','宋','宋诗','song-poetry','','[]','西風吹夢落青帘，濁酒三盃路二千。',64,'全唐诗/poet.song.187000.json','["西風吹夢落青帘，濁酒三盃路二千。", "別岸舟行秋色裏，故人家在夕陽邊。", "囊中有藥難醫國，竿上無鈎可釣賢。", "見說近來書籍貴，監取唐漢莫論錢。"]'),
('08b9be70-4eeb-41eb-9630-3ce09782b39b','秋望有懷','華岳','宋','宋诗','song-poetry','','[]','片雲如雨卷西風，綽盡遮闌眼力雄。',64,'全唐诗/poet.song.187000.json','["片雲如雨卷西風，綽盡遮闌眼力雄。", "遠水半連晴漢碧，暮霞全借夕陽紅。", "姓名未得聯諸子，鬢髮皤然已一翁。", "欲識翠微詩外意，豈徒憂國願年豐。"]'),
('916b5e11-94c3-462b-951d-143c7e899772','送李子方','華岳','宋','宋诗','song-poetry','','[]','亂雲推月上層樓，樓上朱簾不下鈎。',64,'全唐诗/poet.song.187000.json','["亂雲推月上層樓，樓上朱簾不下鈎。", "雞翅拍開朱戶鎖，鴈聲喚上木蘭舟。", "黄花撚酒留人醉，紅葉題詩倩水流。", "李廣不侯人不笑，笑他人作爛羊頭。"]'),
('b38e18ee-05e6-43ae-8933-7b720b12e8ee','寄兩庠同舍','華岳','宋','宋诗','song-poetry','','[]','昔年槌鼓扣天閽，遠謫南州七度春。',64,'全唐诗/poet.song.187000.json','["昔年槌鼓扣天閽，遠謫南州七度春。", "大享有恩來北闕，小囚無賂脫東閩。", "烏衣座滿民流血，畫燭簾深案積塵。", "見說九重宵旰慮，長沙猶有少年人。"]'),
('1d19284a-0449-4944-8396-2e3261526d89','呈沿漕宰','華岳','宋','宋诗','song-poetry','','[]','長亭不作馬蹄迂，一葉孤蓬入帝都。',64,'全唐诗/poet.song.187000.json','["長亭不作馬蹄迂，一葉孤蓬入帝都。", "星布關津皆自放，雷封纂節獨相拘。", "可憐罔市千般有，誰信虛舟一物無。", "爲祝琴堂早催發，片帆連夜過姑蘇。"]'),
('700fb80d-fee4-48a2-8a71-fe6265ff9d0a','九日','華岳','宋','宋诗','song-poetry','','[]','禾落西風黄葉飛，子卿無信鴈來遲。',64,'全唐诗/poet.song.187000.json','["禾落西風黄葉飛，子卿無信鴈來遲。", "凄凉自笑劉思父，慷慨難追杜牧之。", "歸興十分濃似酒，愁腸一縷亂如絲。", "憑君細把茱萸問，此會明年健有誰。"]'),
('a68f94ce-a4ae-4ae7-986e-5d4598facad4','戲呈趙可父','華岳','宋','宋诗','song-poetry','','[]','少年場屋擅詞鋒，審讞無私只奉公。',64,'全唐诗/poet.song.187000.json','["少年場屋擅詞鋒，審讞無私只奉公。", "夜月蘭宮無宿曜，秋霜蓮幕有春風。", "明堂難毀周公制，鄉校猶存子産功。", "文德自來能服遠，更煩劉向爲和戎。"]'),
('6d248bac-0eb8-4f37-8a2e-079fd8a1dfa7','挽吳夫人','華岳','宋','宋诗','song-poetry','','[]','鸞驂不是厭塵凡，王母瑶池促駕還。',64,'全唐诗/poet.song.187000.json','["鸞驂不是厭塵凡，王母瑶池促駕還。", "家在兩三千里外，人生一十六年間。", "好隨神女游舒水，難伴文君歸蜀山。", "試向仙源問消息，桃花零落水潺潺。"]'),
('2ce76c27-9057-44ce-8ff5-2b3dc3f7fdc0','巖桂落英','華岳','宋','宋诗','song-poetry','','[]','凈掃庭階襯落英，西風吹恨入蓬瀛。',64,'全唐诗/poet.song.187000.json','["凈掃庭階襯落英，西風吹恨入蓬瀛。", "人從紫麝囊中過，馬踏黄金屑上行。", "眠醉不須鋪錦褥，研香還解作珠纓。", "宮娥未許填溝壑，收拾流酥浸玉罌。"]'),
('2bf5b5a6-dbfe-4530-9943-c4d090a23cd2','牢城述懷','華岳','宋','宋诗','song-poetry','','[]','江外音書久不來，重城昏鼓又相催。',64,'全唐诗/poet.song.187000.json','["江外音書久不來，重城昏鼓又相催。", "眼前螢掣簷前電，耳底蚊轟屋底雷。", "乃事類棋方入局，此心如火已成灰。", "憑君試問吳元白，老寇東川回未回。"]'),
('bbcec567-d806-4971-9dcd-4b48bc109183','重午','華岳','宋','宋诗','song-poetry','','[]','虎眼龍鬚午未乾，楚臣遺淚尚潸潸。',64,'全唐诗/poet.song.187000.json','["虎眼龍鬚午未乾，楚臣遺淚尚潸潸。", "梅天有雨金丸重，麥地無風翠浪閒。", "蒲解梟風豈梟賊，符能驅祟不驅姦。", "一樽菖酒呼天問，何事男兒鬢漸斑。"]'),
('62e3fd4a-ddc6-465a-aef6-970383b24259','有觸述懷','華岳','宋','宋诗','song-poetry','','[]','英雄還要識英雄，不識英雄總是空。',64,'全唐诗/poet.song.187000.json','["英雄還要識英雄，不識英雄總是空。", "投鼠在人當忌器，見鴻非我獨彎弓。", "情從忠佞分輕重，事戒恩威戾始終。", "說與翠微休截截，三緘從此更須工。"]'),
('7717da12-1db5-4a06-b16b-6016b2bb1e18','巖桂','華岳','宋','宋诗','song-poetry','','[]','西風吹老碧蓮房，萬壑風流拆麝囊。',64,'全唐诗/poet.song.187000.json','["西風吹老碧蓮房，萬壑風流拆麝囊。", "謾與籬花爭曉色，肯教盆蕙壓秋芳。", "月中有女曾分種，世上無花敢鬭香。", "要識仙根迥然別，一枝開傍郄家牆。"]'),
('76169131-778b-4439-a738-d86482080350','偶成','華岳','宋','宋诗','song-poetry','','[]','一別京華近十年，此心無日不悠然。',64,'全唐诗/poet.song.187000.json','["一別京華近十年，此心無日不悠然。", "嗅梅得句天然巧，把酒開懷地自偏。", "鐵硯不須兵十萬，銅盤何用客三千。", "功名自有風雲會，不遇風雲毋自煎。"]'),
('4382e739-e6b2-4d6e-9c22-d1e20805af39','寄王士貴','華岳','宋','宋诗','song-poetry','','[]','畫橋相送百花春，轉眼孤鴻逐斷雲。',64,'全唐诗/poet.song.187000.json','["畫橋相送百花春，轉眼孤鴻逐斷雲。", "別後有誰能顧我，客中無日不思君。", "風前花影嘗興念，月下桐聲久不聞。", "見說近來多好况，一書無惜寄云云。"]'),
('e536f3bc-0aad-4b74-a2d7-dcd7c7ffd3bb','發書與幼弟及坦齋','華岳','宋','宋诗','song-poetry','','[]','風煙世事不堪聽，勿謂封侯勝白丁。',64,'全唐诗/poet.song.187000.json','["風煙世事不堪聽，勿謂封侯勝白丁。", "老眼隔年新舊曆，歸心連夜短長亭。", "一聲蜀鳥驚胡蝶，十幅蠻花寄鶺鴒。", "更向坦齋夫子道，近來雙鬢已星星。"]'),
('82d12c26-faf4-4dba-8e00-01150608cf52','寄王清之','華岳','宋','宋诗','song-poetry','','[]','封書漢上寄清之，却恐清之漢上歸。',64,'全唐诗/poet.song.187000.json','["封書漢上寄清之，却恐清之漢上歸。", "千里謾懷明月共，寸心常伴白雲飛。", "湘妃有淚能斑竹，周士無心戀采薇。", "安得一緘飛海嶠，與兄聯轡上淮淝。"]'),
('fef4cca8-9184-4678-9749-9f2bc03f89e5','感應王祠','華岳','宋','宋诗','song-poetry','','[]','如神正直護縲囚，當代公卿總合羞。',64,'全唐诗/poet.song.187000.json','["如神正直護縲囚，當代公卿總合羞。", "疏紙未燒謀已遂，爐香方爇病先瘳。", "乞靈屢假三更寐，釋縛常封萬戶侯。", "待得有勳書竹帛，一封當爲薦宸旒。"]'),
('02ef4eb7-90f7-4838-802b-d12bdb373bc7','寄張舍人','華岳','宋','宋诗','song-poetry','','[]','萬冤無計徹天衢，三尺金科謾卷舒。',64,'全唐诗/poet.song.187000.json','["萬冤無計徹天衢，三尺金科謾卷舒。", "公不戴星馳駟馬，民將指日就枯魚。", "黄堂宴妓不加意，丹陛慮囚空有書。", "見說羣烏廣瞻聽，如何公論尚躊躇。"]'),
('cddc84a8-34c7-4ee2-89a1-ddf060c03409','禱富沙','華岳','宋','宋诗','song-poetry','','[]','十年蹤跡淖泥沙，爲炷靈香禱富沙。',64,'全唐诗/poet.song.187000.json','["十年蹤跡淖泥沙，爲炷靈香禱富沙。", "萬里無由詣霜闕，一書聊欲爲星槎。", "解驂許我來齊晏，釋縛從君問左車。", "他日橫飛上麟閣，行祠當爲建京華。"]'),
('5dd1093f-a8f9-4076-95ae-daa15b7b4ac8','謝劉判院','華岳','宋','宋诗','song-poetry','','[]','細軸濃雲寄矮齋，蒲團和氣忽驚回。',64,'全唐诗/poet.song.187000.json','["細軸濃雲寄矮齋，蒲團和氣忽驚回。", "一牀浪捲芙蓉皺，十幅香重錦繡開。", "不怕夜寒侵斗帳，却愁春夢到陽臺。", "感恩未作瓊瑶報，先把新詩寄小梅。"]'),
('01a962eb-f640-425b-aa70-61f353117514','寄苕溪故人','華岳','宋','宋诗','song-poetry','','[]','昔年分袂霅川東，繫馬花梢撲亂紅。',64,'全唐诗/poet.song.187000.json','["昔年分袂霅川東，繫馬花梢撲亂紅。", "解珮送行情怏怏，舉盃言別恨匆匆。", "中人以上誰知我，北斗以南惟有公。", "此去東閩有良便，一書無惜慰羈窮。"]'),
('82123633-7c07-49ca-91fd-39a0b23f4162','不禱','華岳','宋','宋诗','song-poetry','','[]','不炷靈香不誦經，兆盃籤榜總欺人。',64,'全唐诗/poet.song.187000.json','["不炷靈香不誦經，兆盃籤榜總欺人。", "窮通只合從天地，禍福何須問鬼神。", "命到死時生莫倖，事當直處曲還伸。", "從今若問開先事，桃李無言二月春。"]'),
('9e02e5e4-4137-4b90-a9ba-82a673a2bcfd','送提舉陳工部','華岳','宋','宋诗','song-poetry','','[]','溪風拂拂卷征衣，溪上攀轅恨馬遲。',64,'全唐诗/poet.song.187000.json','["溪風拂拂卷征衣，溪上攀轅恨馬遲。", "蝗不入閩今已矣，碑無留峴古求之。", "泉知送客聲猶咽，燭昧留人淚謾垂。", "願速長沙還賈誼，爲公江上斬鯨鯢。"]'),
('41902f9c-722a-49b5-b95f-0b889de9183b','悉事','華岳','宋','宋诗','song-poetry','','[]','欲歸未去兩紛拏，何事回天力未加。',64,'全唐诗/poet.song.187000.json','["欲歸未去兩紛拏，何事回天力未加。", "九牧誰爲十羊主，百冠當念一人髽。", "肘邊有石心雖切，腰下無錢手謾叉。", "千萬有人逢伯樂，爲言龍種尚盤車。"]'),
('c7254bdc-3de1-4544-b9c3-bb997bd346f0','呈陳信父','華岳','宋','宋诗','song-poetry','','[]','老來百計總無成，當路時官懶問名。',64,'全唐诗/poet.song.187000.json','["老來百計總無成，當路時官懶問名。", "國事只將心事比，今人難作古人評。", "蒼頭笑我樽無佐，白髮欺人鑷又生。", "惟有建溪知客意，過灘時作不平鳴。"]'),
('3fc1aaae-dfe0-487d-a53a-1f65e44bfb05','寄江子崗','華岳','宋','宋诗','song-poetry','','[]','秋夜封書上子崗，別來化日又舒長。',64,'全唐诗/poet.song.187000.json','["秋夜封書上子崗，別來化日又舒長。", "只知電燭兩經月，不覺星毛半欲霜。", "竹葉照人凝盞滑，梅花撩客透籬香。", "知他詩債曾償未，料得尋春日日忙。"]'),
('ee35de1f-57ee-42f0-aa38-77a12a57a0a9','書太乙編年卷尾','華岳','宋','宋诗','song-poetry','','[]','年來太乙犯咸池，三式編年事可疑。',64,'全唐诗/poet.song.187000.json','["年來太乙犯咸池，三式編年事可疑。", "西北膏腴從脯腊，東南皮肉恐瘡痍。", "堯天日月期無已，胡地煙雲歲有之。", "更向江湖問同志，中原何日是歸期。"]'),
('c37b035a-fb11-4b4f-887e-e8f3b2a7ae5a','怒成','華岳','宋','宋诗','song-poetry','','[]','舌端豪氣吐長虹，四海一身無處容。',64,'全唐诗/poet.song.187000.json','["舌端豪氣吐長虹，四海一身無處容。", "不向北山求刺虎，便從南海學屠龍。", "鼎須劉闢方成器，劍到魏齊那是鋒。", "欲抱不平朝玉帝，夢魂飛上祝融峰。"]'),
('dfdd8ea0-52aa-444c-a260-5bda1c86a81d','楮衾','華岳','宋','宋诗','song-poetry','','[]','霜風剪水作冰花，織出吳綾不用梭。',64,'全唐诗/poet.song.187000.json','["霜風剪水作冰花，織出吳綾不用梭。", "十幅曉雲藏處士，一牀秋水浸嫦娥。", "直疑天上無青女，却信人間有睡魔。", "更向屏山畫梅竹，紅塵還有此風麽。"]'),
('e32ab238-733d-4774-b0cd-ccd106cfb832','勉趙法曹','華岳','宋','宋诗','song-poetry','','[]','銀潢河海浸崆峒，君獨軒昂萬派中。',64,'全唐诗/poet.song.187000.json','["銀潢河海浸崆峒，君獨軒昂萬派中。", "北鄙虎牢今子産，東山狼跋古周公。", "固知魯衛封同姓，合向燕秦策異功。", "我欲誓江同擊楫，中流不惜伴英雄。"]'),
('d18706db-cee8-4299-aae2-a1bf34bf2e76','獄中責廷尉  其一','華岳','宋','宋诗','song-poetry','','[]','重門有路透泉關，便合摳衣問比干。',64,'全唐诗/poet.song.187000.json','["重門有路透泉關，便合摳衣問比干。", "愧我直言難媚竈，從渠怒髮自衝冠。", "烏臺有月身何及，犴獄無天淚謾彈。", "自恨不逢包孝肅，此身那許報平安。"]'),
('55d676a8-6304-44a9-a62d-9178ffe1eff4','獄中責廷尉  其二','華岳','宋','宋诗','song-poetry','','[]','吾巾不是不冠儒，曾被儒冠幾誤予。',64,'全唐诗/poet.song.187000.json','["吾巾不是不冠儒，曾被儒冠幾誤予。", "鐵硯不磨天地軸，毛錐難復帝王居。", "當傳衛霍無傳秘，却著韓曹不著書。", "堪笑蒼生無眼力，不知豪傑在樵漁。"]'),
('d789024b-adee-45d1-897b-244724b614ae','挽戚虛中','華岳','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','夢裏匡廬興未闌，轉頭世事已辛酸。',64,'全唐诗/poet.song.187000.json','["夢裏匡廬興未闌，轉頭世事已辛酸。", "肥家有術疑非藥，漉酒從人笑不冠。", "鴈序向人羣已失，鳳雛過眼影何單。", "不堪回首原頭路，一塢松楸生暮寒。"]'),
('a1bad4a5-e65f-474a-bed7-f4ea5fae5ba6','寄盧進士','華岳','宋','宋诗','song-poetry','','[]','丈夫策定在吳鈎，浪把橋門作勝遊。',64,'全唐诗/poet.song.187000.json','["丈夫策定在吳鈎，浪把橋門作勝遊。", "綵筆誤人隨驥尾，錦標還我占鼇頭。", "關山夢寐三千里，竹帛功名四十秋。", "安得九重容借箸，盡將軍國爲前籌。"]'),
('10ce2ff8-8571-4837-bb8e-1591b4c2016f','九日言懷','華岳','宋','宋诗','song-poetry','','[]','凄凄天氣間炎凉，破帽翻風客鬭狂。',64,'全唐诗/poet.song.187000.json','["凄凄天氣間炎凉，破帽翻風客鬭狂。", "酒味暗消黄蘂辣，鴈聲喚得菊花香。", "三京昔擬恢同軌，九日今猶客異鄉。", "更仗阿誰上沙漠，爲予申意郭汾陽。"]'),
('cb5899d0-fd56-4894-acb1-24d75bbf3b64','呈鄱陽趙及甫','華岳','宋','宋诗','song-poetry','','[]','不學炎凉不自謀，動和權勢作仇讐。',64,'全唐诗/poet.song.187000.json','["不學炎凉不自謀，動和權勢作仇讐。", "筆鋒带怒摇山岳，劍氣銜冤射斗牛。", "龍虎榜中當擢第，麒麟閣上合封侯。", "功名未入男兒手，誰肯甘爲郡督郵。"]'),
('3fec07e8-c0b0-4a2b-b991-127afba9a05c','九日溪樓遠望','華岳','宋','宋诗','song-poetry','','[]','西風寥落做重陽，人在東南水一方。',64,'全唐诗/poet.song.187000.json','["西風寥落做重陽，人在東南水一方。", "地僻阻它鴻鴈信，天寒撩我菊萸觴。", "江澄素練魚翻赤，葉剪紅綃蟹結黄。", "不是倚闌迷望眼，欲憑歸鴈問蘇郎。"]'),
('a27b638a-43ae-4153-9e4c-b4d0f99abda3','訴董寺丞','華岳','宋','宋诗','song-poetry','','[]','神首羅睺欲蝕天，彎弓直造玉皇前。',64,'全唐诗/poet.song.188000.json','["神首羅睺欲蝕天，彎弓直造玉皇前。", "九重不忍誅林甫，一札翻令囿馬遷。", "投鼠固知當忌器，得魚誰敢便忘筌。", "吾今一死初無憾，願把孤忠托孟堅。"]'),
('9f1444e3-b39a-4c31-863b-a0d89e101cfc','寄小王徐子晉','華岳','宋','宋诗','song-poetry','','[]','十載長沙路二千，歸心日夜在長安。',64,'全唐诗/poet.song.188000.json','["十載長沙路二千，歸心日夜在長安。", "居家有譽眉空白，戀闕無謀心謾丹。", "獲鴈不聞蘇子信，沐猴徒笑楚人冠。", "馬蹄恐有唐城便，爲把功名問二潘。"]'),
('70cfe38a-6149-418c-bc64-d0f9a0d8ece6','獄中作','華岳','宋','宋诗','song-poetry','','[]','壯士剛腸不受冤，髑髏可斷志難干。',64,'全唐诗/poet.song.188000.json','["壯士剛腸不受冤，髑髏可斷志難干。", "越仇未報薪當卧，漢賊猶存鋏謾彈。", "情款不從囚口責，炙漿難塞吏腸寬。", "何當盡瀝姦邪血，染作衣裳看孟安。"]'),
('54436859-f3e2-4d99-92ee-b449e8a3fc1d','池亭即事','華岳','宋','宋诗','song-poetry','','[]','春風恰恰破桃李，池館無人一徑深。',64,'全唐诗/poet.song.188000.json','["春風恰恰破桃李，池館無人一徑深。", "鷗刷斷翎翻水面，蝶拋殘粉出花心。", "詩懷攪我丹心破，節物催人白髮侵。", "流水伯牙今已矣，世間那復有知音。"]'),
('e9ec8684-872c-4bbd-9121-e746cb0e7485','南劍水閣','華岳','宋','宋诗','song-poetry','','[]','欲向津頭問鏌鋣，一潭秋水漫煙霞。',64,'全唐诗/poet.song.188000.json','["欲向津頭問鏌鋣，一潭秋水漫煙霞。", "畫屏對客景藏景，芳樹壓溪花照花。", "有策廷爭慚賈誼，無功廟食笑張華。", "夜深霹靂轟雙劍，驚起延平十萬家。"]'),
('13fc7871-fbac-414e-b1de-2735197cbac1','丹青閣','華岳','宋','宋诗','song-poetry','','[]','閣上闌干紫翠環，閣中身世異塵寰。',64,'全唐诗/poet.song.188000.json','["閣上闌干紫翠環，閣中身世異塵寰。", "長虹吸月印秋水，孤鶩伴霞量晚山。", "萬里風煙屏帳裏，一時人物畫圖間。", "凌烟須是男兒事，却恐功名未放閒。"]'),
('12846dd7-a6df-43da-b2a5-c301afdc9839','折桂園友人宴','華岳','宋','宋诗','song-poetry','','[]','牆頭羅綺碧雲濃，牆外鞦韆電掣空。',64,'全唐诗/poet.song.188000.json','["牆頭羅綺碧雲濃，牆外鞦韆電掣空。", "蝴蝶拍開花面粉，鷓鴣吹落杏腮紅。", "翠裀不卷珠簾月，蠟燭還摇錦袖風。", "醉眼不知塵世有，直疑身在廣寒宮。"]'),
('3a6f1935-e9c2-47d2-a303-67cc2ea2dc17','夜步水西','華岳','宋','宋诗','song-poetry','','[]','半趿芒鞋過水西，樓臺燈火未多時。',64,'全唐诗/poet.song.188000.json','["半趿芒鞋過水西，樓臺燈火未多時。", "山羞見我頭頭轉，月怕拋人步步隨。", "楓葉卷愁秋去早，溪聲翻笑夜歸遲。", "柴門只解關煙雨，不隔離愁些子兒。"]'),
('b014fc74-50d7-457a-830d-fb38ef03545e','酒樓秋望','華岳','宋','宋诗','song-poetry','','[]','西風吹客上闌干，萬里無雲宇宙寬。',64,'全唐诗/poet.song.188000.json','["西風吹客上闌干，萬里無雲宇宙寬。", "秋水碧連天一色，暮霞紅映日三竿。", "花摇舞帽枝猶軟，酒入詩腸句不寒。", "古往今來恨多少，一時收拾付盃盤。"]'),
('f591ae1f-ec0d-4e93-87e8-05249b5793da','臨清閣','華岳','宋','宋诗','song-poetry','','[]','闌干古木瑣青葱，闌外簷花灼半空。',64,'全唐诗/poet.song.188000.json','["闌干古木瑣青葱，闌外簷花灼半空。", "萬里好山春黛碧，一溪流水暮霞紅。", "窗疎不礙東西月，帆過始知南北風。", "試問支郎一樽酒，好天良夜與誰同。"]'),
('bf9d3612-d717-418e-b556-b4820f068fb7','思故人','華岳','宋','宋诗','song-poetry','','[]','十載無人問益之，誰于欬唾覓珠璣。',64,'全唐诗/poet.song.188000.json','["十載無人問益之，誰于欬唾覓珠璣。", "兩三千里家何在，三十六峰人未歸。", "將謂抱薪能救燎，果然畫餠不充饑。", "東川恐遇連榮祖，一笑不須論是非。"]'),
('580263ea-d3a6-490a-9710-0cd02ba8e5aa','有激呈江聖與判院','華岳','宋','宋诗','song-poetry','','[]','不郊不國不吾廬，兀兀騰騰十載餘。',64,'全唐诗/poet.song.188000.json','["不郊不國不吾廬，兀兀騰騰十載餘。", "頸昔已逃三尺劍，腹今猶秘九疇書。", "齊牛難爇吳元濟，賈鵩何慚董仲舒。", "只合三緘且鉗口，一蓑歸去伴樵漁。"]'),
('8912cca8-fdd6-430d-9c2d-c89bc31962a1','與楞伽老瑛上人','華岳','宋','宋诗','song-poetry','','[]','勿謂年來世道艱，都緣彼此不相參。',64,'全唐诗/poet.song.188000.json','["勿謂年來世道艱，都緣彼此不相參。", "一生知己有千萬，十事從人無二三。", "紅杏無壇堪拱北，白蓮有社結和南。", "扁舟若有東歸便，斷竹枯松寄一擔。"]'),
('d8b450a3-9685-4b2a-80bc-57ecfdd456ae','呈王子蒙隠者','華岳','宋','宋诗','song-poetry','','[]','國士還須爲國憂，肯同兒女作身謀。',64,'全唐诗/poet.song.188000.json','["國士還須爲國憂，肯同兒女作身謀。", "存無補世亡無異，生不驚人死不休。", "秦鹿須還屠狗逐，楚猴猶爲爛羊羞。", "如今若論西都事，却與中唐風馬牛。"]'),
('a113db66-d98f-4b9b-9d66-1884c6108bd6','夜讀離騷','華岳','宋','宋诗','song-poetry','','[]','楮衾封冷白凝霜，展轉無眠夜未央。',64,'全唐诗/poet.song.188000.json','["楮衾封冷白凝霜，展轉無眠夜未央。", "風欲送愁先卷帳，雨嫌多夢故敲窗。", "自慚鼓瑟投齊好，謾接歌輿效楚狂。", "起把離騷讀幽悶，楚詞還似楚江長。"]'),
('4b5b5075-6c1a-4324-b1bf-37a3ee718db2','倪尚書生祠','華岳','宋','宋诗','song-poetry','','[]','聞說先生入建都，一年民樂吏清癯。',64,'全唐诗/poet.song.188000.json','["聞說先生入建都，一年民樂吏清癯。", "四廂夜月封朱戶，兩院春風鎖翠蕪。", "一旦有書追駟馬，萬冤無計徹羣烏。", "焚香再拜祝公壽，問有清朝賞罰無。"]'),
('600a627b-d268-491f-ad40-d179fd267d02','秋晚述懷呈薛子長','華岳','宋','宋诗','song-poetry','','[]','一罋香醪一曲琴，得相尋處且相尋。',64,'全唐诗/poet.song.188000.json','["一罋香醪一曲琴，得相尋處且相尋。", "盃寬却怪青山小，坐久不知黄葉深。", "當路星軺已鉗口，異鄉風物更關心。", "何時繫艇秋江上，醉卧蘆花雪滿襟。"]'),
('e2e475ef-af56-4815-9220-65515b5b1622','雙桂堂','華岳','宋','宋诗','song-poetry','','[]','月姊親移入慶門，廣寒今是並肩人。',64,'全唐诗/poet.song.188000.json','["月姊親移入慶門，廣寒今是並肩人。", "分他蟾窟雌雄種，作我螢窗南北隣。", "傲竇雖慳三樹玉，比詵翻剩一枝春。", "主人便好鞭黄鵠，斫取魁梢謝紫宸。"]'),
('bac81ae0-d677-4e2b-ba93-7ca10626d657','憶弟妹','華岳','宋','宋诗','song-poetry','','[]','別來三載客東南，始信人生聚首難。',64,'全唐诗/poet.song.188000.json','["別來三載客東南，始信人生聚首難。", "眼底不聞鴻鴈信，鼻頭常爲鶺鴒酸。", "問天不語語徒厲，驀地上心心類剜。", "安得春風吹馬首，卧聽行列報平安。"]'),
('baf4030d-efd8-4285-8e19-1d7a677e81f8','責逋  其一','華岳','宋','宋诗','song-poetry','','[]','索逋無術謁公門，豈謂公門反愴神。',64,'全唐诗/poet.song.188000.json','["索逋無術謁公門，豈謂公門反愴神。", "令尹幸酬三百索，癡兒猶戀一千緡。", "如今索手方知錯，自此甘心莫怨貧。", "不是恩波不旁洽，五窮無奈苦隨人。"]'),
('0b57c533-99bb-4e00-a94c-ab2dee0e6752','責逋  其二','華岳','宋','宋诗','song-poetry','','[]','刳腸植粟餧官牛，牛骨成塵粟未酬。',64,'全唐诗/poet.song.188000.json','["刳腸植粟餧官牛，牛骨成塵粟未酬。", "何事蓮參猶閣筆，反憐花縣若虛舟。", "季公素重千金諾，膠鬲當貽萬世羞。", "願效相如還趙璧，莫教顔色嘆牀頭。"]'),
('531b65cb-7f43-4d45-a1e8-ebfcaef1f8ed','送趙右秋  其一','華岳','宋','宋诗','song-poetry','','[]','梅花飛雪滿霜洲，洲上行人去莫留。',64,'全唐诗/poet.song.188000.json','["梅花飛雪滿霜洲，洲上行人去莫留。", "蠟炬結花催管籥，鴈聲喚客上蘭舟。", "莫嫌冰炭情難入，自是薰蕕味不侔。", "執節從教少知遇，勿于世路學沉浮。"]'),
('bddb2037-fd90-48bf-bb40-8d1cfc2513dd','送趙右秋  其二','華岳','宋','宋诗','song-poetry','','[]','閩藩齊指右參軍，玉骨清無半點塵。',64,'全唐诗/poet.song.188000.json','["閩藩齊指右參軍，玉骨清無半點塵。", "一味恤刑常召禍，十年游宦只憂貧。", "圜扉月照金波夜，寒谷花開玉樹春。", "客子與君雖素昧，一時聊記子張紳。"]'),
('1abf268e-4320-439a-950e-388c7a6cd2fd','牢城言懷','華岳','宋','宋诗','song-poetry','','[]','重城不隔世間塵，箇裏無花別有春。',64,'全唐诗/poet.song.188000.json','["重城不隔世間塵，箇裏無花別有春。", "冤鬼夜隨風雨泣，病囚時作犬羊呻。", "雷霆不霹欺君賊，彗孛偏凌爲國人。", "欲問老天天已老，料應無說爲敷陳。"]'),
('c4d50929-64b1-4bf9-8eb9-fd6aa785ce67','贈楞伽老瑛上人','華岳','宋','宋诗','song-poetry','','[]','無聊斷梗撥寒灰，門掩霜風客自推。',64,'全唐诗/poet.song.188000.json','["無聊斷梗撥寒灰，門掩霜風客自推。", "急下火壚叉手接，便將布袋解頭開。", "拂牀展卷呈詩稿，炙盞分茶當酒盃。", "別後逢人須問訊，楞伽曾倩寄書來。"]'),
('5103c1dd-d708-488f-8ad3-4c912ebad707','謝仵判院惠米','華岳','宋','宋诗','song-poetry','','[]','溝壑膏粱總自招，仲尼陳蔡亦囂囂。',64,'全唐诗/poet.song.188000.json','["溝壑膏粱總自招，仲尼陳蔡亦囂囂。", "不逢魯肅千囷指，空折淵明五斗腰。", "孤竹二饑知我意，蒼梧一飽爲君謠。", "從今隻手摩挲腹，却向顔門問一瓢。"]'),
('8e7ca06b-bf3c-4731-86e7-23584143ed24','除夜大雪丙寅除夜得春，瑞雪大作，時有襄淮之衄，因記夜半入蔡之事，使人振腕不寐。時在建三除夜矣','華岳','宋','宋诗','song-poetry','','[]','青帝明朝下玉京，先教滕六掩車塵。',64,'全唐诗/poet.song.188000.json','["青帝明朝下玉京，先教滕六掩車塵。", "梅花笑我三年臘，椒葉爭他一夜春。", "烏角觸簷鞭墮玉，馬蹄印路椀拋銀。", "何當夜縛吳元濟，去作中興社稷臣。"]'),
('e1f5a64a-8ef2-4f65-a82f-b7b579f7f78b','呈毛南仲','華岳','宋','宋诗','song-poetry','','[]','暮宿東溪一草堂，倦和衣屨卧胡牀。',64,'全唐诗/poet.song.188000.json','["暮宿東溪一草堂，倦和衣屨卧胡牀。", "夢隨鸞去遼天闊，夜到雞鳴剗地長。", "早起不須禽爲喚，多憂誰謂草能忘。", "清閒却愧毛南仲，醉卧西窗一枕凉。"]'),
('ae470329-663f-4944-8201-8326da348fab','除夜  其一','華岳','宋','宋诗','song-poetry','','[]','纔辱東皇造化工，便隨飛鵲報簾櫳。',64,'全唐诗/poet.song.188000.json','["纔辱東皇造化工，便隨飛鵲報簾櫳。", "人間狴犴知無所，天上蓬萊還有宮。", "酒色半澄春後綠，蠟花全折夜來紅。", "從今泰道能連茹，願駕蒼蟠躍震風。"]'),
('f9b8a227-fe51-47fb-9626-383cf1039d4c','除夜  其二','華岳','宋','宋诗','song-poetry','','[]','吳鈎不是怒鯨鯢，夜半劉琨屢舞雞。',64,'全唐诗/poet.song.188000.json','["吳鈎不是怒鯨鯢，夜半劉琨屢舞雞。", "十載載春游太學，二年年夜宿圜扉。", "楚盤未必資毛遂，周粟如何飽叔齊。", "塵世功名儻來爾，無言桃李自成蹊。"]'),
('359f2c4c-7543-4f30-9a22-eacd55a66893','呈富大卿','華岳','宋','宋诗','song-poetry','','[]','司農未曉報龍樓，昨夜中天貫索流。',64,'全唐诗/poet.song.188000.json','["司農未曉報龍樓，昨夜中天貫索流。", "石父不逢齊子相，馬遷空作漢家囚。", "銅壺滴碎短長夢，鈴索拽翻新舊愁。", "安得君王賜歸騎，一廛投老大江頭。"]'),
('858f04b1-9d57-40d8-a18f-229b35bb120a','雪中呈劉子沖','華岳','宋','宋诗','song-poetry','','[]','朔風卷水入天渠，剪作飛花散六虛。',64,'全唐诗/poet.song.188000.json','["朔風卷水入天渠，剪作飛花散六虛。", "竹本無聲緣葉密，梅因有影怕花疎。", "路從玉鑑上頭過，家在冰壺裏面居。", "欲作一詩撩謝女，不知爲况近何如。"]'),
('7511f76d-9a6e-416a-a33e-2b6c40b4ba43','雪中有戲','華岳','宋','宋诗','song-poetry','','[]','一夜風神揭海神，盡將純素掩丹青。',64,'全唐诗/poet.song.188000.json','["一夜風神揭海神，盡將純素掩丹青。", "四圍白壁成千嶂，萬里紅塵沒一星。", "搭岸柳條橫玉带，壓牆梅萼上銀屏。", "好將今日平淮策，說與當年李愬聽。"]'),
('c2e35a04-9964-4ab8-9d50-15b9dce5b8cb','憂世寄清溪友人','華岳','宋','宋诗','song-poetry','','[]','廟堂無計息干戈，國士銜冤未汨羅。',64,'全唐诗/poet.song.188000.json','["廟堂無計息干戈，國士銜冤未汨羅。", "尺五指天均日月，八千里地舊山河。", "人無遠慮心徒切，里有新喪巷不歌。", "况是十年芹泮客，倚闌尤覺淚滂沱。"]'),
('622f2f7e-25ee-4e3e-af01-578d509f0478','嘲曹掾友人','華岳','宋','宋诗','song-poetry','','[]','世態年來日日新，宦途澆薄更驚人。',64,'全唐诗/poet.song.188000.json','["世態年來日日新，宦途澆薄更驚人。", "闕期動徹連三政，選調無疑費百緡。", "是吏有囊盛短卷，非財無藥療長貧。", "參軍也勝陶彭澤，且糶官糧醉幾巡。"]'),
('39934ad1-7632-4b10-bf22-acd1dc1dab8a','囚中記貧','華岳','宋','宋诗','song-poetry','','[]','英雄不遇不憂貧，獄吏從教喚不應。',64,'全唐诗/poet.song.188000.json','["英雄不遇不憂貧，獄吏從教喚不應。", "煮飯只燒沽酒鑵，讀書權借守囚燈。", "堪嗟世事危如卵，無怪人情冷似冰。", "勿謂功名成倖致，志公終不是閒僧。"]'),
('ffcfcde8-a3fc-4e78-84b3-a229867b7b1e','送倪尚書歸霅川','華岳','宋','宋诗','song-poetry','','[]','筆麟圖鳳久無聲，何事權輿復見今。',64,'全唐诗/poet.song.188000.json','["筆麟圖鳳久無聲，何事權輿復見今。", "魯祭不因夫子肉，齊卿難奪孟軻心。", "我公去就何爲重，吾道興亡所繫深。", "安得斯文天未喪，載歌狼跋繼遺音。"]'),
('20ff8318-67ec-4e72-8a57-821201d21933','宣城道中','華岳','宋','宋诗','song-poetry','','[]','躍馬上宣城，千山翠欲顰。',48,'全唐诗/poet.song.188000.json','["躍馬上宣城，千山翠欲顰。", "蕙風輕卷舌，櫻雨細沾唇。", "柳絮難驅臘，榆錢不買春。", "何如澆一斗，爛醉石湖濱。"]'),
('5d4b3f43-9f2f-4348-b890-21b54ee193c7','當塗道中','華岳','宋','宋诗','song-poetry','','[]','春晴不慷慨，十日九清陰。',48,'全唐诗/poet.song.188000.json','["春晴不慷慨，十日九清陰。", "蝶宿花留粉，鶑眠柳借金。", "邊塵方障眼，漢壁尚關心。", "醒去愁無奈，盃行滿滿斟。"]'),
('d59e00c8-0c57-4174-9ed1-e71eb36f6f8a','壽昌道中','華岳','宋','宋诗','song-poetry','','[]','山斷疑無路，林開覺有村。',48,'全唐诗/poet.song.188000.json','["山斷疑無路，林開覺有村。", "饑牛戀茅壠，吠犬護柴門。", "悶去詩千首，愁來酒一尊。", "明朝南去路，懷抱與誰論。"]'),
('c34a3fa4-bd29-454e-95be-6c92e9dc316f','別王泰之','華岳','宋','宋诗','song-poetry','','[]','風神戀行客，吹柳纏簪纓。',48,'全唐诗/poet.song.188000.json','["風神戀行客，吹柳纏簪纓。", "傍水鳥多白，近山蟬更清。", "別腸雲閣淚，歸路月關情。", "告德無多日，清觴聊一傾。"]'),
('57e461f0-a4e3-4d26-89a7-3b381bb314b5','遊溪西寺','華岳','宋','宋诗','song-poetry','','[]','寺覺重遊好，僧期後會賒。',48,'全唐诗/poet.song.188000.json','["寺覺重遊好，僧期後會賒。", "青蟲彫病葉，白鳥篆平沙。", "水瘦石生齒，山寒梅未花。", "功名今有待，且謁惠公茶。"]'),
('28f47a14-aaf9-40b5-a862-2c27121d93b6','登樓晚望','華岳','宋','宋诗','song-poetry','','[]','疎雨洗空碧，晚晴人倚樓。',48,'全唐诗/poet.song.188000.json','["疎雨洗空碧，晚晴人倚樓。", "稻花千頃浪，楓葉一簾秋。", "遠岸明殘日，孤村認小舟。", "溪山如愛我，相見亦回頭。"]'),
('fe8fa83e-b4ad-4fc8-be45-d27ff993e528','安分呈李竹齋','華岳','宋','宋诗','song-poetry','','[]','風雨思君子，煙霞憶舊遊。',48,'全唐诗/poet.song.188000.json','["風雨思君子，煙霞憶舊遊。", "一區山水國，萬里帝王州。", "臘罋香浮玉，春旗雪滿甌。", "安貧隨處樂，此外復何求。"]'),
('2d01ff86-d900-41d3-9d9c-bcaffdc94d3e','拜茶','華岳','宋','宋诗','song-poetry','','[]','北苑春將半，星槎欲奏功。',48,'全唐诗/poet.song.188000.json','["北苑春將半，星槎欲奏功。", "杵鳴千臼雪，鎗卷一旗風。", "盝錦鸚毛翠，簽羅象眼紅。", "封成拜玄鶴，飛上紫微宮。"]'),
('e9b88ac2-7b33-4eab-bd6b-fb7858e062ae','邸食責庖者','華岳','宋','宋诗','song-poetry','','[]','陋邸已無味，庖人更不材。',48,'全唐诗/poet.song.188000.json','["陋邸已無味，庖人更不材。", "盦炊全做粥，燒鮝半成灰。", "添醋酸綿齒，研椒辣木腮。", "何時聳堂臠，香霧靄樽罍。"]'),
('9477e265-c0a2-4224-b49a-786ee0b9d310','秋意','華岳','宋','宋诗','song-poetry','','[]','木剪空山瘦，西風掃落黄。',48,'全唐诗/poet.song.188000.json','["木剪空山瘦，西風掃落黄。", "荷殘簪失蓋，菊老餠還香。", "詩盡情尤闊，愁多夜更長。", "悶懷無處著，隨鴈落瀟湘。"]'),
('19e1f13b-2837-4c8f-9482-892d01115b79','書堂遇雨','華岳','宋','宋诗','song-poetry','','[]','風疊雲成片，溝搓水作層。',48,'全唐诗/poet.song.188000.json','["風疊雲成片，溝搓水作層。", "濕書移案避，添硯就簷承。", "瓦擊聲疑雹，窗低暗欲燈。", "須臾西漏日，晴意慢騰騰。"]'),
('ab2c3cd7-84ff-4043-9fdb-852c589e012c','矮齋','華岳','宋','宋诗','song-poetry','','[]','屋老塵生索，椽低帳不縑。',48,'全唐诗/poet.song.188000.json','["屋老塵生索，椽低帳不縑。", "炙燈煙染棟，見客帽翻簷。", "織壁慳三尺，遮門斷半簾。", "吾身交九四，控制萬愁兼。"]'),
('03551d67-5076-4904-a684-6b60155c0944','容膝','華岳','宋','宋诗','song-poetry','','[]','具體功非遠，全軀恨已消。',48,'全唐诗/poet.song.188000.json','["具體功非遠，全軀恨已消。", "安禪須促膝，覓句敢成摇。", "悔不身齊足，時當事半腰。", "行人只蒲伏，何處得逍遥。"]'),
('86f12521-1d16-4f06-b0b3-95dda3b1f113','野飲呈祝山甫','華岳','宋','宋诗','song-poetry','','[]','野景何須買，山花不待培。',48,'全唐诗/poet.song.188000.json','["野景何須買，山花不待培。", "幕天分古木，裀地得蒼苔。", "酒上鶑調曲，肴空鵲墮梅。", "一壺隨所適，何處問蓬萊。"]'),
('16d2fe87-142a-4860-b832-38b31a30e360','題練省元壁','華岳','宋','宋诗','song-poetry','','[]','脚債嗟猶欠，心朋喜偶逢。',48,'全唐诗/poet.song.188000.json','["脚債嗟猶欠，心朋喜偶逢。", "溪聲含客怒，山色爲誰濃。", "古樹晴摇蓋，殘蟬晚带鐘。", "莫辭一樽酒，明日是吳儂。"]'),
('a40025a8-386b-469d-bbab-78fd88b3c3c8','南浦客邸','華岳','宋','宋诗','song-poetry','','[]','南浦半月雨，溪流暗沒沙。',48,'全唐诗/poet.song.188000.json','["南浦半月雨，溪流暗沒沙。", "斷橋虹散綺，拍岸雪飛花。", "孤館客無夢，短蓬人未家。", "何如擁紅日，照我上筠車。"]'),
('42bc8e20-31bb-4249-8ce4-ba875e137fa4','借景樓','華岳','宋','宋诗','song-poetry','','[]','朱箔鈎新月，平闌架落霞。',48,'全唐诗/poet.song.188000.json','["朱箔鈎新月，平闌架落霞。", "百錢呼酒炙，四壁聽笙笳。", "翠映誰家竹，香飄何處花。", "功名未歸我，且此寄生涯。"]'),
('58981b24-7782-47ba-83d9-451a729f01b3','宿水陸寺','華岳','宋','宋诗','song-poetry','','[]','蕭寺廊廡闊，無人獨自行。',48,'全唐诗/poet.song.188000.json','["蕭寺廊廡闊，無人獨自行。", "吳儂非好僻，楚客爲誰清。", "花落憑風掃，燈殘借月明。", "江湖有烟浪，且此寄餘生。"]'),
('0a16b73e-26f0-4b90-b571-434eaf02de4b','呈魯伯瞻','華岳','宋','宋诗','song-poetry','','[]','信斷無青鳥，盟寒有白鷗。',48,'全唐诗/poet.song.188000.json','["信斷無青鳥，盟寒有白鷗。", "悶和詩作首，愁聽□□□。", "水滴蓮花曉，山空桂子秋。", "功名有期會，教□□□□。"]'),
('c22eccf3-efec-4be4-b7a4-27f322a0bee2','浦城買舟','華岳','宋','宋诗','song-poetry','','[]','微雨催行旆，西風送客舟。',48,'全唐诗/poet.song.188000.json','["微雨催行旆，西風送客舟。", "菊□□□□，□□□□□。", "浪激花翻雪，山涵影浸秋。", "前灘□□□，□□□□□。"]'),
('704c3ab4-40e4-457c-aaec-d045a4390717','歸興呈吳夢祥','華岳','宋','宋诗','song-poetry','','[]','魚鴈音書少，關山夢寐遥。',48,'全唐诗/poet.song.188000.json','["魚鴈音書少，關山夢寐遥。", "對花思粉面，遇□□□□。", "喜意鵲應報，歸心馬更驕。", "西風綽鞭𩍐，飛□□□□。"]'),
('7c9ab6b0-218a-4a6f-b322-9bc039da7422','秋晚即事','華岳','宋','宋诗','song-poetry','','[]','秋宇清如洗，秋宵分外長。',48,'全唐诗/poet.song.188000.json','["秋宇清如洗，秋宵分外長。", "寒雞鳴午夜，征鴈喚重陽。", "楓葉已全赤，菊花纔半黄。", "不知秋幾許，試與問蘇郎。"]'),
('e33f0f86-e726-49a1-9db3-83e7d30337e6','呈李景山','華岳','宋','宋诗','song-poetry','','[]','居靜心嘗樂，愁多鬢不禁。',48,'全唐诗/poet.song.188000.json','["居靜心嘗樂，愁多鬢不禁。", "買舟和月載，把酒對花斟。", "白水有深淺，青山無古今。", "從茲得真趣，消盡利名心。"]'),
('cf471c7e-6521-4cec-96ab-e8882c74c097','小圃','華岳','宋','宋诗','song-poetry','','[]','舍北有餘隙，平禠作小園。',48,'全唐诗/poet.song.188000.json','["舍北有餘隙，平禠作小園。", "花存四五本，竹種兩三根。", "風伯倩摇珮，月娥煩佐尊。", "誰知方丈裏，別有一乾坤。"]'),
('d1420e11-03fd-4943-b3a0-dfe29e3972c1','村居','華岳','宋','宋诗','song-poetry','','[]','莫怪村居僻，村居亦可嘉。',48,'全唐诗/poet.song.188000.json','["莫怪村居僻，村居亦可嘉。", "僕羸腰带艾，婢倩鬢簪花。", "歌罷蛙催樂，酒闌蜂報衙。", "門前少車馬，慚愧五侯家。"]'),
('d94087a7-9549-4ac4-86a4-1c3f0df6e9c5','宣城道中','華岳','宋','宋诗','song-poetry','','[]','恰到杏花天，轉頭過禁煙。',48,'全唐诗/poet.song.188000.json','["恰到杏花天，轉頭過禁煙。", "燕歸纔數日，蠶起又三眠。", "少智慚樗里，多材憶孟堅。", "功名且隨分，無苦自咨煎。"]'),
('9a7fe68e-970d-4f56-8512-c7285dba5446','過新豐市懷古','華岳','宋','宋诗','song-poetry','','[]','路出橫江去，虛堂立道偏。',48,'全唐诗/poet.song.188000.json','["路出橫江去，虛堂立道偏。", "雨聲楊柳外，風色杏花前。", "有淚沾詩宿，無歌述酒仙。", "采江千古恨，號認向誰傳。"]'),
('9e2201fd-73c9-4628-94fd-925eb2ede018','買舟浦城','華岳','宋','宋诗','song-poetry','','[]','畏路逢危路，尋舟得小舟。',48,'全唐诗/poet.song.188000.json','["畏路逢危路，尋舟得小舟。", "始云爲得計，終乃復添憂。", "艙狹難伸足，篷低怎舉頭。", "十圍無處著，跼促向中流。"]'),
('e709cfc7-3053-4b47-8115-919cffce7035','憩妙因寺','華岳','宋','宋诗','song-poetry','','[]','蕭寺寒山外，崎嶇一徑幽。',48,'全唐诗/poet.song.188000.json','["蕭寺寒山外，崎嶇一徑幽。", "斷雲迎客入，曲水護堤流。", "木石四時古，軒窗五月秋。", "午煩聊小憩，拂石爲支頭。"]'),
('fea25359-1437-4a46-8e9a-a6adfd40ef77','再繼前韵','華岳','宋','宋诗','song-poetry','','[]','俗塵方倥傯，得得訪清幽。',48,'全唐诗/poet.song.188000.json','["俗塵方倥傯，得得訪清幽。", "煙練素疑抹，山屏翠欲流。", "松筠掃日月，藤蔓懸春秋。", "物外有餘樂，吾生空白頭。"]'),
('85398c32-fc2b-48d0-ad22-3dad5e1c0c87','讀漢史','華岳','宋','宋诗','song-poetry','','[]','漢將假帝爲真帝，齊乞真王作假王。',32,'全唐诗/poet.song.188000.json','["漢將假帝爲真帝，齊乞真王作假王。", "大抵紀韓皆是信，不知誰短又誰長。"]'),
('74637183-b3fc-47b6-8950-8c1abba9b622','寄王五四將仕  其一','華岳','宋','宋诗','song-poetry','','[]','季叔青天轟霹靂，屈原平地溺波濤。',32,'全唐诗/poet.song.188000.json','["季叔青天轟霹靂，屈原平地溺波濤。", "從教晉楚多戕賊，二子何曾損一毫。"]'),
('b93020fc-50d4-4bb1-b917-81bd1bd44d94','寄王五四將仕  其二','華岳','宋','宋诗','song-poetry','','[]','周田且謂曾占易，商野何嘗識夢書。',32,'全唐诗/poet.song.188000.json','["周田且謂曾占易，商野何嘗識夢書。", "假使二君無感召，不成終老在樵漁。"]'),
('941fa557-755d-497c-9ea3-81c4e95f4d20','約叔真  其一','華岳','宋','宋诗','song-poetry','','[]','半間屋抵斗來大，一箇身同山樣高。',32,'全唐诗/poet.song.188000.json','["半間屋抵斗來大，一箇身同山樣高。", "側坐斜眠俱不得，煩君除去一牛毛。"]'),
('25cdea6c-943a-46fe-a4be-550e58b0d9e0','約叔真  其二','華岳','宋','宋诗','song-poetry','','[]','厄堂有事留司馬，凌閣無名問太宗。',32,'全唐诗/poet.song.188000.json','["厄堂有事留司馬，凌閣無名問太宗。", "我且盤桓君且去，歸斯千載約芙蓉。"]'),
('18584843-e438-4b63-97d3-0236f44e4f9b','題窗間','華岳','宋','宋诗','song-poetry','','[]','陽虎不名真盜玉，子張何事便書紳。',32,'全唐诗/poet.song.188000.json','["陽虎不名真盜玉，子張何事便書紳。", "聖賢立論有微旨，精義當求妙入神。"]'),
('c58a05d6-27a8-496b-8ee3-5babf8b7c462','過西溪','華岳','宋','宋诗','song-poetry','','[]','路隨馬足難知數，山疊魚鱗不記名。',32,'全唐诗/poet.song.188000.json','["路隨馬足難知數，山疊魚鱗不記名。", "隔岸青帘人不渡，一溪流水暮潮生。"]'),
('0450fb36-d9ea-4a2e-808d-5187386ce8d6','題蓮華壁間','華岳','宋','宋诗','song-poetry','','[]','風外落花千萬片，水邊啼鳥兩三聲。',32,'全唐诗/poet.song.188000.json','["風外落花千萬片，水邊啼鳥兩三聲。", "無情驚起陽臺夢，獨倚閒窗看月明。"]'),
('b3f31051-34d0-4bb6-b2a4-8b1cbea0077b','贈呂元玘','華岳','宋','宋诗','song-poetry','','[]','周末見人歌采芑，楚先聞客賦離騷。',32,'全唐诗/poet.song.188000.json','["周末見人歌采芑，楚先聞客賦離騷。", "胸中有氣不能吐，空使虹蜺萬丈高。"]'),
('b6ce20bb-fb5b-4aa2-a82e-4426cdae3c82','初抵富沙  其一','華岳','宋','宋诗','song-poetry','','[]','芳草不隨春水綠，連山猶带夕陽明。',32,'全唐诗/poet.song.188000.json','["芳草不隨春水綠，連山猶带夕陽明。", "人生有酒且行樂，休向河梁問子卿。"]'),
